window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["artifacts"]={"updatedAt":"2026-07-14","count":153,"artifacts":[{"id":"dan-duoc-truc-co-ky","name":"Hai bình đan dược Trúc Cơ kỳ","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Đỉnh cấp","soHuu":["Mai Ngưng"],"trangThai":"đã tặng","blurb":"Đan dược đỉnh cấp Trúc Cơ kỳ luyện từ yêu đan, Hàn Lập tặng Mai Ngưng trả ân tình Thông Linh Khí.","detail":"Hàn Lập luyện chế từ yêu đan, có tác dụng tăng tiến tu vi Trúc Cơ kỳ. Đối với tu sĩ Kết Đan kỳ như Hàn Lập đã không còn tác dụng. Tặng cho Mai Ngưng để trả nhân tình nàng từng truyền Thông Linh Khí.","congNang":["Tăng tiến tu vi Trúc Cơ kỳ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0594","denChuong":"@c0594","cachCoDuoc":"Tự luyện chế","trangThai":"đã tặng"},{"ten":"Mai Ngưng","tuChuong":"@c0594","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"đang sở hữu"}],"tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập tặng Mai Ngưng","text":"Hàn Lập tặng hai bình đan dược Trúc Cơ kỳ đỉnh cấp cho Mai Ngưng để trả ân tình Thông Linh Khí.","anchor":"Trong bình là đan dược Trúc Cơ kỳ, hôm nay đối với Hàn Lập mà nói đã không còn"}]},"nguon":["@c0594"]},{"id":"dinh-linh-dan","name":"Định Linh Đan","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thánh dược","soHuu":[],"trangThai":"chưa luyện","blurb":"Thánh dược hỗ trợ ngưng kết Nguyên Anh: tăng tu vi, định tâm an hồn, giảm tâm ma xâm nhập. Cần Thuần dịch từ Linh Nhãn Chi Thụ làm thuốc dẫn.","detail":"Đan dược nổi danh trong tu tiên giới, uống trước khi ngưng kết Nguyên Anh sẽ khiến quá trình dễ dàng hơn không ít. Có công năng tăng tiến tu vi, định tâm an hồn, giảm bớt tâm ma xâm nhập. Thuốc dẫn bắt buộc là Thuần dịch — linh dịch chảy từ rễ Linh Nhãn Chi Thụ mỗi hai trăm năm.","congNang":["Tăng tiến tu vi","Định tâm an hồn","Giảm bớt tâm ma xâm nhập khi ngưng kết Nguyên Anh"],"dacDiem":"Cần Thuần dịch từ Linh Nhãn Chi Thụ làm thuốc dẫn","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ thông tin","text":"Hé lộ Định Linh Đan là thánh dược hỗ trợ ngưng kết Nguyên Anh, cần Thuần dịch từ Linh Nhãn Chi Thụ ở Vân Mộng Sơn làm thuốc dẫn.","anchor":"Nếu là lúc ngưng kết Nguyên Anh trước đó uống vào một viên, tuyệt đối có thể khiến cho tu sĩ ngưng kết Nguyên Anh cảm thấy dễ dàng không ít"}]},"nguon":["@c0594"]},{"id":"linh-nhan-chi-thu","name":"Linh Nhãn Chi Thụ","category":"khac","categoryLabel":"Thần mộc","phamCap":"Đại thần mộc","soHuu":[],"trangThai":"tồn tại","blurb":"Một trong ba đại thần mộc cuối cùng trong tu tiên giới, ở sâu trong Vân Mộng Sơn. Giá trị cao hơn Thiên Lôi Trúc và Dưỡng Hồn Mộc.","detail":"Mỗi hai trăm năm từ bộ rễ chảy ra Thuần dịch — nguyên liệu tuyệt hảo, đặc biệt là thuốc dẫn cho Định Linh Đan. Nằm sâu trong Vân Mộng Sơn, do ba tông phái Cổ Kiếm Viện, Lạc Vân Tông, Bách Xảo Viện liên hợp chiếm cứ bảo vệ.","congNang":["Sản sinh Thuần dịch mỗi 200 năm từ bộ rễ"],"dacDiem":"Một trong ba đại thần mộc cuối cùng trong tu tiên giới, giá trị cao hơn Thiên Lôi Trúc và Dưỡng Hồn Mộc","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ thông tin","text":"Giới thiệu Linh Nhãn Chi Thụ là một trong ba đại thần mộc cuối cùng, nằm sâu trong Vân Mộng Sơn, mỗi 200 năm chảy Thuần dịch làm thuốc dẫn Định Linh Đan.","anchor":"một trong ba đại thần mộc cuối cùng trong tu tiên giới"}]},"nguon":["@c0594"]},{"id":"thuan-dich","name":"Thuần dịch","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tuyệt hảo","soHuu":[],"trangThai":"tồn tại","blurb":"Linh dịch chảy từ rễ Linh Nhãn Chi Thụ mỗi 200 năm, không thể trực tiếp phục dụng, là thuốc dẫn cho Định Linh Đan.","detail":"Nguyên liệu tuyệt hảo luyện linh dược, đặc biệt là thuốc dẫn bắt buộc cho Định Linh Đan. Không thể trực tiếp phục dụng. Mỗi hai trăm năm Linh Nhãn Chi Thụ mới chảy ra một lần từ bộ rễ.","congNang":["Nguyên liệu luyện linh dược","Thuốc dẫn cho Định Linh Đan"],"tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"xuất hiện","importance":"normal","giaiDoan":"Hé lộ thông tin","text":"Giới thiệu Thuần dịch là linh dịch chảy từ rễ Linh Nhãn Chi Thụ mỗi 200 năm, thuốc dẫn cho Định Linh Đan.","anchor":"Linh Nhãn Chi Thụ sẽ từ bộ rễ chảy ra một loại linh dịch gọi là “Thuần dịch”"}]},"nguon":["@c0594"]},{"id":"can-khon-thap","name":"Càn Khôn Tháp","cn":"乾坤塔","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Đại danh khí","soHuu":["Yến gia"],"trangThai":"dang-co","blurb":"Phù bảo của Yến gia, được Bách Xảo Viện luyện chế bằng phương pháp hàng đầu, là nhất kiện đại danh khí pháp bảo đương thời Việt Quốc.","detail":"Phù bảo của Yến gia tại Việt Quốc, được luyện chế bằng phương pháp luyện chế pháp bảo hàng đầu từ Bách Xảo Viện. Là nhất kiện đại danh khí pháp bảo, khiến Yến gia trở thành đệ nhất gia tộc Việt Quốc.","congNang":["Không rõ công năng cụ thể tại chương này"],"nguonGoc":"Bách Xảo Viện luyện chế cho Yến gia","chuSoHuu":[{"ten":"Yến gia","tuChuong":"@c0596","denChuong":"","cachCoDuoc":"Được Bách Xảo Viện luyện chế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0596","loai":"nhắc tới","importance":"normal","giaiDoan":"Được Hàn Lập nhắc khi phân tích Bách Xảo Viện","text":"Hàn Lập nhận định phù bảo Càn Khôn Tháp của Yến gia được luyện chế bằng phương pháp hàng đầu của Bách Xảo Viện, là đại danh khí pháp bảo đương thời.","anchor":"cũng là nhờ vào phương pháp luyện chế pháp bảo này mà trở thành nhất kiện đại danh khí pháp bảo"}]},"nguon":["@c0596"]},{"id":"tran-ky-mau-xanh","name":"Trận kỳ màu xanh","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Du sư đệ"],"trangThai":"dang-co","blurb":"Trận kỳ dùng để mở thông đạo xuyên qua đại trận hộ phái Lạc Vân Tông, phát ra mũi tên nhọn màu xanh nhạt bắn xuyên sương mù.","detail":"Du sư đệ lấy từ Túi Trữ Vật, đọc khẩu quyết khiến trận kỳ phát mũi tên nhọn màu xanh nhạt bắn xuyên sương mù, mở thông đạo rộng hai ba trượng xuyên qua đại trận hộ phái Lạc Vân Tông. Thông đạo tự khép lại phía sau khi đoàn người đi qua.","congNang":["Mở thông đạo xuyên đại trận hộ phái Lạc Vân Tông @c0597"],"chuSoHuu":[{"ten":"Du sư đệ","tuChuong":"@c0597","denChuong":"","cachCoDuoc":"Sở hữu sẵn (đệ tử Lạc Vân Tông)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0597","loai":"dùng","importance":"normal","giaiDoan":"Mở đại trận hộ phái đưa nhóm tân đệ tử vào","text":"Du sư đệ dùng trận kỳ đọc khẩu quyết, phát mũi tên nhọn xanh nhạt bắn xuyên sương mù, mở thông đạo rộng hai ba trượng để đoàn người xuyên qua đại trận hộ phái Lạc Vân Tông.","anchor":"cái trận kỳ màu xanh trong tay bắt đầu xuất hiện ra một mũi tên nhọn màu xanh nhạt"}]},"nguon":["@c0597"]},{"id":"van-tam-phu","name":"Vấn Tâm Phù","cn":"問心符","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Miêu sư huynh"],"trangThai":"dang-dung","blurb":"Ngân phù chói mắt dài khoảng một gang tay, dùng phối hợp Vấn Tâm Thuật để kiểm tra tâm ý tân đệ tử Lạc Vân Tông.","detail":"Do Miêu sư huynh chuẩn bị đúng bảy cái cho bảy tán tu. Được áp lên vai phải từng người, khi phát tác thì ngân quang đại thịnh rồi lập lòe sáng tối, báo hiệu người đó lên lầu hai chịu kiểm tra.","congNang":["Phối hợp Vấn Tâm Thuật kiểm tra tâm ý người đeo","Phát sáng khi kích hoạt báo hiệu thứ tự kiểm tra"],"dacDiem":"Ngân phù, dài khoảng một gang tay, phát ngân quang khi kích hoạt","tabs":{"tienTrinh":[{"chuong":"@c0598","loai":"dùng","importance":"normal","giaiDoan":"Kiểm tra nhập môn Lạc Vân Tông","text":"Bảy Vấn Tâm Phù được Miêu sư huynh giao cho Du sư đệ áp lên vai phải bảy tán tu mới. Phù của Hàn Lập phát sáng đầu tiên, hắn là người đầu tiên lên lầu hai chịu kiểm tra.","anchor":"Hàn Lập mới nghiêng đầu một cái rồi nhìn cái phù màu bạc dài khoảng một gang tay"}]},"nguon":["@c0598"]},{"id":"ma-nao-giac","name":"Mã Não Giác","cn":"瑪瑙角","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":[],"trangThai":"Chưa có","blurb":"Một trong ba tài liệu cần thiết để luyện chế đan dược Cửu Khúc Linh Sâm, tại Thiên Nam không thể tìm thấy.","detail":"Cùng với Cửu Khúc Linh Sâm và bát cấp Bạn Yêu Thảo, là nguyên liệu then chốt mà Hàn Lập chưa thể thu thập tại Thiên Nam.","nguon":["@c0602"]},{"id":"dia-hoang-tinh","name":"Địa Hoàng Tinh","cn":"地黄精","aliases":["Hoàng Tinh"],"category":"khac","categoryLabel":"Linh thảo","phamCap":"Trên 50 năm tuổi giá hơn 30 khối linh thạch","soHuu":[],"trangThai":"dang-co","blurb":"Linh dược lâu năm, dị chủng Tuyết Vân Hồ cực kỳ thích ăn. Cần loại trên năm mươi năm tuổi mới đủ dụ nó ra khỏi hang bùn.","detail":"Linh thảo có nhiều loại niên hạn khác nhau. Loại trên mười năm tuổi giá mười mấy khối linh thạch, loại trên năm mươi năm giá hơn ba mươi khối. Dược viên của Hàn Lập tại Thiên Tuyền Phong có hai cây trên năm mươi năm tuổi. Khuê Hoán xin mượn nhưng bị Hàn Lập từ chối vì không có tư cách tự ý sử dụng linh dược trong vườn.","congNang":["Mồi nhử dị chủng Tuyết Vân Hồ"],"tabs":{"tienTrinh":[{"chuong":"@c0603","loai":"xuất hiện","importance":"normal","giaiDoan":"Được nhắc đến như mồi nhử Tuyết Vân Hồ","text":"Khuê Hoán đến dược viên xin mượn Địa Hoàng Tinh trên năm mươi năm để dụ dị chủng Tuyết Vân Hồ, bị Hàn Lập từ chối cho mượn linh dược nhưng cho mượn linh thạch để tự mua.","anchor":"muốn đem con thú này dẫn dụ ra thì tối thiểu cũng cần Địa Hoàng Tinh ngoài năm mươi năm"}]},"nguon":["@c0603"]},{"id":"linh-nhan-chi-ngoc","name":"Linh Nhãn Chi Ngọc","cn":"灵眼之玉","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Cao cấp nhất trong các loại linh nhãn chi thạch","soHuu":["Hắc y thiếu phụ"],"trangThai":"Đề nghị cho Hàn Lập mượn, chưa chính thức chuyển giao","blurb":"Bảo vật cao cấp nhất trong các loại linh nhãn chi thạch, nằm trong hộp ngọc đen cổ, do hắc y thiếu phụ Nguyên Anh kỳ sở hữu.","detail":"Loại linh nhãn chi thạch cao cấp nhất, được hắc y thiếu phụ cất giữ trong hộp ngọc đen cổ. Công năng: giúp giai đoạn giả anh trước Kết Anh ổn định thêm ba phần, ngưng kết Nguyên Anh dễ dàng hơn, rút ngắn quá trình tu luyện khoảng ba lần. Thiếu phụ đề nghị cho Hàn Lập mượn với điều kiện dùng xong phải trả nguyên vẹn và giúp bà chuyển một tín hàm cho một người nào đó.","nguon":["@c0607"]},{"id":"hap-linh-thach","name":"Hấp Linh thạch","cn":"青金石","aliases":["Thanh Kim thạch"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Tài liệu luyện khí trân quý, gần thất truyền","soHuu":[],"trangThai":"Cấu thành vách tường thạch thất trong mật cảnh","blurb":"Loại đá cực hiếm còn gọi là Thanh Kim thạch, miễn dịch linh lực và tự phục hồi, được dùng xây cả một thạch thất trong mật cảnh ba phái.","detail":"Tài liệu luyện khí vô cùng trân quý, ngoài tự nhiên cực hiếm, gần như thất truyền và không còn mấy người biết đến. Đặc tính: kiếm mang công kích không để lại vết xước, phi kiếm bắn vào chỉ tạo lỗ nhỏ sâu một tấc rồi tự liền lại, ngoài lực cực mạnh phá hỏng thì không gì tác động được kể cả linh lực. Vách tường thạch thất nơi hắc y thiếu phụ ẩn tu được tạo hoàn toàn từ loại đá này, thô sơ lồi lõm không giống động phủ tu sĩ bình thường.","nguon":["@c0607"]},{"id":"linh-nhan-chi-ngoc-hoa-hinh","name":"Linh Nhãn Chi Ngọc (sắp hóa hình)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Sắp hóa hình, vượt xa Linh nhãn chi thạch thường","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Viên ngọc trắng to vài tấc, bên trong có hình con trâu nhỏ xanh sống động sắp hóa hình, phẩm chất cực cao, giúp rút ngắn thời gian tiến Giả Anh kỳ còn vài năm.","detail":"Viên ngọc trắng to vài tấc, bên trong có hình con trâu nhỏ màu xanh bằng ngón tay cái sống động như thật, cho thấy ngọc sắp hóa hình — phẩm chất vượt xa Linh nhãn chi thạch phổ thông. Thiếu phụ áo đen trao cho Hàn Lập làm thù lao đưa tin. Hàn Lập nhận định dùng nó tu luyện chỉ cần vài năm thay vì mười năm để tiến vào cảnh giới Giả Anh. Đây cũng là nguồn linh khí khiến Tuyết Vân Hồ tiến hóa thành yêu hồ.","hinhDang":"Viên ngọc trắng to vài tấc, bên trong có hình con trâu nhỏ xanh sống động","nguonGoc":"Do thiếu phụ áo đen sở hữu, trao cho Hàn Lập","congNang":["Tu luyện hiệu quả cực cao, rút ngắn thời gian tiến Giả Anh kỳ từ mười năm còn vài năm","Linh khí tỏa ra có thể khiến yêu thú tiến hóa (Tuyết Vân Hồ tiến hóa nhờ nhiễm linh khí)"],"chuSoHuu":[{"ten":"Hắc y thiếu phụ","tuChuong":"@c0608","denChuong":"@c0608","cachCoDuoc":"","trangThai":"đã trao"},{"ten":"Hàn Lập","tuChuong":"@c0608","denChuong":"","cachCoDuoc":"Nhận từ thiếu phụ áo đen làm thù lao","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"đổi chủ","importance":"major","giaiDoan":"Thiếu phụ trao cho Hàn Lập","text":"Thiếu phụ áo đen trao Linh nhãn chi ngọc sắp hóa hình cho Hàn Lập làm thù lao đưa tin. Phẩm chất cực cao, bên trong có hình trâu xanh sống động, giúp rút ngắn thời gian tiến Giả Anh kỳ.","anchor":"tận mắt trông thấy bên trong ngọc có một con trâu nhỏ màu xanh bằng ngón tay cái"}]},"capNhatToi":"@c0608","nguon":["@c0608"]},{"id":"thien-hoa-than-lien","name":"Thiên Hỏa Thần Liên","cn":"","aliases":["Ngân liên","dây xích bạc"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hắc y thiếu phụ"],"trangThai":"đang sử dụng (trói buộc thiếu phụ)","blurb":"Dây xích màu trắng xuyên qua xương đùi thiếu phụ, tương thông nguyên thần, do thiếu phụ tự chế để giam giữ bản thân.","detail":"Dây xích trắng xuyên qua xương đùi thiếu phụ áo đen, một đầu chôn sâu vào nền đá. Theo lời thiếu phụ: do bà tự chế bằng tâm pháp đặc biệt để tự giam giữ bản thân, tương thông nguyên thần. Nếu cưỡng ép dùng chân hỏa luyện chế thì có thể mất mạng. Cần chìa khóa đặc biệt mới mở được, chìa khóa đã giao cho bạn thân giữ.","hinhDang":"Mấy sợi dây xích màu trắng","nguonGoc":"Do thiếu phụ áo đen tự chế bằng tâm pháp đặc biệt","congNang":["Trói buộc/giam cầm, xuyên qua xương người bị trói","Tương thông nguyên thần người bị trói, cưỡng ép luyện chế bằng chân hỏa sẽ nguy hiểm tính mạng","Cần chìa khóa đặc biệt mới mở được"],"chuSoHuu":[{"ten":"Hắc y thiếu phụ","tuChuong":"@c0608","denChuong":"","cachCoDuoc":"Tự chế","trangThai":"đang bị trói bởi chính nó"}],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện khi thiếu phụ chứng minh bị giam","text":"Thiếu phụ vén quần lộ hai đùi khô gầy bị mấy sợi dây xích trắng xuyên qua xương chôn sâu vào nền đá. Bà nói tự chế Thiên Hỏa Thần Liên cùng Thanh kim thạch để giam giữ bản thân.","anchor":"Thiên Hỏa Thần Liên cùng gian kim thạch này đem bản thân giam giữ tại đây"}]},"capNhatToi":"@c0608","nguon":["@c0608"]},{"id":"hop-ngoc-o-vang","name":"Hộp ngọc ố vàng (tín vật)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":[],"trangThai":"Hàn Lập đang giữ","blurb":"Hộp ngọc ố vàng giấu sau đài đá, bên ngoài khắc đồ án ngọn lửa có bóng người gào rít, mặt trước dán đạo phù vàng phát uy áp mạnh có tác dụng trấn áp thiếu phụ.","detail":"Hộp ngọc ố vàng tỏa mùi hương, giấu trong lỗ sâu sau đài đá. Bên ngoài khắc đồ án ngọn lửa, trong hỏa diễm mơ hồ có bóng một người đang nhìn trời gào rít. Mặt trước dán một đạo phù vàng phát ánh sáng chói mắt, tỏa uy áp cực mạnh. Thiếu phụ nói đây là tín vật nhờ Hàn Lập chuyển đi và yêu cầu xé phù, nhưng khi Hàn Lập mang hộp có phù lại gần bà thì bà hoảng sợ thực sự — cho thấy đạo phù/hộp này chính là vật trấn áp thiếu phụ.","hinhDang":"Hộp ngọc ố vàng, khắc đồ án ngọn lửa có bóng người gào rít, có đạo phù vàng chói mắt","congNang":["Đạo phù trên hộp có tác dụng trấn áp thiếu phụ áo đen"],"tabs":{"tienTrinh":[{"chuong":"@c0608","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập lấy ra từ sau đài đá","text":"Hàn Lập tìm thấy hộp ngọc ố vàng trong lỗ sâu sau đài đá, bên ngoài khắc đồ án ngọn lửa có bóng người gào rít, mặt trước dán đạo phù phát uy áp mạnh.","anchor":"bên ngoài có khắc một đồ án ngọn lửa, trong hỏa diễm mơ hồ có bóng một người, đang nhìn trời gào rít"}]},"capNhatToi":"@c0608","nguon":["@c0608"]},{"id":"la-phu-hop-ngoc","name":"Lá phù trong hộp ngọc","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Lá phù chứa trong hộp ngọc ố vàng tìm thấy trong thạch thất, phóng ra phù văn vàng có khả năng khắc chế Thi Tiêu.","detail":"Phóng ra vô số phù văn màu vàng có khả năng khắc chế Thi Tiêu, khiến quái vật đau đớn kêu thảm thiết và bốc khói xanh. Linh khí hữu hạn, sau khi phát huy hết tác dụng thì kim quang tắt.","congNang":["Khắc chế Thi Tiêu/tà vật, phóng phù văn vàng tiêu trừ @c0609"],"tabs":{"tienTrinh":[{"chuong":"@c0609","loai":"dung","importance":"normal","giaiDoan":"Sử dụng khắc chế Thi Tiêu","text":"Hàn Lập khoát tay cho hộp ngọc bay tới thiếu phụ áo đen, lá phù phóng ra vô số phù văn vàng khiến Thi Tiêu đau đớn kêu thảm thiết, bốc khói xanh. Sau khi linh khí hết, kim quang trên lá phù tắt.","anchor":"kim quang trên lá phù cũng không có bị mất đi"}]},"nguon":["@c0609"]},{"id":"hop-ngoc-tinh-hon-thi-tieu","name":"Hộp ngọc chứa tinh hồn thi tiêu","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đang được Hàn Lập cất giữ, chưa mở","blurb":"Hộp ngọc bên ngoài dán linh phù kỳ lạ, nghi chứa tinh hồn thi tiêu bị Trừu Hồn thuật phong ấn. Hàn Lập thu vào túi trữ vật, hẹn đại thành Nguyên Anh mới dám mở.","detail":"Hộp ngọc rơi bên cạnh thi tiêu bất động. Bên ngoài dán lá phù có phù văn kỳ lạ khiến Hàn Lập muốn nghiên cứu. Bên trong nghi là tinh hồn thi tiêu bị phong ấn bằng Trừu Hồn thuật. Thi tiêu trước đó vẫn có thể nói chuyện và lừa Hàn Lập mở hộp dù tinh hồn đã bị trừu, khiến Hàn Lập thắc mắc. Hàn Lập dự định khi đại thành Nguyên Anh sẽ dùng Ích tà thần lôi và Đề Hồn Thú đối phó nếu bên trong là linh hồn thi tiêu hay hồn quỷ.","congNang":["Phong ấn tinh hồn thi tiêu, phù văn bên ngoài có tác dụng trấn áp chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0610","denChuong":"","cachCoDuoc":"Nhặt được bên cạnh thi tiêu bất động","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0610","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập thu nhặt sau khi chế trụ thi tiêu","text":"Hàn Lập phân tích hộp ngọc dán linh phù chứa tinh hồn thi tiêu bị Trừu Hồn thuật phong ấn, sờ lá phù rồi thu vào túi trữ vật.","anchor":"hắn sau khi sờ lá phù vài lần sau đó đột nhiên vung tay đem thu nó vào túi trữ vật"}]},"nguon":["@c0610"]},{"id":"noi-giap-xanh","name":"Nội giáp xanh","cn":"","category":"phap-bao","categoryLabel":"Phòng cụ","phamCap":"Không rõ (không kém Hoàng Lân giáp)","soHuu":["Hàn Lập"],"trangThai":"Đang dùng","blurb":"Nội giáp di vật của Ôn Thiên Nhân (truyền nhân Lục Đạo), mềm mại như tơ, lấp lóe ánh sáng xanh. Cứu Hàn Lập khỏi lợi trảo bất ngờ của yêu hồ cấp cao.","detail":"Lộ ra khi áo Hàn Lập bị yêu hồ xé rách, lấp lóe ánh sáng xanh bên trong. Là nội giáp của Lục Đạo truyền nhân Ôn Thiên Nhân, mềm mại như tơ, chất lượng không kém Hoàng Lân giáp. Chặn được lợi trảo khổng lồ trắng như tuyết của yêu hồ cấp cao mà Hàn Lập không bị thương.","congNang":["Phòng ngự vật lý cực mạnh, chặn được lợi trảo yêu hồ cấp cao"],"nguonGoc":"Di vật của Ôn Thiên Nhân, truyền nhân Lục Đạo","dacDiem":"Mềm mại như tơ, ánh sáng xanh, chất lượng không kém Hoàng Lân giáp","chuSoHuu":[{"ten":"Ôn Thiên Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"","denChuong":"","cachCoDuoc":"Thu được từ Ôn Thiên Nhân","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0610","loai":"dùng","importance":"normal","giaiDoan":"Cứu mạng Hàn Lập trước lợi trảo yêu hồ","text":"Áo Hàn Lập bị xé rách lộ nội giáp xanh lấp lóe bên trong, chặn được lợi trảo khổng lồ của yêu hồ biến hình.","anchor":"Đúng là nội giáp của Lục Đạo truyền nhân – Ôn Thiên Nhân"}]},"nguon":["@c0610"]},{"id":"thanh-truc-phong-van-kiem","name":"Thanh Trúc Phong Vân Kiếm","cn":"青竹蜂云剑","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp bảo bổn mạng","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Pháp bảo bổn mạng của Hàn Lập, hiện chưa có hồn khí. Ngân Nguyệt đề nghị làm hồn khí cho kiếm, Hàn Lập đã đồng ý.","detail":"Thanh Trúc Phong Vân Kiếm là pháp bảo bổn mạng của Hàn Lập, được xác nhận hiện không có hồn khí. Ngân Nguyệt chủ động đề nghị rời nguyên thần khỏi Ngọc Như Ý để chuyển sang làm hồn khí cho kiếm, nếu thành thì uy lực sẽ tăng mạnh.","dacDiem":"Hiện chưa có hồn khí, sắp được Ngân Nguyệt nhập vào làm hồn khí","congNang":["Pháp bảo bổn mạng, sắp được bổ sung hồn khí từ Ngân Nguyệt để tăng uy lực"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0613","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0613","loai":"nâng cấp","importance":"major","giaiDoan":"Xác nhận không có hồn khí, Ngân Nguyệt đề nghị nhập vào","text":"Được xác nhận hiện không có hồn khí. Ngân Nguyệt đề nghị làm hồn khí, Hàn Lập đồng ý, uy lực sẽ tăng đáng kể.","anchor":"Thanh Trúc Phong Vân Kiếm của ngươi không có hồn khí","phamCap":"Pháp bảo bổn mạng"}]},"capNhatToi":"@c0613","nguon":["@c0613"]},{"id":"tui-bich-van","name":"Túi Bích vân","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Pháp khí dạng túi dùng để chứa đồ hoặc nhốt yêu thú, tuy nhiên không đủ sức giam giữ yêu thú tinh thông độn thuật như Tuyết Vân Hồ.","detail":"Túi Bích vân được Khuê Hoán và Vương sư huynh sử dụng để nhốt con Tuyết Vân Hồ khi đem đi bán ở phường thị, nhưng yêu hồ đã dùng kỹ xảo nào đó biến mất khỏi túi một cách vô ảnh vô tung.","congNang":["Chứa đồ vật, nhốt yêu thú"],"tabs":{"tienTrinh":[{"chuong":"@c0615","loai":"dùng","importance":"normal","giaiDoan":"Nhốt Tuyết Vân Hồ thất bại","text":"Được dùng để nhốt Tuyết Vân Hồ nhưng yêu hồ đã trốn thoát khỏi túi trên đường đem bán.","anchor":"lại từ trong túi Bích vân biến mất vô ảnh vô tung"}]},"nguon":["@c0615"]},{"id":"minh-thanh-linh-thuy","name":"Minh Thanh Linh Thuỷ","cn":"明清灵水","category":"dan-duoc","categoryLabel":"Linh dược","phamCap":"Cực hiếm (tam phái Vân Mộng Sơn điều chế)","soHuu":[],"trangThai":"dang-phoi-che","blurb":"Linh thuỷ phối chế từ giọt linh dịch đầu tiên của thánh thụ cùng dược tài trân quý, dùng rửa mắt cho khả năng xuyên sương mù nhìn thấu đá, chỉ hiệu quả với tu sĩ Luyện Khí kỳ và Trúc Cơ kỳ.","detail":"Phần thưởng cho top mười Thí Kiếm Đại Hội do tam phái Vân Mộng Sơn điều chế. Nguyên liệu gồm giọt linh dịch đầu tiên thánh thụ xuất ra cùng các loại dược tài trân quý, trong đó có linh dược ngàn năm. Dùng nước này rửa hai mắt giúp có khả năng xuyên vụ khí thấu thạch, tuy không gia tăng tu vi. Hiệu quả chỉ có tác dụng với tu sĩ Luyện Khí kỳ và Trúc Cơ kỳ.","congNang":["Rửa mắt → cho đôi mắt khả năng xuyên sương mù, nhìn thấu đá","Tẩy trừ hai mắt cho đệ tử, liên quan đến Linh Nhãn Chi Thụ","Công dụng cụ thể chưa rõ, được phối chế từ dược liệu ở gốc Linh Nhãn Chi Thụ"],"dacDiem":"Chỉ hiệu quả với tu sĩ Luyện Khí kỳ và Trúc Cơ kỳ; nguyên liệu cực hiếm gồm linh dịch thánh thụ và linh dược ngàn năm","nguonGoc":"Tam phái Vân Mộng Sơn điều chế","tabs":{"tienTrinh":[{"chuong":"@c0616","loai":"xuất hiện","importance":"major","giaiDoan":"Được tiết lộ là phần thưởng top mười","text":"Vương sư huynh tiết lộ Minh Thanh Linh Thuỷ là phần thưởng cho top mười Thí Kiếm Đại Hội, phối chế từ linh dịch thánh thụ cùng dược tài ngàn năm, có khả năng cho mắt xuyên sương thấu đá.","anchor":"dùng giọt linh dịch đầu tiên mà thánh thụ xuất ra cộng thêm các tài liệu trân quý khác có thể phối chế ra Minh Thanh Linh Thuỷ trong truyền thuyết"},{"chuong":"@c0625","loai":"xuất hiện","importance":"normal","giaiDoan":"Đang được điều chế tại sơn cốc bí mật","text":"Nho sinh họ Bạch giải thích quy trình: Minh Thanh Linh Thủy tích nhập Thuần dịch ở bước cuối, hoàn thành xong phải lập tức tẩy mắt cho mười đệ tử. Ba tu sĩ Kết Đan ngày đêm thủ hộ thánh địa.","anchor":"Minh Thanh Linh Thủy tích nhập Thuần dịch, phải tới bước cuối cùng mới tiến hành"},{"chuong":"@c0628","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu nhắc tới","text":"Hàn Lập nhận ra bình ngọc dưới gốc Linh Nhãn Chi Thụ chứa hương dược dùng phối chế Minh Thanh Linh Thủy. Vệ sư huynh bắt đầu điều phối.","anchor":"Chẵng lẽ cái này dùng để phối chế ra Minh Thanh Linh Thủy"}]},"capNhatToi":"@c0616","nguon":["@c0616","@c0625","@c0628"]},{"id":"thien-tinh-dai","name":"Thiên Tinh đai","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Thượng giai pháp khí","soHuu":["Mộ Phái Linh"],"trangThai":"dang-co","blurb":"Pháp khí phi hành hồng sắc của Mộ Phái Linh, tốc độ cao và có thể mang thêm người bay cùng.","detail":"Pháp khí phi hành dạng dải lụa hồng sắc, có khả năng bao lấy người khác mang theo bay với tốc độ cao. Mộ Phái Linh dùng nó mang Hàn Lập bay đến Thiên Tuyền Phong vì phi kiếm của hắn không phải loại phi hành chuyên dụng.","congNang":["Phi hành tốc độ cao, có thể mang thêm người bay cùng"],"chuSoHuu":[{"ten":"Mộ Phái Linh","tuChuong":"@c0617","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0617","loai":"dùng","importance":"normal","giaiDoan":"Mộ Phái Linh dùng mang Hàn Lập bay","text":"Mộ Phái Linh dùng Thiên Tinh đai bao lấy Hàn Lập, mang hắn bay cùng đến Thiên Tuyền Phong vì phi kiếm của hắn chậm.","anchor":"chi bằng để ta dùng Thiên Tinh đai mang ngươi theo kẻo trễ mất thời gian"}]},"nguon":["@c0617"]},{"id":"bach-kim-qua","name":"Bạch kim qua","category":"phap-bao","categoryLabel":"Pháp khí","soHuu":["Tu sĩ họ Viên"],"trangThai":"binh-thuong","blurb":"Pháp khí của tu sĩ họ Viên (Thiên Tuyền Phong), có chút uy lực, hóa thành cầu vồng trắng chém xuống nhưng không đủ giúp chủ nhân thắng trận.","detail":"Pháp khí dạng qua (kích) màu trắng kim, khi thi triển hóa thành cầu vồng trắng chém xuống đối thủ. Được tu sĩ họ Viên sử dụng trong tỷ thí Lục Xảo Phong, chiếm ưu thế ban đầu nhưng không đủ chống lại thuật ẩn thân và hồng vụ của Kim Dung.","nguon":["@c0619"]},{"id":"hoa-lang-chau","name":"Hoả Lãng châu","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Tuân Thông"],"trangThai":"đang sử dụng","blurb":"Pháp khí gia truyền Tuân gia, viên hoả châu to bằng quả trứng gà, có thể phát ra hoả diễm công kích. Tuân sư đệ dùng trong trận tỷ thí nhưng chưa kịp phát huy.","detail":"Pháp khí nổi danh của Tuân gia (tu tiên gia tộc ở Khê quốc), viên hoả châu to bằng quả trứng gà, có thể phát ra hoả diễm công kích. Tuân sư đệ cầm trên tay trong trận tỷ thí vòng 1 với Hàn Lập nhưng vòng bảo hộ bị phá trước khi kịp thi triển.","congNang":["Phát ra hoả diễm công kích"],"chuSoHuu":[{"ten":"Tuân Thông","tuChuong":"@c0620","denChuong":"","cachCoDuoc":"Gia truyền Tuân gia","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0620","loai":"xuất hiện","importance":"normal","giaiDoan":"Trận tỷ thí vòng 1","text":"Tuân sư đệ thôi động Hoả Lãng châu trong trận tỷ thí với Hàn Lập nhưng chưa kịp phát huy thì vòng bảo hộ đã bị phá.","anchor":"khoả châu trên tay hắn ta hình như là Hoả Lãng châu đỉnh đỉnh đại danh của Tuân gia"}]},"nguon":["@c0620"]},{"id":"hoa-dan-phu","name":"Hoả Đạn phù","category":"khac","categoryLabel":"Linh phù","phamCap":"Sơ cấp","soHuu":["Hàn Lập"],"trangThai":"đã dùng","blurb":"Phù sơ cấp giá một linh thạch mỗi tấm, tạo ra hoả cầu to bằng nắm tay. Hàn Lập dùng ba bốn mươi lá đồng loạt phá vỡ vòng bảo hộ Tuân sư đệ.","detail":"Loại phù sơ cấp phổ thông, mỗi tấm giá một khối linh thạch, kích hoạt tạo ra hoả cầu to bằng nắm tay. Đơn lẻ uy lực yếu nhưng Hàn Lập dùng ba bốn mươi lá đồng loạt, hoả cầu như ong vỡ tổ bắn tới đối phương, phá vỡ cả vòng bảo hộ Hỏa thuộc tính tầng 12 Luyện Khí của Tuân sư đệ. Cách đánh xa xỉ khiến các đệ tử gọi Hàn Lập là phá gia chi tử.","congNang":["Tạo hoả cầu to bằng nắm tay công kích"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0620","denChuong":"","cachCoDuoc":"Mua/tự chế","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0620","loai":"dùng","importance":"normal","giaiDoan":"Trận tỷ thí vòng 1","text":"Hàn Lập ném ba bốn mươi lá Hoả Đạn phù đồng loạt, hoả cầu như ong vỡ tổ phá vỡ vòng bảo hộ Tuân sư đệ.","anchor":"cho dù Hoả đạn phù là loại phù sơ cấp nhưng một tấm phù dù sao cũng phải cần một khối linh thạch mới mua được"}]},"nguon":["@c0620"]},{"id":"han-nguyet-luan","name":"Hàn Nguyệt Luân","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp pháp khí","soHuu":["Đỗ Đông"],"trangThai":"dang-co","blurb":"Đỉnh cấp pháp khí thuộc tính băng hình luân tử bàn, đường kính hơn trượng, bề mặt khắc biểu tượng vầng trăng. Trấn tộc chi bảo của Đỗ gia bị diệt hai trăm năm trước, nay thuộc về Đỗ Đông.","detail":"Pháp khí hình luân tử bàn thuộc tính băng, đường kính hơn trượng, bề mặt khắc biểu tượng vầng trăng. Phát bạch quang tạo vòng bảo hộ băng bao phủ chủ nhân, đồng thời phóng hàn khí hóa thành chim lớn công kích đối thủ. Uy lực cực mạnh, đánh bại mọi đối thủ trong vòng tuyển chọn chỉ sau một chiêu. Vốn là trấn tộc chi bảo của Đỗ gia — gia tộc tu tiên bị tiêu diệt hai trăm năm trước.","congNang":["Phát bạch quang tạo vòng bảo hộ băng bao phủ chủ nhân","Phóng hàn khí hóa thành chim lớn công kích đối thủ"],"phanLoaiPhu":"Luân tử bàn","hinhDang":"Hình luân tử bàn, đường kính hơn trượng, bề mặt khắc biểu tượng vầng trăng","nguonGoc":"Trấn tộc chi bảo của Đỗ gia (bị diệt 200 năm trước)","uyLuc":"Đỉnh cấp pháp khí thuộc tính băng, một chiêu thắng mọi đối thủ vòng tuyển chọn","dacDiem":"Thuộc tính băng, vừa phòng thủ vừa công kích","chuHienThoi":"Đỗ Đông","chuSoHuu":[{"ten":"Đỗ gia","tuChuong":"","denChuong":"","cachCoDuoc":"Trấn tộc chi bảo","trangThai":"da-mat"},{"ten":"Đỗ Đông","tuChuong":"@c0621","denChuong":"","cachCoDuoc":"Thừa kế từ Đỗ gia","trangThai":"dang-co"}],"dinhDanh":"goc","capNhatToi":"@c0621","tabs":{"tienTrinh":[{"chuong":"@c0621","loai":"xuat-hien","importance":"normal","giaiDoan":"Lộ diện trong vòng tuyển chọn","text":"Đỗ Đông dùng Hàn Nguyệt Luân trong vòng tuyển chọn cuối cùng tông nội tỷ thí, đánh bại mọi đối thủ chỉ sau một chiêu. Các trưởng lão nhận ra đây là trấn tộc chi bảo Đỗ gia bị diệt hai trăm năm trước.","anchor":"Là một pháp khí giống như Luân tử bàn, đường kính hơn trượng, trên bề mặt có khắc biểu tượng vầng trăng"}]},"nguon":["@c0621"]},{"id":"hai-thanh-phi-kiem-do-lam","name":"Hai thanh phi kiếm đỏ lam","cn":"","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Không rõ","soHuu":["Diêu Phong"],"trangThai":"dang-co","blurb":"Cặp phi kiếm một đỏ một lam của Diêu Phong, đeo trên lưng, dùng khu kiếm tấn công trong trận đấu nhưng chưa kịp phát huy đã thua.","detail":"Hai thanh trường đoản kiếm, một đỏ một lam, Diêu Phong đeo trên lưng. Khi giao đấu với Hàn Lập, hai kiếm bắn ra phiêu phù trên đỉnh đầu chuẩn bị khu kiếm tấn công, nhưng bị hỏa cầu áp đảo nên chưa kịp dùng.","congNang":["Phi kiếm chiến đấu, khu kiếm tấn công từ xa"],"chuSoHuu":[{"ten":"Diêu Phong","tuChuong":"@c0624","denChuong":"","cachCoDuoc":"Bản thân sở hữu","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0624","loai":"xuat-hien","importance":"normal","giaiDoan":"Trận đầu Thí Kiếm Đại Hội","text":"Diêu Phong xuất hai phi kiếm từ lưng khi giao đấu Hàn Lập, phiêu phù trên đỉnh đầu chuẩn bị khu kiếm nhưng bị hỏa cầu áp đảo, chưa kịp phát huy.","anchor":"hai thanh phi kiếm đồng thời từ trên lưng bắn nhanh ra, phiêu phù ở khoảng không trên đỉnh đầu"}]},"nguon":["@c0624"]},{"id":"di-chung-thanh-quang-dieu","name":"Dị chủng thanh quang điêu","cn":"","category":"khac","categoryLabel":"Linh thú / Tọa kỵ","phamCap":"Năm cấp yêu thú","soHuu":["Lạc Vân Tông"],"trangThai":"dang-co","blurb":"Quái điểu khổng lồ cấp năm yêu thú của Lạc Vân Tông, có thể biến hóa lớn nhỏ, dùng chở đông đảo tu sĩ đi xa.","detail":"Dị chủng thanh quang điêu, yêu thú cấp năm tạp chủng, có thể biến hóa thân thể lớn nhỏ. Lạc Vân Tông dùng làm phương tiện chở đông đảo tu sĩ đến Bách Xảo Viện dự Thí Kiếm Đại Hội. Hai cánh giang ra che khuất cả sân, tạo cuồng phong khiến đệ tử thấp giai chao đảo.","congNang":["Vận chuyển đoàn tu sĩ đi xa","Biến hóa thân thể lớn nhỏ"],"chuSoHuu":[{"ten":"Lạc Vân Tông","tuChuong":"@c0624","denChuong":"","cachCoDuoc":"Sở hữu của tông môn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0624","loai":"xuat-hien","importance":"normal","giaiDoan":"Lạc Vân Tông đến Thí Kiếm Đại Hội","text":"Chở đông đảo tu sĩ Lạc Vân Tông bay đến Bách Xảo Viện, hai cánh giang ra che khuất cả sân tạo cuồng phong.","anchor":"Dị chủng thanh quang điêu này của Lạc Vân Tông chỉ là tạp chủng quái điểu"}]},"nguon":["@c0624"]},{"id":"lenh-bai-vang","name":"Lệnh bài vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tu sĩ áo vàng họ Việt"],"trangThai":"dang-su-dung","blurb":"Vật dụng chuyên dùng của tu sĩ họ Việt để mở cấm chế cấm địa ba phái. Phóng tia vàng và khói vàng làm tan bức vách, tạo thông đạo vài trượng.","detail":"Lệnh bài màu vàng, trên tay tu sĩ họ Việt xuất hiện khi cần mở cấm chế. Phóng tia vàng vào cửa đá dày đặc chú văn, khói vàng lan ra làm tan bức vách cấm chế, tạo thông đạo vài trượng cho người đi qua.","congNang":["Mở cấm chế cấm địa ba phái, tạo thông đạo nhất thời"],"chuSoHuu":[{"ten":"Tu sĩ áo vàng họ Việt","tuChuong":"@c0626","denChuong":"","cachCoDuoc":"Trấn thủ cấm địa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0626","loai":"dung","importance":"normal","giaiDoan":"Mở cấm chế cho đoàn người vào","text":"Tu sĩ họ Việt rút lệnh bài vàng phóng tia vàng vào cửa đá, khói vàng làm tan bức vách cấm chế nhiều tầng, tạo thông đạo vài trượng.","anchor":"trên tay xuất hiện một cái lệnh bài màu vàng"}]},"nguon":["@c0626"]},{"id":"binh-thuan-dich-trang","name":"Bình thuần dịch trắng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Đỗ Đông"],"trangThai":"đang sử dụng","blurb":"Bình nhỏ màu trắng chứa thuần dịch chiết từ Linh Nhãn Chi Thụ, được lão giả tóc rối chuẩn bị giao và Thiên Sát Chân Quân ném cho Đỗ Đông.","detail":"Thuần dịch chiết từ Linh Nhãn Chi Thụ, có thể thay thế chức năng linh thụ ở mức độ nhất định. Lão giả tóc rối lấy ra chuẩn bị giao thì bẫy phản gián sập; sau khi Thiên Sát Chân Quân phụ thân, ném bình cho Đỗ Đông mang đi.","congNang":["Chứa thuần dịch Linh Nhãn Chi Thụ, có thể thay thế chức năng linh thụ ở mức độ nhất định"],"chuSoHuu":[{"ten":"Vệ sư huynh","tuChuong":"@c0631","denChuong":"@c0631","cachCoDuoc":"Chiết từ Linh Nhãn Chi Thụ đang canh giữ","trangThai":"đã chuyển"},{"ten":"Đỗ Đông","tuChuong":"@c0631","denChuong":"","cachCoDuoc":"Thiên Sát Chân Quân ném cho","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0631","loai":"đổi chủ","importance":"normal","giaiDoan":"Lão giả tóc rối giao, Thiên Sát Chân Quân ném cho Đỗ Đông","text":"Lão giả tóc rối lấy bình thuần dịch ra chuẩn bị giao cho Đỗ Đông thì bị ba phái phục kích. Sau khi Thiên Sát Chân Quân phụ thân, cầm bình ném cho Đỗ Đông.","anchor":"trong tay bỗng nhiên cầm bình nhỏ chứa thuần dịch, vứt cho hai người Đỗ Đông"}]},"nguon":["@c0631"]},{"id":"huyen-thien-tien-dang","name":"Huyền Thiên Tiên Đằng","cn":"玄天仙藤","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":[],"trangThai":"chưa rõ","blurb":"Vật phẩm được Đỗ Đông coi là mục tiêu quan trọng nhất, lớn hơn cả Linh Nhãn Chi Thụ. Chi tiết chưa được tiết lộ.","detail":"Đỗ Đông tuyên bố Huyền Thiên Tiên Đằng mới là việc lớn, Linh Nhãn Chi Thụ chỉ là việc nhỏ. Chưa rõ hình dạng, vị trí hay công năng cụ thể.","nguon":["@c0631"]},{"id":"tieu-linh-can","name":"Tiểu linh căn Linh Nhãn Chi Thụ","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Một nhánh linh căn nhỏ Hàn Lập cắt từ Linh Nhãn Chi Thụ, chảy linh dịch trắng sữa thơm ngát, được cất trong hộp ngọc điêu khắc.","detail":"Hàn Lập dùng thanh mang cắt đứt một tiểu linh căn từ Linh Nhãn Chi Thụ, vài giọt linh dịch màu trắng sữa tràn ra từ chỗ cắt tỏa mùi thơm. Được cất vào hộp ngọc điêu khắc rồi bỏ trong Túi trữ vật. Đây là mục tiêu chính của Hàn Lập khi xâm nhập quang tráo.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0632","denChuong":"","cachCoDuoc":"Tự tay chặt từ Linh Nhãn Chi Thụ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0632","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập đắc linh căn","text":"Hàn Lập cắt đứt tiểu linh căn từ Linh Nhãn Chi Thụ, linh dịch trắng sữa tràn ra, cất vào hộp ngọc.","anchor":"một tiểu linh căn dễ dàng bị chặt đứt, theo sau vài giọt linh dịch màu trắng sữa từ chỗ bị cắt tràn ra"}]},"nguon":["@c0632"]},{"id":"ngoc-gian-luc-quang","name":"Ngọc giản lục quang","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"","soHuu":["Vệ sư huynh"],"trangThai":"dang-co","blurb":"Ngọc giản tỏa lục quang yếu ớt của lão giả họ Vệ, chứa công pháp tu luyện và phương pháp luyện chế Định Linh Đan cùng Minh Thanh Linh Thủy.","detail":"Đặt trên bồ đoàn vàng bên cạnh Linh Nhãn Chi Thụ trong quang tráo. Ghi lại công pháp tu luyện cùng đan dược tâm đắc của tu sĩ tóc rối (Vệ sư huynh), bao gồm phương pháp luyện chế Định Linh Đan và Minh Thanh Linh Thủy. Hàn Lập sao chép toàn bộ nội dung sang ngọc giản trống rồi đặt bản gốc lại chỗ cũ.","tabs":{"tienTrinh":[{"chuong":"@c0632","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện và sao chép","text":"Hàn Lập phát hiện ngọc giản lục quang bên linh thụ, sao chép nội dung sang ngọc giản trống rồi đặt bản gốc lại.","anchor":"ghi lại công pháp tu luyện cùng một ít đan dược tâm đắc của tu sĩ tóc rối, phương pháp luyện chế Định Linh Đan cùng Minh Thanh Linh Thủy bất ngờ cũng ở trong đó"}]},"nguon":["@c0632"]},{"id":"duong-hon-moc-chau","name":"Dưỡng Hồn Mộc Châu","cn":"养魂木珠","aliases":["Dưỡng Hồn Châu"],"category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Linh bảo tự động cường hóa thần thức cho người sở hữu, mỗi khi tu luyện công pháp thần thức lại phóng khí tức vào nguyên thần, tăng hiệu suất tu luyện gấp rưỡi. Là nguyên nhân chính giúp Hàn Lập đột phá chướng ngại Đại Diễn Quyết.","detail":"Từ khi Hàn Lập sở hữu châu này, thần thức không ngừng cường đại dù không tận lực rèn luyện. Mỗi khi tu Đại Diễn Quyết, châu phóng một cỗ khí tức nhè nhẹ đưa vào nguyên thần, tăng hiệu suất tu luyện gấp rưỡi. Nhờ đó Hàn Lập đột phá chướng ngại Đại Diễn Quyết một cách kỳ diệu.","congNang":["Tự động cường hóa thần thức cho người sở hữu dù không tận lực rèn luyện","Khi tu luyện công pháp thần thức, phóng khí tức vào nguyên thần tăng hiệu suất 50%"],"tabs":{"tienTrinh":[{"chuong":"@c0633","loai":"he-lo-cong-nang","importance":"major","giaiDoan":"Tiết lộ công năng cốt lõi","text":"Hé lộ Dưỡng Hồn Mộc Châu tự động cường hóa thần thức và bổ trợ tu luyện Đại Diễn Quyết, tăng hiệu suất gấp rưỡi, là nguyên nhân chính giúp Hàn Lập đột phá chướng ngại.","anchor":"từ Dưỡng Hồn Mộc Châu rõ ràng có một cỗ khí tức nhè nhẹ đưa vào trong nguyên thần"}]},"nguon":["@c0633"]},{"id":"cuu-khuc-linh-sam-dan","name":"Cửu Khúc Linh Sâm đan","cn":"九曲灵参丹","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Đan hoàn nhũ bạch cỡ ngón cái, trong suốt, linh quang chớp động, mùi thơm độc nhất vô nhị. Được Hàn Lập luyện từ tham dịch Cửu Khúc Linh Sâm, dùng hỗ trợ kết Nguyên Anh.","detail":"Đan dược kết anh do Hàn Lập luyện chế thành sau nhiều lần thất bại, nguyên liệu chính là tham dịch Cửu Khúc Linh Sâm cùng Mã Não Giác và Bạn Yêu Thảo. Toàn thân nhũ bạch trong suốt, có linh vụ trắng sữa di động trên bề mặt. Dược hiệu cụ thể chỉ biết khi nuốt vào kết anh.","congNang":["Hỗ trợ ngưng kết Nguyên Anh khi kết anh"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0634","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0634","loai":"xuất hiện","importance":"major","giaiDoan":"Luyện thành","text":"Hàn Lập luyện thành công Cửu Khúc Linh Sâm đan sau nhiều lần thất bại, nguyên liệu Mã Não Giác và Bạn Yêu Thảo gần cạn kiệt.","anchor":"Cửu Khúc Linh Sâm đan dược này, thật sự đã được luyện chế thành"}]},"nguon":["@c0634"]},{"id":"vien-chau-nguyen-anh","name":"Viên châu trong suốt","cn":"","category":"khac","categoryLabel":"Sản phẩm kết anh","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Quang đoàn ngũ sắc trên bầu trời ngưng tụ thành viên châu trong suốt cỡ nắm tay, ẩn chứa linh khí khổng lồ đáng sợ, là sản phẩm của quá trình kết Nguyên Anh.","detail":"Trong quá trình Hàn Lập kết Nguyên Anh, linh quang ngũ sắc trên bầu trời động phủ ngưng tụ thành quang đoàn, rồi tiếp tục ngưng tụ thành viên châu trong suốt lớn nhỏ cỡ nắm tay. Viên châu ẩn chứa linh khí khổng lồ đáng sợ, khiến tu sĩ xung quanh sắc mặt đại biến không dám vọng động.","hinhDang":"Trong suốt, cỡ nắm tay","dacDiem":"Ẩn chứa linh khí khổng lồ đáng sợ","congNang":["Ngưng tụ từ thiên địa linh khí trong quá trình kết Nguyên Anh"],"tabs":{"tienTrinh":[{"chuong":"@c0635","loai":"xuất hiện","importance":"normal","giaiDoan":"Ngưng tụ thành hình","text":"Quang đoàn ngũ sắc trên bầu trời động phủ Hàn Lập ngưng tụ thành viên châu trong suốt cỡ nắm tay, ẩn chứa linh khí khổng lồ.","anchor":"quang đoàn thật lớn trong ánh mặt mọi người ngưng tụ thành một viên châu trong suốt lớn nhỏ cở nắm tay"}]},"nguon":["@c0635"]},{"id":"dinh-nhan-dan","name":"Định Nhan Đan","cn":"定颜丹","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đã dùng","blurb":"Đan dược cố định dung mạo vĩnh viễn tại thời điểm uống, không thay đổi theo tuổi tác.","detail":"Hàn Lập tiết lộ từng dùng qua một viên Định Nhan Đan, khiến dung nhan duy trì ở hơn hai mươi tuổi mãi không đổi. Hai trưởng lão Lạc Vân Tông nghe nhắc đến loại đan dược này thì không lấy làm lạ, cho thấy đây là đan dược quen thuộc trong giới tu tiên.","congNang":["Cố định dung mạo vĩnh viễn tại thời điểm phục dụng, không thay đổi theo tuổi tác"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0637","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0637","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập tiết lộ đã dùng","text":"Hàn Lập tiết lộ với hai trưởng lão Lạc Vân Tông rằng từng dùng một viên Định Nhan Đan nên dung mạo giữ nguyên hơn hai mươi tuổi.","anchor":"từng dùng qua một viên Định nhan đan, dung nhan thủy chung duy trì tại thời khắc đó"}]},"nguon":["@c0637"]},{"id":"truyen-am-phu-ngon-mo","name":"Truyền Âm Phù Ngôn gia – Mộ gia","cn":"","category":"khac","categoryLabel":"Phù bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Hai tấm phù truyền âm một hồng một trắng do tộc trưởng Ngôn gia và Mộ gia gửi tới cáo lỗi Hàn Lập về việc Mộ Phái Linh tự nhận là thị thiếp.","detail":"Hai trương phù một hồng một trắng, khi nhận phù rung lên phát sáng cho thần thức xâm nhập đọc nội dung. Ngân Nguyệt giữ nguyên vẹn chờ Hàn Lập ra khỏi tĩnh thất.","congNang":["Truyền âm khoảng cách xa, cho thần thức xâm nhập đọc nội dung"],"nguon":["@c0640"]},{"id":"lenh-bai-cam-che-mau-tim","name":"Lệnh bài cấm chế màu tím","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"","soHuu":["Mộ Phái Linh"],"trangThai":"dang-dung","blurb":"Lệnh bài do Hàn Lập giao cho Mộ Phái Linh, dùng để tùy ý ra vào pháp trận cấm chế quanh động phủ của hắn.","detail":"Hàn Lập lấy từ trên người đặt lên bàn giao cho Mộ Phái Linh. Mang trên người có thể tùy ý ra vào bên trong pháp trận mà hắn bố trí quanh động phủ.","congNang":["Ra vào cấm chế pháp trận quanh động phủ Hàn Lập"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0642","denChuong":"@c0642","cachCoDuoc":"Tự chế/sở hữu","trangThai":"da-tang"},{"ten":"Mộ Phái Linh","tuChuong":"@c0642","denChuong":"","cachCoDuoc":"Được Hàn Lập giao","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0642","loai":"doi-chu","importance":"normal","giaiDoan":"Giao cho Mộ Phái Linh","text":"Hàn Lập lấy lệnh bài tím đặt lên bàn giao cho Mộ Phái Linh để nàng tùy ý ra vào pháp trận quanh động phủ.","anchor":"lấy từ trên người ra một khối lệnh bài màu tím đặt lên bàn"}]},"nguon":["@c0642"]},{"id":"canh-tinh","name":"Canh Tinh","cn":"庚星","aliases":["Duệ kim chi bảo"],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu luyện khí","phamCap":"Cực phẩm (quý hơn Luyện Tinh)","soHuu":[],"trangThai":"Chưa tìm được","blurb":"Tài liệu luyện khí cực hiếm còn gọi là Duệ kim chi bảo, trộn vào pháp bảo khiến độ sắc bén tăng gấp bội. Là điều kiện bắt buộc để bày Đại Canh Kiếm Trận.","detail":"Loại tài liệu cực hiếm ở tu tiên giới, được gọi là Duệ kim chi bảo. Trộn chút vào pháp bảo rồi bồi luyện làm độ sắc bén tăng gấp bội. Giá trị còn trên Luyện Tinh mà Hàn Lập đang sở hữu. Mấy ngàn năm ở cả Loạn Tinh Hải cũng chưa xuất hiện. Hàn Lập cần 72 phần Canh Tinh để trộn vào 72 phi kiếm bày Đại Canh Kiếm Trận nhưng không có chỗ trao đổi.","congNang":["Trộn vào pháp bảo rồi bồi luyện làm độ sắc bén tăng gấp bội","Chưa rõ công dụng cụ thể, chỉ biết là vật phẩm Hàn Lập ráo riết tìm kiếm"],"dacDiem":"Cực hiếm, mấy ngàn năm ở Loạn Tinh Hải chưa xuất hiện, quý hơn Luyện Tinh","capNhatToi":"@c0643","tabs":{"tienTrinh":[{"chuong":"@c0643","loai":"xuat-hien","importance":"normal","giaiDoan":"Được nhắc tới như điều kiện bắt buộc","text":"Hàn Lập nhận ra cần 72 phần Canh Tinh trộn vào phi kiếm để bày Đại Canh Kiếm Trận, nhưng vật này cực hiếm, mấy ngàn năm ở Loạn Tinh Hải chưa xuất hiện, không có chỗ trao đổi.","anchor":"chính là “Duệ kim chi bảo”rất hiếm người thấy"},{"chuong":"@c0677","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập công khai tìm kiếm","text":"Hàn Lập đem yêu đan và linh thảo ra đổi Canh tinh tại trao đổi hội nhưng không ai có. Thiên Tinh Chân Nhân lộ tia chần chờ khi nghe nhắc.","anchor":"Canh tinh? Lời Hàn Lập vừa ra khỏi miệng, ánh mắt tu sĩ bốn phía đều lộ ra vẻ cổ quái"}]},"nguon":["@c0643","@c0677"]},{"id":"cach-am-phu","name":"Cách âm phù","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["La huynh"],"trangThai":"dang-co","blurb":"Phù lục cách âm, hai tay bắt quyết khiến phù lóe sáng hóa một tầng bạch quang bao bọc toàn phòng, ngăn âm thanh lọt ra ngoài.","detail":"La huynh lấy Cách âm phù từ trong áo, hai tay bắt quyết khiến phù lóe sáng hóa bạch quang bao bọc toàn phòng để cách âm trước khi bàn chuyện nghi ngờ thân phận Hàn Lập.","congNang":["Cách âm, bao phủ toàn phòng bằng bạch quang ngăn âm thanh lọt ra ngoài"],"chuSoHuu":[{"ten":"La huynh","tuChuong":"@c0645","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0645","loai":"dùng","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"La huynh thi triển Cách âm phù bao phòng bạch quang để bàn riêng với đại hán về thân phận Hàn Lập.","anchor":"hóa thành một tầng bạch quang, đem toàn phòng bao bọc lại"}]},"nguon":["@c0645"]},{"id":"phi-kiem-ngu-khi-han-lap","name":"Phi kiếm ngự khí của Hàn Lập","category":"phap-bao","categoryLabel":"Pháp khí","phamCap":"Đỉnh cấp pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Phi kiếm ngự khí đỉnh cấp của Hàn Lập, bị Bành Dịch Song Hung nhận ra là vật tốt và trở thành lý do chúng nảy lòng đoạt bảo.","detail":"Kiện pháp khí phi kiếm ngự khí được tu sĩ ục ịch họ La đánh giá là đỉnh cấp pháp khí, vượt xa mức tán tu bình thường có thể sở hữu, trở thành một trong những căn cứ khiến Bành Dịch Song Hung quyết định giết chủ nhân để đoạt.","nguon":["@c0646"],"tabs":{"tienTrinh":[{"chuong":"@c0646","loai":"nhac-toi","importance":"normal","giaiDoan":"Bị nhắm tới","text":"Bị Bành Dịch Song Hung nhận ra là đỉnh cấp pháp khí, trở thành lý do chính chúng muốn đoạt bảo.","anchor":"sử dụng phi kiếm ngự khí nọ, rõ ràng chính là kiện đỉnh cấp pháp khí"}]}},{"id":"tui-linh-thu-han-lap","name":"Túi linh thú của Hàn Lập","category":"phap-bao","categoryLabel":"Pháp khí","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Vài túi linh thú bên người Hàn Lập, bị La huynh dùng làm bằng chứng hắn có xuất thân không tầm thường.","detail":"Mấy túi linh thú mà Hàn Lập mang bên người, bị Bành Dịch Song Hung chú ý vì tán tu bình thường không có khả năng nuôi nhiều linh thú như vậy.","nguon":["@c0646"]},{"id":"kim-don-phu","name":"Kim độn phù","cn":"","category":"phap-bao","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Đại hán đầu hói"],"trangThai":"da-dung","blurb":"Phù lục độn thuật cho phép người dùng hóa kim hồng bỏ chạy với tốc độ cao.","detail":"Đại hán đầu bóng lưỡng (Bành Dịch Song Hung) dán phù này lên người, hóa thành kim hồng bỏ chạy khi thấy Hàn Lập lộ tu vi Nguyên Anh. Tuy nhiên vẫn bị phi kiếm Thanh Trúc Phong Vân Kiếm của Hàn Lập đuổi kịp.","congNang":["Kim độn bỏ chạy, hóa kim hồng di chuyển tốc độ cao"],"tabs":{"tienTrinh":[{"chuong":"@c0647","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng và thất bại","text":"Đại hán đầu bóng dán phù lên người hóa kim hồng bỏ chạy nhưng bị phi kiếm Hàn Lập đuổi kịp chém chết.","anchor":"móc ra kim phù, vỗ lên trên người một cái"}]},"nguon":["@c0647"]},{"id":"hop-bach-ngoc-phong-kim-cau","name":"Hộp bạch ngọc phong kim cầu","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Hộp bạch ngọc dùng để chứa kim cầu giam Mộc Linh Anh, được dán phù lục cấm chế để phong cấm hoàn toàn.","detail":"Hàn Lập lấy hộp bạch ngọc từ túi trữ vật, đặt kim cầu chứa Mộc Linh Anh vào rồi đóng lại, dán phù lục cấm chế khiến tiếng la mắng bên trong ngưng hẳn.","nguon":["@c0648"]},{"id":"phu-luc-cam-che","name":"Phù lục cấm chế","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"da-dung","blurb":"Phù lục cấm chế được Hàn Lập dán lên hộp bạch ngọc chứa kim cầu, khiến âm thanh Mộc Linh Anh bên trong lập tức ngưng lại.","detail":"Lấy từ túi trữ vật, dán lên hộp bạch ngọc để phong cấm kim cầu giam Mộc Linh Anh, hiệu quả tức thì khiến tiếng la mắng ngừng hẳn.","nguon":["@c0648"]},{"id":"tui-linh-thu-dai-han-pho-gia","name":"Túi linh thú của đại hán Phó Gia","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đổi chủ","blurb":"Túi linh thú chứa trấn tộc linh thú Phó Gia, bị Hàn Lập thu sau khi giết đại hán Kết Đan sơ kỳ.","detail":"Bên hông đại hán Phó Gia mang mấy túi linh thú lớn nhỏ, trong đó chứa trấn tộc linh thú. Khi chủ chết, túi phát linh quang màu đen, bên trong truyền ra tiếng hí rống nổi giận rồi tắt. Bị Hàn Lập thu lại.","chuSoHuu":[{"ten":"Đại hán Phó Gia","tuChuong":"@c0650","denChuong":"@c0650","cachCoDuoc":"sở hữu ban đầu","trangThai":"chết"},{"ten":"Hàn Lập","tuChuong":"@c0650","denChuong":"","cachCoDuoc":"thu sau khi giết chủ cũ","trangThai":"đang giữ"}],"congNang":["Chứa linh thú, bao gồm trấn tộc linh thú Phó Gia"],"tabs":{"tienTrinh":[{"chuong":"@c0650","loai":"doi-chu","importance":"normal","giaiDoan":"Đại hán chết, Hàn Lập thu","text":"Đại hán Phó Gia bị Hàn Lập giết, túi linh thú phát linh quang đen rồi ảm đạm, bên trong trấn tộc linh thú hí rống nổi giận. Hàn Lập thu lại túi.","anchor":"Mà Túi linh thú trên tay đại hán vừa mới phát ra linh quang màu đen, trong nháy mắt ngay lúc đại hán chết, một lần nữa lại ảm đạm"}]},"nguon":["@c0650"]},{"id":"dao-cau-vong","name":"Đạo cầu vồng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (uy lực cấp Nguyên Anh)","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Pháp bảo tấn công dạng cầu vồng dài hơn mười trượng, phóng thanh mang chém giết. Trong khoảnh khắc giết ba tu sĩ Kết Đan Kỳ cùng hơn mười đệ tử Phó Gia.","detail":"Pháp bảo hình đạo cầu vồng dài hơn mười trượng, bay cuộn vào mục tiêu rồi xoay quanh phóng ra mười mấy đạo thanh mang chói mắt chém giết. Uy lực cực mạnh: giết tức thì ba tu sĩ Kết Đan Kỳ (tứ phân ngũ liệt) cùng hơn mười tu sĩ cấp thấp hơn (chặt đầu) mà không ai kịp nhìn thấy.","hinhDang":"Dạng cầu vồng dài hơn mười trượng","uyLuc":"Giết tức thì 3 Kết Đan Kỳ + hơn 10 tu sĩ cấp thấp trong khoảnh khắc","dacDiem":"Bay cuộn vào mục tiêu, xoay quanh phóng thanh mang chói mắt","congNang":["Phóng mười mấy đạo thanh mang chém giết mục tiêu","Tứ phân ngũ liệt tu sĩ Kết Đan Kỳ","Chặt đầu tu sĩ cấp thấp"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0651","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0651","loai":"dùng","importance":"major","giaiDoan":"Tàn sát đại sảnh Phó Gia bảo","text":"Bay cuộn vào đại sảnh Phó Gia bảo, xoay quanh ba tu sĩ Kết Đan Kỳ phóng thanh mang, giết ba Kết Đan cùng hơn mười đệ tử Phó Gia trong khoảnh khắc.","anchor":"một đạo cầu vồng dài hơn mười trượng giống như thiên ngoại phi tiên từ bên ngoài bay cuộn vào"}]},"nguon":["@c0651"]},{"id":"ngoc-gian-di-vat-tan-nhu-am","name":"Ngọc giản di vật của Tân Như Âm","cn":"","aliases":["Ngọc giản trận pháp thượng cổ"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Di vật Tân Như Âm lưu lại trước khi mất, ngọc giản màu xanh nhạt phong ấn bằng phù lục. Nội dung bí ẩn khiến phàm nhân xem bị phản phệ, Hàn Lập xác nhận trợ giúp rất nhiều.","detail":"Ngọc giản màu xanh nhạt, được phong ấn bằng phù lục vàng. Tổ mẫu phụ nhân năm xưa tò mò liếc xem nội dung liền hộc máu ba lần, hôn mê một ngày đêm, phải nhờ người chế phù phong ấn lại. Hàn Lập dễ dàng thổi luồng khói xanh phá phù lục, xem xong xác nhận nội dung trợ giúp rất nhiều rồi thu đi. Nội dung cụ thể chưa tiết lộ.","hinhDang":"Ngọc giản màu xanh nhạt","nguonGoc":"Di vật Tân Như Âm lưu trước khi bệnh mất, bảo quản qua nhiều thế hệ nha hoàn","dacDiem":"Phàm nhân hoặc tu sĩ yếu xem nội dung sẽ bị phản phệ hộc máu hôn mê","congNang":["Nội dung chưa rõ, Hàn Lập xác nhận trợ giúp rất nhiều"],"chuSoHuu":[{"ten":"Tân Như Âm","tuChuong":"","denChuong":"@c0653","cachCoDuoc":"Tự lưu giữ","trangThai":"đã mất (bệnh qua đời)"},{"ten":"Hàn Lập","tuChuong":"@c0653","denChuong":"","cachCoDuoc":"Nhận từ hậu nhân nha hoàn theo di ngôn","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0653","loai":"đổi chủ","importance":"major","giaiDoan":"Hàn Lập nhận di vật","text":"Phụ nhân hậu duệ nha hoàn đào hộp ngọc dưới gốc cây giao cho Hàn Lập. Hàn Lập phá phù lục phong ấn, xem nội dung ngọc giản xác nhận trợ giúp rất nhiều rồi thu đi.","anchor":"Thứ trong ngọc giản đích xác đối với ta trợ giúp rất nhiều"}]},"capNhatToi":"@c0653","nguon":["@c0653"]},{"id":"linh-nhan-chi-tuyen","name":"Linh Nhãn Chi Tuyền","cn":"灵眼之泉","category":"khac","categoryLabel":"Linh vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đã thu gọn thành viên châu","blurb":"Con suối linh tuyền trong mật thất động phủ cũ của Hàn Lập tại Thái Nhạc Sơn Mạch, phát tán linh khí trắng kinh người.","detail":"Linh tuyền Hàn Lập phát hiện từ thuở Trúc Cơ thành công, nằm trong mật thất động phủ dưới đống loạn thạch Thái Nhạc Sơn Mạch. Sau nhiều năm vẫn hoàn hảo không tổn hại. Hàn Lập dùng pháp thuật thu gọn toàn bộ thành viên châu cỡ nắm tay, cất vào hộp ngọc mang đi. Trong quá trình thu, cỗ linh khí trắng bắn xuyên nóc ra ngoài, thu hút sự chú ý của nhóm tu sĩ Quỷ Linh Môn.","congNang":["Phát tán linh khí trắng kinh người","Có thể thu gọn thành viên châu nhỏ gọn"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0655","denChuong":"","cachCoDuoc":"Thu hồi từ động phủ cũ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0655","loai":"đổi chủ","importance":"major","giaiDoan":"Hàn Lập thu hồi","phamCap":"Không rõ","text":"Hàn Lập trở về động phủ cũ tại Thái Nhạc Sơn Mạch, thi triển pháp thuật thu gọn toàn bộ Linh Nhãn Chi Tuyền thành viên châu cỡ nắm tay, cất vào hộp ngọc mang đi.","anchor":"Quang mang tăng vọt, bao phủ toàn bộ con suối bên trong, vạn phần chói mặt"}]},"nguon":["@c0655"]},{"id":"phe-linh-kiem","name":"Phệ Linh Kiếm","cn":"","aliases":["Phệ Kim Kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn gia (lịch đại chưởng quản)"],"trangThai":"phong-an","blurb":"Bảo kiếm ba màu do Hàn Lập luyện hơn 1000 con tam sắc Phệ Kim Trùng hợp thể mà thành, phun linh khí phong ấn làm vỏ kiếm, đặt tại tông đường Hàn gia làm bảo vật trấn gia.","detail":"Hàn Lập triệu hơn 1000 con tam sắc Phệ Kim Trùng từ túi linh thú, tụ lại hóa thành bảo kiếm ba màu, phun linh khí xanh bao phủ tạo vỏ kiếm phong ấn. Kiếm có khả năng tự hành giết địch; rút ra khỏi vỏ thì ngoài tông đường trong vòng mười dặm mọi sinh vật đều bị tiêu diệt. Chỉ người đeo ngọc bội chứa tinh khí Hàn Lập mới rút được kiếm. Kiếm chỉ sử dụng được ba lần, mỗi lần linh khí giảm, sau ba lần vỏ kiếm tan biến, linh trùng bay đi. Kiếm không thể di chuyển ra khỏi tông đường.","phanLoaiPhu":"Bảo vật trấn gia","hinhDang":"Bảo kiếm ba màu (tam sắc)","vatLieu":"Hơn 1000 con tam sắc Phệ Kim Trùng hợp thể + linh khí phong ấn làm vỏ","nguonGoc":"Do Hàn Lập luyện hóa linh trùng Phệ Kim Trùng mà thành","uyLuc":"Tự hành giết địch, rút kiếm thì trong vòng 10 dặm ngoài tông đường mọi sinh vật bị tiêu diệt","dacDiem":"Chỉ dùng được 3 lần rồi tan biến; không thể di chuyển ra khỏi tông đường; cần ngọc bội tinh khí mới rút được","chuHienThoi":"Hàn gia (lịch đại chưởng quản)","congNang":["Tự hành giết địch @c0660","Rút kiếm ra ngoài tông đường trong vòng 10 dặm tiêu diệt mọi sinh vật @c0660"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0660","denChuong":"@c0660","cachCoDuoc":"Tự luyện hóa","trangThai":"da-giao"},{"ten":"Hàn gia (lịch đại chưởng quản)","tuChuong":"@c0660","denChuong":"","cachCoDuoc":"Hàn Lập giao tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0660","loai":"xuat-hien","importance":"major","giaiDoan":"Hàn Lập luyện hóa và giao cho Hàn gia","text":"Hàn Lập triệu hơn 1000 con tam sắc Phệ Kim Trùng hợp thể thành bảo kiếm ba màu, phun linh khí phong ấn tạo vỏ kiếm, đặt tên Phệ Linh Kiếm, đặt tại tông đường Hàn gia làm bảo vật trấn gia kèm ngọc bội tinh khí. Kiếm chỉ dùng được 3 lần.","anchor":"Kiếm này là do ta luyện hoá linh trùng mà thành. Nó có khả năng tự hành giết địch"}]},"capNhatToi":"@c0660","nguon":["@c0660"]},{"id":"ngoc-boi-tinh-khi","name":"Ngọc bội tinh khí","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn gia (lịch đại chưởng quản)"],"trangThai":"dang-su-dung","blurb":"Khối ngọc trong suốt chứa tinh khí Hàn Lập, chìa khóa duy nhất để rút Phệ Linh Kiếm. Giao cho lịch đại chưởng quản Hàn gia truyền đời.","detail":"Miếng ngọc bội trong suốt chứa tinh khí của Hàn Lập. Chỉ người đeo ngọc bội này mới có thể rút Phệ Linh Kiếm ra khỏi vỏ. Hàn Lập giao cho Vân Thiên Khiếu, dặn truyền cho lịch đại chưởng quản Hàn gia.","congNang":["Cho phép rút Phệ Linh Kiếm ra khỏi vỏ @c0660"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0660","denChuong":"@c0660","cachCoDuoc":"Tự tạo","trangThai":"da-giao"},{"ten":"Vân Thiên Khiếu","tuChuong":"@c0660","denChuong":"","cachCoDuoc":"Hàn Lập giao tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0660","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập giao cho hậu nhân","text":"Hàn Lập giao ngọc bội chứa tinh khí cho Vân Thiên Khiếu, dặn truyền cho lịch đại chưởng quản Hàn gia.","anchor":"Còn đây là một miếng ngọc bội có chứa tinh khí của ta, chỉ những ai đeo ngọc bội này thì mới có thể rút kiếm ra khỏi vỏ"}]},"capNhatToi":"@c0660","nguon":["@c0660"]},{"id":"dan-duoc-luyen-vo","name":"Đan dược luyện võ (tặng Lệ gia)","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Lệ Phong"],"trangThai":"dang-su-dung","blurb":"Bảy tám bình đan dược có ích cho người luyện võ phàm nhân, Hàn Lập tặng Lệ Phong để cấp cho Lệ gia đề cao thực lực.","detail":"Bảy tám bình nhỏ đan dược, có ích cho người luyện võ phàm nhân, giúp đề cao thực lực mà không cần khổ công tu luyện. Hàn Lập lấy từ túi trữ vật tặng cho Lệ Phong.","congNang":["Đề cao thực lực luyện võ cho phàm nhân @c0660"],"nguon":["@c0660"]},{"id":"dan-duoc-keo-dai-tuoi-tho","name":"Đan dược kéo dài tuổi thọ","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Vân Thiên Khiếu","Lệ Phong"],"trangThai":"dang-su-dung","blurb":"Hai bình đan dược màu vàng, đối với phàm nhân có tác dụng kéo dài tuổi thọ, cường thân kiện thể, bảo đảm sống quá trăm tuổi.","detail":"Hai bình đan dược màu vàng do Hàn Lập tặng riêng cho Vân Thiên Khiếu và Lệ Phong. Đối với phàm nhân có thể kéo dài tuổi thọ, cường thân kiện thể, không bị bệnh tật ốm đau, bảo đảm sống quá trăm tuổi.","congNang":["Kéo dài tuổi thọ cho phàm nhân @c0660","Cường thân kiện thể, không bệnh tật @c0660"],"nguon":["@c0660"]},{"id":"moc-linh-anh","name":"Mộc Linh Anh","cn":"木灵婴","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Linh anh duy nhất mà Hạm Vân Chi và Liễu sư muội của Ngự Linh Tông đều muốn dung hợp để một bước lên trời. Bên trong chứa cấm chế cho phép cảm ứng đơn phương từ xa.","detail":"Mộc Linh Anh hiện nằm trên người Hàn Lập. Chỉ có duy nhất một, chứa cấm chế cho phép cảm ứng đơn phương vị trí từ xa. Hạm Vân Chi và nữ tử họ Liễu (Ngự Linh Tông) đều muốn dung hợp Mộc Linh Anh để đột phá cảnh giới. Hàn Lập phát hiện có đạo linh lực bí mật quanh quẩn bên người chính là do Mộc Linh Anh phát ra.","congNang":["Cho phép cảm ứng đơn phương vị trí từ xa","Dung hợp có thể giúp tăng cảnh giới (một bước lên trời)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0661","denChuong":"","cachCoDuoc":"Thu được từ trước","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0661","loai":"nhắc tới","importance":"major","giaiDoan":"Ngự Linh Tông truy tung vị trí Mộc Linh Anh","text":"Nhóm Ngự Linh Tông dùng bí công cảm ứng vị trí Mộc Linh Anh trên người Hàn Lập. Hàn Lập phát hiện linh lực bí mật quanh người. Mộc Linh Anh chỉ có một, Hạm Vân Chi và Liễu sư muội cạnh tranh kịch liệt để giành cơ hội dung hợp.","anchor":"Mộc Linh Anh chỉ có một, nàng cùng Hạm Vân Chi bình thường biểu hiện ra ngoài là sư tỷ sư muội","phamCap":"Không rõ"}]},"nguon":["@c0661"]},{"id":"phieu-linh-dai","name":"Phiêu Linh Đái","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Phụ nhân họ Lâm"],"trangThai":"dang-co","blurb":"Pháp bảo phong thuộc tính của phụ nhân họ Lâm, phối hợp Phong hỏa chi độn khiến tốc độ như hổ thêm cánh.","detail":"Pháp bảo phong thuộc tính mà phụ nhân họ Lâm tu luyện. Khi kết hợp với Phong hỏa chi độn, tốc độ tăng vượt bậc, đạt ngang Nguyên Anh Sơ Kỳ dù bản thân nàng chỉ Kết Đan Sơ Kỳ.","congNang":["Tăng tốc độ độn pháp, phối hợp Phong hỏa chi độn"],"dacDiem":"Phong thuộc tính","chuSoHuu":[{"ten":"Phụ nhân họ Lâm","tuChuong":"@c0662","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0662","loai":"xuất hiện","importance":"normal","giaiDoan":"Xuất hiện trong cuộc đào tẩu","text":"Phụ nhân họ Lâm dùng Phiêu Linh Đái phối hợp Phong hỏa chi độn, đạt tốc độ ngang Nguyên Anh Sơ Kỳ, chạy xa nhất bốn năm mươi dặm.","anchor":"bản thân nàng tu luyện một kiện pháp bảo phong thuộc tính “Phiêu Linh Đái” càng làm cho độn pháp như hổ thêm cánh"}]},"nguon":["@c0662"]},{"id":"dia-ngoc-luc-sac-theo-doi","name":"Đĩa ngọc lục sắc (bảo vật theo dõi)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hạm Vân Chi"],"trangThai":"đang sử dụng","blurb":"Đĩa ngọc lớn bằng bàn tay, trong suốt xanh biếc, vành khắc phù văn thượng cổ vàng bạc, tản linh khí lục sắc. Hiện quang điểm hồng theo dõi sinh tử và vị trí đồng bạn.","detail":"Bảo vật dùng theo dõi đồng bạn, trung tâm bóng loáng như gương, hiện các quang điểm hồng sắc lúc ẩn lúc hiện đại diện vị trí người được đánh dấu. Quang điểm tắt nghĩa là người đó đã chết. Hạm Vân Chi dùng để giám sát tình trạng nhóm đồng hành khi phân tán bỏ chạy.","congNang":["Theo dõi sinh tử và vị trí đồng bạn qua quang điểm hồng"],"chuSoHuu":[{"ten":"Hạm Vân Chi","tuChuong":"@c0663","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0663","loai":"xuất hiện","importance":"normal","giaiDoan":"Hạm Vân Chi dùng theo dõi đồng bạn","text":"Hạm Vân Chi cưỡi linh cầm trắng noãn phi hành, tay cầm đĩa ngọc lục sắc theo dõi vị trí đồng bạn qua quang điểm hồng, phát hiện bốn đệ tử Trúc Cơ gần như cùng lúc bị giết.","anchor":"trên đó bóng loáng trong như gương, có bảy tám quang điểm hồng sắc lúc ẩn lúc hiện lấp lóe không ngừng"}]},"nguon":["@c0663"]},{"id":"luc-duc-suong-cong","name":"Lục Dực Sương Công","cn":"六翼霜蜈","category":"khac","categoryLabel":"Kỳ trùng","phamCap":"Xếp hạng 18 trên bảng kỳ trùng","soHuu":["Liễu sư muội","Hàn Lập"],"trangThai":"Ấu trùng, chưa gỡ cấm chế nhận chủ","blurb":"Thượng cổ linh trùng thời kỳ hoang dã, huyết thống chân long thuộc tính băng, xếp hạng 18 trên bảng kỳ trùng. Hình dạng phi thiên ngô công toàn thân đen, lưng hai cánh trắng, phun băng sương. Khi trưởng thành sinh sáu cánh, hàn khí bao trùm trăm dặm đóng băng vạn vật.","detail":"Đám ấu trùng phi thiên ngô công (rét bay) lớn khoảng một thước, toàn thân đen, lưng mọc hai cánh trắng, phun băng sương trắng. Cùng loại thượng cổ linh trùng thời kỳ hoang dã như Phệ Kim Trùng, có huyết thống chân long thuộc tính băng. Khi trưởng thành sẽ sinh sáu cánh, hàn khí phun ra bao trùm trăm dặm đóng băng vạn vật. Thuộc quyền nữ tu Ngự Linh Tông (Liễu sư muội), bị Hàn Lập thu vào tay áo dễ dàng nhờ đã luyện hóa Kiền Lam Băng Diễm. Hàn Lập muốn chiếm nhưng cần ép chủ gỡ cấm chế nhận chủ trước.","phanLoaiPhu":"Kỳ trùng / thượng cổ linh trùng","hinhDang":"Phi thiên ngô công (rét bay) khoảng một thước, toàn thân đen, lưng hai cánh trắng","nguonGoc":"Thượng cổ linh trùng thời kỳ hoang dã, huyết thống chân long thuộc tính băng","congNang":["Phun hàn khí băng sương đóng băng vạn vật","Trưởng thành sinh sáu cánh, hàn khí trùm trăm dặm"],"uyLuc":"Ấu trùng: hàn khí chưa đủ mạnh. Trưởng thành: hàn khí bao trùm trăm dặm đóng băng vạn vật","dacDiem":"Huyết thống chân long thuộc tính băng, có cấm chế nhận chủ và cấm chế tự bạo","chuSoHuu":[{"ten":"Liễu sư muội","tuChuong":"@c0664","denChuong":"@c0664","cachCoDuoc":"Nuôi dưỡng","trangThai":"bi-cuop"},{"ten":"Hàn Lập","tuChuong":"@c0664","denChuong":"","cachCoDuoc":"Thu từ nữ tu Ngự Linh Tông, chưa gỡ cấm chế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0664","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện, bị Hàn Lập thu phục","phamCap":"Xếp hạng 18 trên bảng kỳ trùng","text":"Nữ tu Ngự Linh Tông thả đám ấu trùng Lục Dực Sương Công phun băng sương chống cự Hàn Lập nhưng vô hiệu vì hắn đã luyện Kiền Lam Băng Diễm. Hàn Lập thu hết vào tay áo, bắt sống nữ tử để ép gỡ cấm chế nhận chủ.","anchor":"chính là kỳ trùng Lục Dực Sương Công xếp hạng thứ mưới tám trên bảng"}]},"capNhatToi":"@c0664","nguon":["@c0664"]},{"id":"tho-linh-anh","name":"Thổ Linh Anh","cn":"土灵婴","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Linh Anh cấp Nguyên Anh","soHuu":["Ngự Linh Tông"],"trangThai":"đang giữ","blurb":"Một trong Ngũ Hành Linh Anh, được lão giả Kỳ Linh Sơn vô ý luyện chế ra vài năm trước, nhờ đó bí pháp Ngũ Hành Linh Anh mới được khôi phục.","detail":"Thổ Linh Anh được lão giả thạch thất vô ý luyện chế, là thành quả giúp khôi phục đại bí thuật Ngũ Hành Linh Anh đã thất truyền. Hiện do Ngự Linh Tông nắm giữ cùng hai Linh Anh khác.","nguon":["@c0665"]},{"id":"kim-linh-anh","name":"Kim Linh Anh","cn":"金灵婴","category":"khac","categoryLabel":"Linh Anh","phamCap":"Cực hiếm","soHuu":["Ngự Linh Tông"],"trangThai":"Ngự Linh Tông đang nắm giữ","blurb":"Loại Linh Anh thuộc tính kim, hiếm nhất trong năm loại. Ngự Linh Tông mới luyện chế được hơn mười năm trước, là điều kiện then chốt để tiến hành Dung hợp Linh Anh đại pháp.","detail":"Kim Linh Anh là loại Linh Anh thuộc tính kim cực hiếm, hiếm nhất trong năm loại Linh Anh cần thiết cho phép Dung hợp Linh Anh đại pháp. Hơn mười năm trước Ngự Linh Tông mới vô tình luyện chế thành công. Sau khi có Kim Linh Anh, tông môn mới tuyển mười tu sĩ Kết Đan làm ứng viên dung hợp và bắt đầu chuyên tu bí thuật liên quan.","boCha":"dung-hop-linh-anh-dai-phap","congNang":["Một trong 5 Linh Anh thuộc tính cần thiết cho phép Dung hợp Linh Anh đại pháp @c0666"],"chuSoHuu":[{"ten":"Ngự Linh Tông","tuChuong":"@c0666","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"xuat-hien","importance":"normal","giaiDoan":"Liễu Ngọc tiết lộ cho Hàn Lập","text":"Liễu Ngọc khai báo Kim Linh Anh là loại hiếm nhất, mới luyện được hơn mười năm trước, là mấu chốt khiến Ngự Linh Tông bắt đầu tuyển ứng viên dung hợp.","anchor":"Nhất là loại Kim Linh Anh hiếm thấy. Thẳng đến hơn mười năm trước, mới vô tình luyện chế được ra loại Linh Anh có thuộc tính này"}]},"nguon":["@c0666"]},{"id":"thiet-te-thu","name":"Thiết Tê Thú","cn":"铁犀兽","category":"khac","categoryLabel":"Linh thú","phamCap":"Quý hiếm","soHuu":["Hàn Lập"],"trangThai":"Bị Hàn Lập giam trong quang tráo","blurb":"Linh thú hình thanh ngưu, lưng có lân giáp, lực chiến ngang tu sĩ Kết Đan Trung Kỳ. Vốn là linh thú tổ truyền Phó Gia tại Nguyên Vũ Quốc, bị Hàn Lập đoạt sau khi diệt Phó Gia.","detail":"Thiết Tê Thú là linh thú quý hiếm hình dáng tựa thanh ngưu, lưng có lân giáp, sở hữu lực chiến ngang tu sĩ Kết Đan Trung Kỳ mà không hề rơi xuống hạ phong. Bị Hàn Lập nhốt trong quang tráo cấm chế thuộc tính thổ tại đại sảnh Lạc Vân Tông. Liễu Ngọc nhận ra đây là linh thú tổ truyền của Phó Gia tại Nguyên Vũ Quốc — gia tộc đã bị diệt. Hàn Lập dùng một đạo điện hồ cực nhỏ từ ngón tay đánh ngã nó dễ dàng để thị uy.","congNang":["Lực chiến ngang tu sĩ Kết Đan Trung Kỳ @c0666"],"chuSoHuu":[{"ten":"Phó Gia","tuChuong":"@c0666","denChuong":"@c0666","cachCoDuoc":"Tổ truyền","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0666","denChuong":"","cachCoDuoc":"Đoạt sau khi diệt Phó Gia","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0666","loai":"xuat-hien","importance":"normal","giaiDoan":"Hàn Lập thị uy trước Liễu Ngọc","text":"Hàn Lập dùng một đạo điện hồ cực nhỏ đánh ngã Thiết Tê Thú trong quang tráo để thị uy trước Liễu Ngọc. Liễu Ngọc nhận ra đây là linh thú tổ truyền Phó Gia Nguyên Vũ Quốc.","anchor":"cũng có một linh thú tổ truyền như vậy. Nghe nói có thể lực địch tu sĩ Kết Đan Trung Kỳ mà không hề rơi xuống hạ phong"}]},"nguon":["@c0666"]},{"id":"kiem-lam-bang-diem","name":"Kiềm Lam Băng Diễm","cn":"钳蓝冰焰","category":"khac","categoryLabel":"Dị hỏa","phamCap":"Chưa rõ","soHuu":["Hàn Lập"],"trangThai":"dang-luyen-hoa","blurb":"Dị hỏa màu xanh biếc đang được Hàn Lập luyện hóa, mỗi tia cần một năm, toàn bộ cần khoảng hai trăm năm. Hàn khí Lục Dực Sương Công có thể rút ngắn thời gian và tăng phúc cho nó.","detail":"Hàn Lập tiết lộ tiến độ luyện hóa Kiềm Lam Băng Diễm: mỗi tia cần một năm tiêu hóa, toàn bộ cần tối thiểu hai trăm năm. Hàn khí từ Lục Dực Sương Công phun ra có thể rút ngắn thời gian rất nhiều đồng thời có tác dụng tăng phúc kỳ diệu. Hàn Lập trình diễn dung hợp sương hoa trắng với băng diễm xanh biếc thành một con chim lửa màu tím nhỏ cỡ ngón tay bay múa linh hoạt.","congNang":["Dung hợp với sương hoa (hàn khí) tạo thành chim lửa tím (@c0667)","Hàn khí Lục Dực Sương Công rút ngắn thời gian luyện hóa và tăng phúc (@c0667)"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0667","denChuong":"","cachCoDuoc":"Chưa rõ (đang luyện hóa)","trangThai":"dang-luyen-hoa"}],"tabs":{"tienTrinh":[{"chuong":"@c0667","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Tiết lộ tiến độ luyện hóa và dung hợp sương hoa lam diễm","text":"Hàn Lập tiết lộ mỗi tia cần một năm, toàn bộ cần khoảng hai trăm năm luyện hóa. Hàn khí Lục Dực Sương Công rút ngắn thời gian và tăng phúc. Trình diễn dung hợp sương hoa trắng với băng diễm xanh thành chim lửa tím nhỏ bay múa linh hoạt.","anchor":"muốn đem tất cả băng diễm thành sở hữu của mình, tối thiểu cũng cần hai trăm năm thời gian"}]},"capNhatToi":"@c0667","nguon":["@c0667"]},{"id":"lenh-bai-den","name":"Lệnh bài đen","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Ngân Nguyệt"],"trangThai":"dang-dung","blurb":"Lệnh bài đen dùng để điều khiển linh thú gia tộc, phát ra hoàng quang bao trùm thú để khuất phục.","detail":"Hàn Lập lấy từ Túi trữ vật, vứt cho Ngân Nguyệt dùng để dạy dỗ tê thú. Lệnh bài bắn ra hoàng quang bao tê thú lại, tê thú phát ra tiếng kêu thê lương.","congNang":["Điều khiển, khuất phục linh thú gia tộc, phát hoàng quang bao trùm"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0668","denChuong":"@c0668","cachCoDuoc":"Có sẵn trong Túi trữ vật","trangThai":"da-giao"},{"ten":"Ngân Nguyệt","tuChuong":"@c0668","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0668","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập giao cho Ngân Nguyệt dùng dạy dỗ tê thú","text":"Hàn Lập lấy lệnh bài đen từ Túi trữ vật, vứt cho Ngân Nguyệt. Ngân Nguyệt dùng lệnh bài chiếu hoàng quang bao tê thú, truyền ra tiếng kêu thê lương.","anchor":"Hàn Lập từ trong Túi trữ vật móc ra một cái lệnh bài đen thui, vứt cho Ngân Nguyệt"}]},"nguon":["@c0668"]},{"id":"ma-diem-tim","name":"Ma diễm tím (vô danh)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Ma diễm vô danh Hàn Lập phát hiện khi hấp thu hàn khí rết Lục Dực Sương Công, uy lực hơn Kiền Lam Băng Diễm, tiềm năng ngang Tu La Thánh Hỏa.","detail":"Hàn Lập phát hiện ngẫu nhiên trong lúc hấp thu hàn khí từ rết Lục Dực Sương Công, uy lực vượt Kiền Lam Băng Diễm. Theo thời gian hàn khí Lục Dực Sương Công tăng mạnh, uy lực ma diễm cũng tăng theo, cuối cùng không kém Tu La Thánh Hỏa bao nhiêu. Ngân Nguyệt ban đầu ngỡ là Tu La Thánh Hỏa nhưng Hàn Lập phủ nhận.","congNang":["Ma diễm phòng thủ/tấn công, uy lực tăng theo hàn khí Lục Dực Sương Công"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0668","denChuong":"","cachCoDuoc":"Phát hiện ngẫu nhiên khi hấp thu hàn khí rết","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0668","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập tiết lộ với Ngân Nguyệt","text":"Hàn Lập cho biết ma diễm vô danh phát hiện khi hấp thu hàn khí Lục Dực Sương Công, uy lực hơn Kiền Lam Băng Diễm, tiềm năng ngang Tu La Thánh Hỏa.","anchor":"uy lực so với Kiềm Lam Băng Diễm thì tốt hơn"}]},"nguon":["@c0668"]},{"id":"truyen-tin-phu","name":"Truyền tín phù","cn":"传信符","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":["Lữ trưởng lão"],"trangThai":"dang-co","blurb":"Phù lục dùng để liên lạc, bắn ra đạo ánh sáng hóa lửa xuyên qua cấm chế báo tin cho người trong động phủ.","detail":"Lữ trưởng lão bắn ra một đạo ánh sáng từ Truyền tín phù, hóa thành lửa xuyên qua cấm chế bên ngoài động phủ Hàn Lập để báo tin có người đến thăm.","nguon":["@c0670"]},{"id":"ngoc-gian-ban-do-nam-lung-hau","name":"Ngọc giản bản đồ của Nam Lũng Hầu","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản chứa bản đồ chỉ đường đến địa điểm tụ hội bí mật tại giao dịch hội, do Nam Lũng Hầu bí mật trao cho Hàn Lập.","detail":"Nam Lũng Hầu sau tỷ thí thần thức đã bắn ngọc giản này cho Hàn Lập, bên trong chứa bản đồ dẫn đến nơi tụ hội bí mật vào ngày thứ tư khi giao dịch hội bắt đầu. Hàn Lập thu nhận nhưng không xem ngay, cất vào túi trữ vật.","congNang":["Chứa bản đồ dẫn đến nơi tụ hội bí mật"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0673","denChuong":"@c0673","cachCoDuoc":"Tự chuẩn bị","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0673","denChuong":"","cachCoDuoc":"Được Nam Lũng Hầu trao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0673","loai":"xuất hiện","importance":"normal","giaiDoan":"Được trao cho Hàn Lập","text":"Nam Lũng Hầu bắn ngọc giản chứa bản đồ cho Hàn Lập, mời tụ hội ngày thứ tư giao dịch hội.","anchor":"Ngọc giản này có một bản đồ, giao dịch hội bắt đầu vào thứ tư, đạo hữu theo bản đồ đó đến tụ hội"}]},"capNhatToi":"@c0673","dinhDanh":"goc","nguon":["@c0673"]},{"id":"mat-na-o-linh","name":"Mặt nạ ô linh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thiên Tinh Chân Nhân"],"trangThai":"đang sử dụng","blurb":"Mặt nạ gỗ điêu khắc có phù văn ẩn hiện, do Thiên Tinh Chân Nhân phát cho tu sĩ tham dự Giao hoán hội để che giấu thân phận.","detail":"Ô mộc điêu khắc thành mặt nạ, mặt ngoài phù văn ẩn hiện. Dán sát da thịt, cảm giác lành lạnh mềm nhuyễn nhẹ như không. Ngay cả thần thức cường đại cũng không thể nhìn xuyên qua. Thiên Tinh Chân Nhân phát cho Hàn Lập và Lữ Lạc tại Giao hoán hội Nguyên Anh kỳ.","phanLoaiPhu":"Mặt nạ ngụy trang","hinhDang":"Mặt nạ gỗ ô mộc điêu khắc, phù văn ẩn hiện trên bề mặt","vatLieu":"Ô mộc","congNang":["Che giấu dung mạo","Chặn thần thức dò xét"],"dacDiem":"Dán sát da thịt, lành lạnh mềm nhuyễn nhẹ như không, thần thức cường đại không nhìn xuyên qua","chuHienThoi":"Thiên Tinh Chân Nhân (phát cho khách dự hội)","chuSoHuu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"@c0675","denChuong":"","cachCoDuoc":"Tự chế/sở hữu sẵn","trangThai":"dang-co"},{"ten":"Hàn Lập","tuChuong":"@c0675","denChuong":"","cachCoDuoc":"Được Thiên Tinh Chân Nhân phát","trangThai":"dang-co"},{"ten":"Lữ Lạc","tuChuong":"@c0675","denChuong":"","cachCoDuoc":"Được Thiên Tinh Chân Nhân phát","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0675","loai":"xuất hiện","importance":"normal","giaiDoan":"Phát tại Giao hoán hội","text":"Thiên Tinh Chân Nhân phát mặt nạ ô linh cho Hàn Lập và Lữ Lạc để che giấu thân phận tại Giao hoán hội Nguyên Anh kỳ. Hỏa Long Đồng Tử từ chối vì vóc người đặc biệt.","anchor":"hai luồng bạch quang hiện lên xuất hiện một cái ô mộc điêu khắc thành mặt nạ. Mặt ngoài phù văn ẩn hiện"}]},"capNhatToi":"@c0675","nguon":["@c0675"]},{"id":"xich-tinh-chi","name":"Xích tinh chi","cn":"赤星芝","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Đỉnh bật tài liệu luyện đan hỏa thuộc tính","soHuu":["Hàn Lập"],"trangThai":"Hàn Lập sở hữu","blurb":"Linh chi ba ngàn năm thuộc loại Băng hỏa tinh chi, toàn thân hỏa hồng, chỉ sinh trưởng quanh dung nham. Cẩm bào tu sĩ ra giá mười vạn linh thạch, Hàn Lập đổi bằng thất cấp yêu đan thổ thuộc tính.","detail":"Xích tinh chi là linh chi ba ngàn năm, thuộc loại Băng hỏa tinh chi, toàn thân hỏa hồng, có khói đỏ xoay quanh. Chỉ sinh trưởng xung quanh dung nham, là tài liệu luyện đan hỏa thuộc tính đỉnh bật. Cẩm bào tu sĩ mất năm sáu năm khổ công mới có được, đem ra hội trao đổi tu sĩ Nguyên Anh với giá mười vạn linh thạch hoặc tài liệu thổ thuộc tính cùng cấp. Hàn Lập dùng một khỏa thất cấp yêu đan thổ thuộc tính đổi thành công. Hàn Lập nhận định linh chi có thể dùng lục dịch thúc giục tăng trưởng.","phanLoaiPhu":"Băng hỏa tinh chi","hinhDang":"Linh chi màu đỏ rực, toàn thân hỏa hồng, có khói đỏ xoay quanh","nguonGoc":"Sinh trưởng xung quanh dung nham, cẩm bào tu sĩ mất năm sáu năm khổ công thu được","dacDiem":"Linh chi 3000 năm, tài liệu luyện đan hỏa thuộc tính đỉnh bật, có thể dùng lục dịch thúc giục tăng trưởng","chuHienThoi":"Hàn Lập","congNang":["Tài liệu luyện đan hỏa thuộc tính đỉnh bật, có thể dùng lục dịch thúc giục tăng niên hạn"],"chuSoHuu":[{"ten":"Cẩm bào tu sĩ","tuChuong":"@c0676","denChuong":"@c0676","cachCoDuoc":"Năm sáu năm khổ công tìm được","trangThai":"da-ban"},{"ten":"Hàn Lập","tuChuong":"@c0676","denChuong":"","cachCoDuoc":"Đổi bằng thất cấp yêu đan thổ thuộc tính","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0676","loai":"đổi chủ","importance":"major","giaiDoan":"Cẩm bào tu sĩ trưng ra → Hàn Lập đổi được","text":"Cẩm bào tu sĩ trưng Xích tinh chi ba ngàn năm tại hội trao đổi Nguyên Anh, ra giá mười vạn linh thạch. Hàn Lập dùng một khỏa thất cấp yêu đan thổ thuộc tính đổi thành công.","anchor":"Hàn Lập đi vài bước đến trước mặt cẩm bào tu sĩ, bàn tay vừa lộn, một cái hộp ngọc liền xuất hiện"}]},"capNhatToi":"@c0676","dinhDanh":"goc","nguon":["@c0676"]},{"id":"khon-tien-hoan","name":"Khốn Tiên Hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nữ tu sĩ áo xanh nhạt"],"trangThai":"Chưa nhận chủ, đang được trao đổi","blurb":"Pháp bảo do nữ tu sĩ áo xanh nhạt tự luyện chế bằng kim tinh, kiêm công thủ, có thể vây địch hoặc hộ thân. Chưa nhận chủ, đem ra hội trao đổi Nguyên Anh.","detail":"Khốn Tiên Hoàn là pháp bảo do nữ tu sĩ áo xanh nhạt tinh thông luyện khí thuật tự luyện chế. Dùng kim tinh luyện thành, hình dạng tinh hoàn màu trắng cỡ một tấc, có thể biến lớn thành một trượng, trên bề mặt hiện ngân bạch sắc phù văn tản linh khí kinh người. Pháp bảo kiêm công thủ, dùng để vây địch hoặc hộ thân đều hiệu quả.","hinhDang":"Tinh hoàn màu trắng cỡ một tấc, biến lớn thành một trượng, trên bề mặt hiện ngân bạch sắc phù văn","vatLieu":"Kim tinh","dacDiem":"Kiêm công thủ, biến hóa lớn nhỏ, ngân bạch sắc phù văn tản linh khí","chuHienThoi":"Nữ tu sĩ áo xanh nhạt","congNang":["Kiêm công thủ, dùng vây địch hoặc hộ thân"],"chuSoHuu":[{"ten":"Nữ tu sĩ áo xanh nhạt","tuChuong":"@c0676","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"dang-ban"}],"tabs":{"tienTrinh":[{"chuong":"@c0676","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu trưng bày tại hội trao đổi","text":"Nữ tu sĩ áo xanh nhạt giới thiệu Khốn Tiên Hoàn do chính mình luyện chế bằng kim tinh, kiêm công thủ, chưa nhận chủ, biểu diễn tinh hoàn biến lớn thành một trượng.","anchor":"Dùng để vây địch hoặc hộ thân, cũng cực kỳ hiệu quả, là pháp bảo kiêm công thủ"}]},"capNhatToi":"@c0676","dinhDanh":"goc","nguon":["@c0676"]},{"id":"hon-thach","name":"Hồn Thạch","cn":"魂石","category":"nguyen-lieu","categoryLabel":"Nguyên liệu / Linh vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"Đang sử dụng (đổi một phần)","aliases":["Âm minh thú tinh"],"blurb":"Tên thượng cổ của Âm minh thú tinh, tinh thạch xanh ngọc phát ba động âm hàn kỳ lạ, được Thiên Tinh Chân Nhân ráo riết thu mua.","detail":"Hồn Thạch chính là Âm minh thú tinh mà Hàn Lập lấy được từ chỗ âm minh, chỉ khác cách gọi giữa cổ tu sĩ thượng cổ và người ở âm minh. Dạng tinh thạch xanh ngọc, phát ra ba động âm hàn, không thuộc thuộc tính mộc cũng không phải hồn khí thông thường. Viên mẫu Thiên Tinh Chân Nhân đưa ra chỉ cỡ ngón tay cái, còn viên Hàn Lập đưa ra đổi lớn cỡ trứng gà — cực kỳ hiếm. Khôi lỗi trong Hư Thiên Điện đều ngậm Hồn Thạch, cho thấy loại nguyên liệu này liên quan mật thiết đến việc vận hành khôi lỗi thượng cổ. Thiên Tinh Chân Nhân muốn thu thập nhiều Hồn Thạch, mưu đồ cụ thể chưa rõ.","nguon":["@c0678"]},{"id":"hang-linh-phu","name":"Hàng Linh Phù","cn":"降灵符","category":"khac","categoryLabel":"Phù lục / Mật phù","phamCap":"Cao cấp (mật phù ngũ hành)","soHuu":["Hàn Lập"],"trangThai":"Chưa luyện chế","blurb":"Mật phù ngũ hành uy lực cực lớn mà Hàn Lập dự định luyện chế, có thể cứu mạng ở thời điểm mấu chốt.","detail":"Hàng Linh Phù là phù lục cao cấp loại mật phù ngũ hành đặc thù, uy lực rất lớn theo ghi chép trên cốt phiến. Hàn Lập đã mua được nguyên liệu phụ trợ (giấy phù, mực cao cấp) tại phường thị phía tây Thành Điền Thiên, nhưng chưa tìm được bút chế phù đủ cấp — loại bút đỉnh cấp trong phường thị chỉ đủ chế phù lục cao cấp thông thường, không đủ cho mật phù này. Phù lục cao cấp tại tu tiên giới có khi còn quý hơn đỉnh cấp pháp khí. Chế phù sư Kết Đan kỳ cả Thiên Nam chỉ có mấy người, Nguyên Anh kỳ chuyên chế phù thì không có.","nguon":["@c0678"]},{"id":"tan-phu-mau-vang","name":"Tàn phù màu vàng","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Chưa rõ (nghi trân phẩm)","soHuu":["Tôn Hỏa"],"trangThai":"hu-hai","blurb":"Tờ phù lục màu vàng đã bị tàn phá gần một nửa, được Tôn Hỏa phát hiện trong đám phù lục cấp thấp và biến sắc giữ lại bằng mọi giá, ngụ ý giá trị đặc biệt.","detail":"Khi Tôn Hỏa chuẩn bị giao phù lục bồi thường cho chưởng quỹ, phát hiện tờ phù vàng tàn phá gần nửa liền lập tức giữ lại, phản ứng khẩn trương. Chưa rõ cấp bậc và công năng cụ thể. Tiêu đề chương nhấn mạnh tầm quan trọng.","congNang":[],"chuSoHuu":[{"ten":"Tôn Hỏa","tuChuong":"@c0679","denChuong":"","cachCoDuoc":"Có sẵn trong đám phù lục cấp thấp mang theo","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0679","loai":"xuat-hien","importance":"major","giaiDoan":"Tôn Hỏa phát hiện trong đám phù bồi thường","phamCap":"Chưa rõ","text":"Tôn Hỏa khi chuẩn bị giao phù lục cấp thấp bồi thường, nhìn thấy tờ phù vàng tàn phá gần nửa liền biến sắc giữ lại không giao, phản ứng khẩn trương cho thấy giá trị đặc biệt.","anchor":"lập tức từ trong đám phù lấy ra một cái phù lục màu vàng đã bị tàn phá gần một nữa giữ lại"}]},"nguon":["@c0679"]},{"id":"phu-luc-hai-nua","name":"Phù lục (hai nửa)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Hàn Lập","Tôn Hỏa"],"trangThai":"da-huy","blurb":"Tín vật hai nửa do Tôn Nhị Cẩu và Hàn Lập mỗi người giữ một phiến, dùng để nhận diện hậu nhân Tôn gia với chủ nhân.","detail":"Hàn Lập ghép nửa phù lục của Tôn Hỏa với nửa của mình, hai phiến hoàn toàn ăn khớp không một khe hở, xác nhận Tôn Hỏa là hậu nhân chính thống. Sau đó Hàn Lập phát hồng quang thiêu hủy cả hai phiến thành tro bụi.","congNang":["Tín vật nhận chủ giữa Hàn Lập và dòng tộc Tôn gia, ghép hai nửa xác nhận thân phận"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0680","denChuong":"@c0680","cachCoDuoc":"Giữ từ trước","trangThai":"da-huy"},{"ten":"Tôn Hỏa","tuChuong":"@c0680","denChuong":"@c0680","cachCoDuoc":"Thừa kế từ Tôn Nhị Cẩu","trangThai":"da-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c0680","loai":"dùng","importance":"normal","giaiDoan":"Ghép khớp rồi thiêu hủy","text":"Hàn Lập ghép hai nửa phù lục ăn khớp hoàn toàn, xác nhận Tôn Hỏa là hậu nhân Tôn Nhị Cẩu, rồi phát hồng quang thiêu hủy cả hai phiến thành tro bụi.","anchor":"đem hai phiến phù lục đến cùng nhau, chỗ hé ra hoàn toàn ăn khớp, một khe hở cũng không có"}]},"nguon":["@c0680"]},{"id":"hoa-van-phu","name":"Hỏa vân phù","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Thường phẩm","soHuu":[],"trangThai":"hong","blurb":"Phù lục bị chưởng quỹ tiệm tạp hóa bán lừa là hàng cao cấp, thực chất chỉ là hàng bình thường không phải do đại sư chế tạo.","detail":"Chưởng quỹ thừa nhận Hỏa vân phù bán trong hộp chỉ là hàng bình thường, không phải do đại sư chế tạo, tình nguyện nhận phạt từ chấp pháp sử.","nguon":["@c0680"]},{"id":"bich-lam-ngoc-boi","name":"Bích lam ngọc bội (tương xứng tâm linh)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Hàn Lập","Mộ Phái Linh"],"trangThai":"đang dùng","blurb":"Một đôi ngọc bội bích lam tương xứng tâm linh. Hàn Lập giữ một chiếc, tặng Mộ Phái Linh chiếc còn lại. Rót linh lực vào tạo tầng phòng hộ và cảm ứng dù cách ngàn dặm.","detail":"Đôi ngọc bội bích lam tương xứng tâm linh. Hàn Lập tặng Mộ Phái Linh một chiếc, tự giữ chiếc còn lại. Khi rót linh lực vào sẽ tạo một tầng phòng hộ, đồng thời cho phép Hàn Lập cảm ứng được ngay dù cách xa ngàn dặm.","congNang":["Tạo tầng phòng hộ khi rót linh lực","Cảm ứng cự ly ngàn dặm giữa hai chiếc trong đôi"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0681","denChuong":"","cachCoDuoc":"Tự có sẵn, giữ một chiếc","trangThai":"dang-co"},{"ten":"Mộ Phái Linh","tuChuong":"@c0681","denChuong":"","cachCoDuoc":"Hàn Lập tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0681","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập tặng Mộ Phái Linh một chiếc","text":"Hàn Lập trao cho Mộ Phái Linh một chiếc bích lam ngọc bội tương xứng tâm linh, dặn rót linh lực khi gặp nguy để hắn cảm ứng được dù cách ngàn dặm.","anchor":"chỉ cần rót linh lực vào đấy thì ta sẽ có mặt ngay lập tức"}]},"dinhDanh":"goc","nguon":["@c0681"]},{"id":"ngoc-gian-thuong-co-khoi-loi-thuat","name":"Ngọc giản Thượng cổ Khôi Lỗi Thuật","category":"khac","categoryLabel":"Ngọc giản","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Bạch ngọc giản gốc ghi chép thuật luyện chế Khôi Lỗi Thượng cổ, bản gốc không phải sao chép, có hình vẽ các loại tài liệu cần thiết. Thiên Tinh Chân Nhân trao cho Hàn Lập để đổi Hồn Thạch.","detail":"Bạch ngọc giản ghi chép phương pháp luyện chế Khôi Lỗi nhiều cấp (cao cấp ngang Nguyên Anh Trung Kỳ, cấp thấp ngang Kết Đan Kỳ). Là bản gốc, có kèm hình vẽ tài liệu cần thiết. Tài liệu chính gồm vạn năm thiết mộc cùng nhiều phụ liệu cực hiếm.","congNang":["Ghi chép phương pháp luyện chế Khôi Lỗi nhiều cấp (cao cấp và cấp thấp)"],"chuSoHuu":[{"ten":"Thiên Tinh Chân Nhân","tuChuong":"","denChuong":"@c0682","cachCoDuoc":"Tìm được","trangThai":"đã trao đi"},{"ten":"Hàn Lập","tuChuong":"@c0682","denChuong":"","cachCoDuoc":"Đổi bằng Hồn Thạch từ Thiên Tinh Chân Nhân","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0682","loai":"đổi chủ","importance":"major","giaiDoan":"Thiên Tinh Chân Nhân trao cho Hàn Lập","text":"Thiên Tinh Chân Nhân trao bạch ngọc giản gốc ghi Thượng cổ Khôi Lỗi Thuật cho Hàn Lập để đổi lấy hai ba mươi khối Hồn Thạch. Ngọc giản là bản gốc, có hình vẽ tài liệu cần thiết.","anchor":"Đây là cái ngọc giản có ghi chép lại cách luyện chế Khôi Lỗi, không phải là những cái sao chép"}]},"nguon":["@c0682"]},{"id":"canh-tinh-dau-gia-c682","name":"Canh Tinh (khối đấu giá)","category":"nguyen-lieu","categoryLabel":"Khoáng thạch","phamCap":"Không rõ","soHuu":["Tu sĩ ngân bào"],"trangThai":"đã bán","blurb":"Khối khoáng thạch Canh Tinh nhỏ bằng hạt hạch đào màu vàng, hào quang chớp động, được đấu giá với giá 76 vạn linh thạch tại Điền Thiên Thành. Hàn Lập bỏ cuộc ở mốc 50 vạn.","detail":"Khối Canh Tinh nhỏ bằng hạt hạch đào, màu vàng với hào quang chớp động. Được bán tại phiên đấu giá Điền Thiên Thành với giá cuối cùng 76 vạn linh thạch, vượt quá khả năng tài chính của Hàn Lập.","congNang":["Tài liệu cho Đại Canh Kiếm Trận"],"tabs":{"tienTrinh":[{"chuong":"@c0682","loai":"xuất hiện","importance":"normal","giaiDoan":"Đấu giá tại Điền Thiên Thành","text":"Khối Canh Tinh được đấu giá, Hàn Lập bỏ cuộc ở mốc 50 vạn, cuối cùng bán với giá 76 vạn linh thạch cho tu sĩ ngân bào.","anchor":"Bảy mươi sáu vạn linh thạch, khối Canh Tinh này là của đạo hữu"}]},"nguon":["@c0682"]},{"id":"khoi-loi","name":"Khôi Lỗi","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thương Khôn Thượng Nhân"],"trangThai":"da-dung","blurb":"Pháp bảo của Thương Khôn Thượng Nhân, tự bạo để tạo vụ nổ/chấn động che mắt đối phương, giúp hắn chạy thoát khi bị vây công năm nghìn năm trước.","detail":"Thương Khôn Thượng Nhân bị buộc phải tự bạo đi một cái Khôi Lỗi, sau đó thi triển đạo thuật thoát thân. Vật phẩm đã bị huỷ sau khi sử dụng.","congNang":["Tạo vụ nổ/chấn động khi tự bạo, che mắt đối phương tạo cơ hội thoát thân"],"tabs":{"tienTrinh":[{"chuong":"@c0684","loai":"dùng","importance":"normal","giaiDoan":"Tự bạo để thoát thân","text":"Thương Khôn Thượng Nhân tự bạo Khôi Lỗi khi bị vây công, tạo cơ hội thi triển đạo thuật chạy thoát.","anchor":"Mà hắn bị buộc phải tự bạo đi một cái Khôi Lỗi, sau đó thi triển đạo thuật dấu trời qua biển"}]},"chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"@c0684","denChuong":"","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-dung"}],"capNhatToi":"@c0684","nguon":["@c0684"]},{"id":"tinh-ban-di-bao","name":"Tinh bàn dị bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Dị bảo","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Đạm hồng sắc ngọc bàn hình tròn của Nam Lũng Hầu, kích hoạt bằng chú ngữ và kim quang, hiện đồ án nhật nguyệt thiên tượng xác định phương hướng trong bão cát khi thần thức bị phong tỏa.","detail":"Viên bàn ngọc hình tròn màu hồng nhạt. Khi kích hoạt bằng niệm chú bắt quyết và bắn kim quang, trên bề mặt xuất hiện kim tinh điểm điểm cùng đồ án kỳ quái ám ngậm tinh thần nhật nguyệt thiên tượng, dùng để xác định phương hướng trong môi trường bão cát phong tỏa thần thức.","hinhDang":"Ngọc bàn hình tròn, đạm hồng sắc","congNang":["Xác định phương hướng khi thần thức bị phong tỏa"],"dacDiem":"Kim hồng lưỡng sắc dị quang, phù văn lưu động","chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0687","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"dùng","importance":"normal","giaiDoan":"Sử dụng xác định phương hướng","text":"Nam Lũng Hầu lấy ra trong bão cát, niệm chú bắt quyết bắn kim quang kích hoạt, trên viên bàn hiện đồ án nhật nguyệt thiên tượng, xác định phương hướng dẫn đoàn bay đi.","anchor":"trên viên bàn kim tinh điểm điểm, xuất hiện ra một cái đồ án kỳ quái ám ngậm tinh thần nhật nguyệt thiên tượng"}]},"nguon":["@c0687"]},{"id":"ma-tran-phien","name":"Ma Trần Phiên","cn":"魔塵幡","category":"than-khi","categoryLabel":"Trấn tộc thánh khí","phamCap":"Trấn tộc thánh khí","soHuu":["Hoàng Sa Bộ"],"trangThai":"phong-an","blurb":"Trấn tộc thánh khí của Hoàng Sa Bộ, gồm 36 can. Có khả năng vây khốn Nguyên Anh tu sĩ nhất thời nửa khắc. Tổ huấn lịch đại cấm dùng nếu chưa tới lúc diệt tộc, vì hư hao sẽ mất tư cách dẫn đầu liên quân mười đại bộ tộc.","detail":"Bộ 36 can phiên (cờ/phướn), là trấn tộc thánh khí của Hoàng Sa Bộ. Uy lực đủ vây khốn tu sĩ Nguyên Anh Kỳ trong nửa khắc nhưng không đủ gây thương nặng. Lịch đại tổ tiên Hoàng Sa Bộ để lại tổ huấn: không tới lúc nguy cơ diệt tộc thì tuyệt đối không sử dụng. Nếu hư hao dù chỉ vài can, Hoàng Sa Bộ sẽ mất tư cách dẫn đầu liên quân mười đại bộ tộc, thậm chí có nguy cơ bị diệt tộc.","congNang":["Vây khốn tu sĩ cao giai (Nguyên Anh) trong nửa khắc"],"dacDiem":"36 can, điều kiện sử dụng cực kỳ nghiêm ngặt — chỉ khi nguy cơ diệt tộc","chuSoHuu":[{"ten":"Hoàng Sa Bộ","tuChuong":"@c0687","denChuong":"","cachCoDuoc":"Trấn tộc truyền thừa","trangThai":"phong-an"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"major","giaiDoan":"Hé lộ tồn tại và tổ huấn","text":"Pháp sĩ bạch quang đề nghị dùng Ma Trần Phiên vây nhóm tu sĩ. Đại Thượng Sư khiển trách nghiêm khắc, nhấn mạnh tổ huấn: không tới lúc diệt tộc tuyệt đối không sử dụng, hư hao sẽ mất tư cách dẫn đầu liên quân mười đại bộ tộc.","anchor":"Ba mươi sáu can Ma Trần Phiên đâu có thể tùy ý vận dụng"}]},"nguon":["@c0687"]},{"id":"ngu-phong-xa","name":"Ngự Phong Xa","cn":"御風車","category":"phap-bao","categoryLabel":"Trấn tộc bảo vật","phamCap":"Trấn tộc bảo vật","soHuu":["Thiên Phong Bộ","Pháp sĩ Mộ Lan"],"trangThai":"dang-co","blurb":"Trấn tộc bảo vật của Thiên Phong Bộ, có tốc độ kinh khủng, có thể đuổi theo tu sĩ nhưng cần tụ tập nhân thủ mới xuất phát.","detail":"Pháp bảo trấn tộc của Thiên Phong Bộ (bộ tộc Mộ Lan), có tốc độ di chuyển cực cao. Cần tụ tập đủ nhân thủ mới có thể xuất phát sử dụng.","congNang":["Di chuyển tốc độ cực cao","Bay tốc độ cực nhanh vượt xa độn quang thường","Chở nhiều người (ít nhất năm Nguyên Anh Kỳ)","Bạch quang bảo vệ che chắn bên trong","Phát ma âm xé gió khi bay"],"dacDiem":"Trấn tộc bảo vật Thiên Phong Bộ, cần tụ tập nhân thủ mới xuất phát","chuSoHuu":[{"ten":"Thiên Phong Bộ","tuChuong":"@c0687","denChuong":"","cachCoDuoc":"Trấn tộc truyền thừa","trangThai":"dang-co"},{"ten":"Pháp sĩ Mộ Lan (không rõ ai)","tuChuong":"@c0688","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ tồn tại","text":"Được pháp sĩ điện hồ nhắc tới khi phân tích: Thiên Phong Bộ có Ngự Phong Xa tốc độ kinh khủng có thể đuổi theo nhưng cần tụ nhân thủ mới xuất phát.","anchor":"lấy Thiên Phong Bộ pháp bảo “Ngự Phong Xa” có tốc độ kinh khủng cũng chưa chắc không phải là không thể đuổi theo mấy người này"},{"chuong":"@c0688","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện truy đuổi nhóm tu sĩ Thiên Nam","text":"Ngự Phong Xa chở năm pháp sĩ Nguyên Anh Kỳ Mộ Lan truy đuổi nhóm Nam Lũng Hầu sau khi rời Hoàng Sa Phong Trận. Bốn pháp sĩ xuống xe chia bốn hướng đuổi, Ngự Phong Xa quay sang nhắm riêng Hàn Lập truy đuổi vào sâu thảo nguyên.","anchor":"Ngự Phong Xa phần thân nhẵn nhụi trắng tinh, chẳng biết do xương thú nào luyện chế thành, mà lại ẩn chứa một cổ sát khí hung bạo"}]},"nguon":["@c0687","@c0688"]},{"id":"bao-chau-lam-muc-lao-gia","name":"Bảo châu lam (của Mục lão giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Mục lão giả"],"trangThai":"dang-dung","blurb":"Hạt châu to bằng nắm tay của Mục lão giả, có thể tạo quang mạc phòng thủ và kết quang võng chống đỡ cự kiếm.","detail":"Mục lão giả dùng một quyền tung bảo châu ra tạo lam quang mạc phòng thủ chặn kiếm quang. Sau đó phun tinh khí lên châu, châu phóng lam sắc tế ti kết thành quang võng chống đỡ được cự kiếm hợp nhất từ hơn 200 kiếm quang của Hàn Lập.","congNang":["Tạo lam quang mạc phòng thủ chặn kiếm quang","Phóng lam sắc tế ti kết quang võng chống đỡ cự kiếm"],"hinhDang":"Hạt châu to bằng nắm tay, phóng lam quang","chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0689","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0689","loai":"dùng","importance":"normal","giaiDoan":"Giao đấu với Hàn Lập","text":"Mục lão giả tung bảo châu tạo quang mạc chặn kiếm quang, sau phun tinh khí kết quang võng chống đỡ cự kiếm hợp nhất.","anchor":"xuất ra một khỏa hạt châu to bằng nắm tay"}]},"nguon":["@c0689"]},{"id":"hoa-lam-co-bao","name":"Hoa lam cổ bảo","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo (không rõ cấp)","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Cổ bảo băng thuộc tính của Hàn Lập, rời tay hóa bạch khí hút thu băng tinh, phát băng hàn linh lực kinh người khiến pháp sĩ tu luyện băng thuộc tính hơn trăm năm cũng lo sợ.","detail":"Long lanh trong suốt, xinh đẹp dị thường. Có thể hoạt động từ xa, cảm ứng linh lực băng hàn vượt trội. Khi xuất ra hóa bạch khí hút thu băng tinh của Băng Tinh Thuật, hóa giải hoàn toàn công kích băng thuộc tính.","hinhDang":"Long lanh trong suốt, hình hoa lam, xinh đẹp dị thường","congNang":["Hóa bạch khí hút thu/hóa giải băng hàn công kích","Phát băng hàn linh lực cảm ứng cực mạnh từ xa"],"dacDiem":"Hoạt động từ xa, cảm ứng linh lực băng hàn vượt trội","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0690","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0690","loai":"dùng","importance":"major","giaiDoan":"Lần đầu xuất hiện trong trận đấu","text":"Hàn Lập xuất hoa lam cổ bảo hóa bạch khí hút thu toàn bộ băng tinh của Băng Tinh Thuật. Mạc lão giả tu luyện băng thuộc tính hơn trăm năm kiêng dè lo sợ trước băng hàn linh lực kinh người của bảo vật này.","anchor":"vẫn cảm ứng băng hàn linh lực kinh người mặc dù có chút lạ lẫm làm cho lão giả kinh sợ"}]},"nguon":["@c0690"]},{"id":"vien-chau-phap-bao-muc-lao-gia","name":"Viên châu pháp bảo (Mục lão giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Mục lão giả"],"trangThai":"dang-dung","blurb":"Pháp bảo phòng ngự của Mục lão giả, triệu hồi về đỉnh đầu phun linh khí xuất quang mạc bảo hộ.","detail":"Được Mục lão giả triệu hồi sau khi bị Kinh Long chung chấn và cự kiếm truy kích, bay đến trên đỉnh đầu phun linh khí tạo quang mạc hộ thể.","congNang":["Xuất quang mạc hộ thể phòng ngự"],"chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0690","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0690","loai":"dùng","importance":"normal","giaiDoan":"Triệu hồi phòng ngự trong trận đấu với Hàn Lập","text":"Mục lão giả triệu hồi viên châu pháp bảo về đỉnh đầu, phun linh khí xuất quang mạc bảo hộ sau khi bị Kinh Long chung chấn và cự kiếm truy kích.","anchor":"pháp bảo này bay đến trên đỉnh đầu, trong miệng phun ra một tia linh khí"}]},"nguon":["@c0690"]},{"id":"thien-trong-phong","name":"Thiên Trọng Phong","cn":null,"aliases":["Hắc phong","ngọn hắc sơn","hắc sắc tiểu sơn","ngọn núi đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo thượng cổ","soHuu":["Mục lão giả"],"trangThai":"không rõ","blurb":"Cổ bảo thượng cổ hình ngọn núi đen, uy lực kinh người đến mức Nguyên Anh Hậu Kỳ cũng khó cường ngạnh đỡ.","detail":"Hàn Lập nhận định đây là cổ bảo thượng cổ tu sĩ lưu lại, không phải vật Mục lão giả tự luyện chế. Trong trận chiến phóng quang hoa lớn áp chế kiếm quang và ngân chung của Hàn Lập, giảm uy lực đại bộ phận. Hàn Lập muốn thu lấy để bù khuyết điểm công kích. Sau trận đấu Nguyên Anh chỉ thu bảo châu, hắc sơn có khả năng bị bỏ lại.","congNang":["Phóng quang hoa áp chế pháp bảo cấp Nguyên Anh"],"chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0691","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"thân xác bị hủy, hắc sơn có thể bị bỏ lại"}],"nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"dùng","importance":"major","giaiDoan":"Trận chiến Mục lão giả vs Hàn Lập","text":"Hắc sơn phóng quang hoa lớn áp chế kiếm quang và ngân chung của Hàn Lập, giảm uy lực đại bộ phận. Hàn Lập nhận định là cổ bảo thượng cổ, Nguyên Anh Hậu Kỳ khó đỡ, muốn thu để bù khuyết điểm công kích. Sau trận Nguyên Anh chỉ thu bảo châu, hắc sơn có khả năng bị bỏ lại.","anchor":"Bảo vật kỳ lạ có uy lực kinh người kia, vừa nhìn cũng biết không phải vật mà lão già này có thể luyện chế"}]}},{"id":"thanh-minh-cham-phu-bao","name":"Thanh Minh Châm","category":"phap-bao","categoryLabel":"Phù bảo","soHuu":["Hàn Lập"],"trangThai":"dang-co","nguon":["@c0691"],"tabs":{"tienTrinh":[{"chuong":"@c0691","loai":"dùng","importance":"normal","giaiDoan":"Tấn công Mục lão giả ở cự ly mười trượng","text":"Hàn Lập phóng Thanh Minh Châm, vô số thanh ti xuyên thủng quang mạc lam nhưng gặp Tinh Băng Thuẫn bị hóa thành băng châm rơi xuống, hoàn toàn thất hiệu.","anchor":"vô số thanh ti liền xuyên thủng quang mạc màu lam, trực tiếp kích khắp tứ phía băng thuẫn"}]}},{"id":"tui-tru-vat-muc-lao-gia","name":"Túi Trữ Vật màu bạc (của Mục lão giả)","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"","soHuu":["Hàn Lập"],"trangThai":"dang-dung","blurb":"Túi Trữ Vật màu bạc của Mục lão giả, bị Hàn Lập thu sau trận chiến. Bên trong nghèo nàn bất thường đối với tu sĩ Nguyên Anh Kỳ.","detail":"Chỉ chứa mười mấy khối Linh Thạch Bậc Trung, nguyên liệu luyện khí tầm thường, vài bình đan dược tàm thường, không có ngọc giản pháp quyết nào. Hàn Lập thất vọng vì không tìm được bí quyết phóng pháp thuật uy lực lớn trong nháy mắt.","chuSoHuu":[{"ten":"Mục lão giả","tuChuong":"@c0689","denChuong":"@c0692","cachCoDuoc":"","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0692","denChuong":"","cachCoDuoc":"Thu chiến lợi phẩm sau khi Mục lão giả bại trận","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0692","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập thu chiến lợi phẩm","text":"Hàn Lập thu Túi Trữ Vật màu bạc nhưng thất vọng vì bên trong chỉ có đồ tầm thường, không có ngọc giản pháp quyết.","anchor":"Đường đường là một gã tu sĩ Nguyên Anh Kỳ mà trên người chẳng có bao nhiêu thứ tốt"}]},"nguon":["@c0692"]},{"id":"ngan-sac-bao-vat-bach-sam-lao-gia","name":"Ngân sắc bảo vật (của Bạch sam lão giả)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bạch sam lão giả"],"trangThai":"dang-co","blurb":"Vật thể cỡ nắm tay phát ngân sắc tinh quang, Bạch sam lão giả há miệng phun ra, phiêu phù trước ngực. Uy lực đủ khiến hai pháp sĩ Nguyên Anh Sơ Kỳ kiêng dè lùi lại đề phòng.","detail":"Bạch sam lão giả há miệng phun ra vật thể ngân sắc cỡ nắm tay, tinh quang bắn bốn phía, phiêu phù trước ngực. Hai pháp sĩ Nguyên Anh Sơ Kỳ đối diện lập tức lui về phía sau đề phòng khi thấy bảo vật này xuất hiện.","congNang":["Khiến đối thủ Nguyên Anh Sơ Kỳ kiêng dè"],"hinhDang":"Cỡ nắm tay, ngân sắc, phun từ miệng","chuSoHuu":[{"ten":"Bạch sam lão giả","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0693","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Bạch sam lão giả há miệng phun ra vật ngân sắc cỡ nắm tay trước khi giao chiến với hai pháp sĩ Mộ Lan, khiến đối phương kiêng dè lùi lại.","anchor":"nhất điểm ngân sắc từ trong miệng phun ra"}]},"nguon":["@c0693"]},{"id":"kim-sac-phi-kiem-nam-lung-hau","name":"Kim sắc phi kiếm (của Nam Lũng Hầu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Phi kiếm kim sắc của Nam Lũng Hầu, được phóng ra từ tay áo khi chuẩn bị giao chiến với hai pháp sĩ Mộ Lan Nguyên Anh Sơ Kỳ.","detail":"Nam Lũng Hầu vung tay áo phóng ra kim sắc phi kiếm khi đối đầu hai pháp sĩ Mộ Lan, chuẩn bị giao chiến.","congNang":["Phi kiếm tấn công"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0693","loai":"xuat-hien","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nam Lũng Hầu vung tay áo phóng ra kim sắc phi kiếm chuẩn bị giao chiến với hai pháp sĩ Mộ Lan.","anchor":"một cái kim sắc phi kiếm từ trong tay áo bay ra"}]},"nguon":["@c0693"]},{"id":"truyen-am-phu","name":"Truyền Âm Phù","cn":"傳音符","category":"khac","categoryLabel":"Phù lục","phamCap":"Không rõ","soHuu":[],"trangThai":"da-dung","blurb":"Phù lục truyền tin từ xa, hóa hỏa quang bay đến. Ma quan pháp sĩ tiếp nhận, hồng quang bạo vỡ ra lộ hỏa diễm chứa thông tin, nội dung khiến hai pháp sĩ Mộ Lan kinh sợ rút lui.","detail":"Một đạo hỏa quang từ xa bay đến, ma quan pháp sĩ ngoắc tay tiếp nhận, hồng quang bạo vỡ ra lộ hỏa diễm trong lòng bàn tay. Nội dung Truyền Âm Phù liên quan đến lão giả họ Mục bị Hàn Lập đánh trọng thương chỉ còn Nguyên Anh chạy trốn, khiến ma quan pháp sĩ kinh hô, truyền âm cho áo lục pháp sĩ cũng biến sắc, cuối cùng hai người rút lui.","congNang":["Truyền tin từ xa"],"hinhDang":"Hóa hỏa quang bay, bạo vỡ thành hỏa diễm khi tiếp nhận","tabs":{"tienTrinh":[{"chuong":"@c0693","loai":"dung","importance":"normal","giaiDoan":"Ma quan pháp sĩ tiếp nhận","text":"Truyền Âm Phù bay đến giữa lúc hai bên sắp giao chiến, ma quan pháp sĩ đọc xong kinh hô, nội dung khiến hai pháp sĩ Mộ Lan kinh sợ rút lui, để ý đặc biệt đến Hàn Lập.","anchor":"Đây đúng là Truyền Âm Phù không biết từ nơi nào bay đến"}]},"nguon":["@c0693"]},{"id":"hai-la-tieu-ky-pha-cam-che","name":"Hai lá tiểu kỳ (phá cấm chế)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu","Bạch sam lão giả"],"trangThai":"dang-co","blurb":"Hai lá tiểu kỳ rộng cỡ vài thốn, một lá lục quang trong suốt, một lá màu vàng ẩn hiện phù văn. Nam Lũng Hầu và Bạch sam lão giả dùng để phá cấm chế ngoại tầng động phủ thượng nhân tại thạch sơn.","detail":"Nam Lũng Hầu và Bạch sam lão giả mỗi người rút ra một lá tiểu kỳ rộng cỡ vài thốn: một lá phát lục quang trong suốt, một lá màu vàng ẩn hiện phù văn di chuyển. Hai người niệm chú khiến tiểu kỳ run rẩy rồi phóng vào núi đá, kích hoạt cấm chế khiến mặt đất rung động dữ dội.","congNang":["Phá cấm chế ngoại tầng động phủ"],"hinhDang":"Rộng cỡ vài thốn, một lá lục quang trong suốt, một lá vàng có phù văn","chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"},{"ten":"Bạch sam lão giả","tuChuong":"@c0693","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0693","loai":"dung","importance":"normal","giaiDoan":"Phá cấm chế ngoại tầng thạch sơn","text":"Nam Lũng Hầu và Bạch sam lão giả niệm chú phóng hai lá tiểu kỳ vào núi đá, kích hoạt cấm chế ngoại tầng động phủ thượng nhân, mặt đất rung động dữ dội.","anchor":"tiểu kỳ nhanh như chớp chui vào núi đá mất tung mất tích"}]},"nguon":["@c0693"]},{"id":"loi-hoa-truy","name":"Lôi Hỏa Trùy","cn":"雷火锥","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ Bảo","soHuu":["Thai phu nhân"],"trangThai":"dang-co","blurb":"Cổ Bảo song thuộc tính lôi hỏa, hình tiêm trùy, tốc độ tự thân cực nhanh khiến tu sĩ Nguyên Anh Kỳ cũng khó tránh. Chuyên khắc chế cấm chế và vòng bảo hộ.","detail":"Bảo vật hình tiêm trùy (mũi nhọn), khi kích hoạt toàn thân hỏa hồng, trong hỏa quang có tia điện bạch sắc nhảy múa — thể hiện song thuộc tính lôi hỏa. Khi phun tinh quang lên, hỏa lãng cực nóng tràn khắp sảnh đường, tu sĩ Kết Đan Hậu Kỳ không chịu nổi phải dùng pháp bảo bảo hộ. Bay xoắn ốc trong đại sảnh với tốc độ cực nhanh, Hàn Lập đánh giá tu sĩ Nguyên Anh Kỳ cũng trốn không nổi, chỉ Phong Lôi Sí mới phòng bị được.","phanLoaiPhu":"Cổ Bảo song thuộc tính","hinhDang":"Hình tiêm trùy (mũi nhọn)","uyLuc":"Hỏa lãng cực nóng tràn khắp sảnh, tốc độ tự thân khiến Nguyên Anh Kỳ khó tránh","dacDiem":"Song thuộc tính lôi hỏa, Cổ Bảo cổ đại","congNang":["Phá cấm chế và vòng bảo hộ","Tấn công tốc độ cao bay xoắn ốc"],"chuSoHuu":[{"ten":"Thai phu nhân","tuChuong":"@c0694","denChuong":"","cachCoDuoc":"Sở hữu sẵn","trangThai":"dang-co"}],"chuHienThoi":"Thai phu nhân","tabs":{"tienTrinh":[{"chuong":"@c0694","loai":"xuat-hien","importance":"major","giaiDoan":"Thai phu nhân rút ra thi triển","text":"Thai phu nhân rút Lôi Hỏa Trùy ra để phá Thái Diệu Thần Cấm. Bảo vật lộ song thuộc tính lôi hỏa, hỏa lãng cực nóng tràn sảnh khiến tu sĩ Kết Đan Hậu Kỳ không chịu nổi. Tốc độ bay tự thân cực nhanh, Hàn Lập đánh giá Nguyên Anh Kỳ cũng trốn không nổi.","anchor":"một đạo sắc đạm đạm hồng bạch quang ảnh cấp tốc bay trong đại sảnh, tốc độ cực nhanh, như có như không"}]},"capNhatToi":"@c0694","nguon":["@c0694"]},{"id":"quyen-truc-ngan-bach","name":"Quyển trục ngân bạch","cn":"","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Chưa rõ","soHuu":["Bạch sam lão giả"],"trangThai":"đang được giữ tạm","blurb":"Quyển trục ngân quang lập lòe được thờ trên bàn thờ đen trước Ngọc Ki Các trong động phủ Thương Khôn Thượng Nhân. Mở ra lộ bức tranh nho sinh lưng đeo trường kiếm ngửa mặt nhìn trời, nghi là chân dung Thương Khôn Thượng Nhân.","detail":"Quyển trục dài chừng vài thước, bao bọc ngân quang lập lòe, đặt trên bàn thờ đen cổ kính ở vị trí trang trọng nhất trước Ngọc Ki Các. Khi mở ra lộ bức tranh vẽ nho sinh lưng đeo trường kiếm ngửa mặt nhìn trời. Lão giả họ Vân thử đánh pháp quyết vào bức tranh nhưng không có phản ứng dị thường, nhận định chỉ là bức tranh bình thường. Được tạm thu vào Túi Trữ Vật chờ phân chia sau.","congNang":["Chưa rõ — thử kích hoạt không có phản ứng, có thể cần điều kiện đặc biệt"],"dacDiem":"Ngân quang bao bọc, tranh vẽ nghi chân dung Thương Khôn Thượng Nhân","chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"@c0696","denChuong":"","cachCoDuoc":"chủ nhân gốc (thờ trong động phủ)","trangThai":"đã mất"},{"ten":"Bạch sam lão giả","tuChuong":"@c0696","denChuong":"","cachCoDuoc":"thu tạm giữ","trangThai":"đang giữ tạm"}],"tabs":{"tienTrinh":[{"chuong":"@c0696","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện trên bàn thờ trước Ngọc Ki Các","text":"Quyển trục ngân quang được phát hiện trên bàn thờ đen trước Ngọc Ki Các. Lão giả họ Vân dùng bạch hà phiến mở ra, lộ bức tranh nho sinh đeo kiếm ngửa mặt nhìn trời. Thử đánh pháp quyết không phản ứng, tạm thu vào Túi Trữ Vật.","anchor":"trên đó thờ phụng một bộ ngân bạch quyển trục dài chừng vài thước, ngân quang lập lòe"}]},"nguon":["@c0696"]},{"id":"co-bao-hinh-ong-truc","name":"Cổ Bảo hình ống trúc","category":"phap-bao","categoryLabel":"Cổ Bảo","phamCap":"Cổ Bảo (chưa rõ cấp)","soHuu":["Hàn Lập"],"trangThai":"đang sở hữu","blurb":"Cổ Bảo hình ống trúc mà Hàn Lập chọn lấy khi phân chia bảo vật tầng một Hư Thiên điện, chưa rõ uy lực và thần thông.","detail":"Một trong sáu Cổ Bảo tại tầng một Hư Thiên điện (động phủ Thương Khôn Thượng Nhân). Không cần tế luyện, có thể phát huy toàn bộ uy lực. Hàn Lập chọn lấy, thu vào túi trữ vật cùng phần tài liệu và đan dược được chia.","dacDiem":"Hình ống trúc","congNang":["Chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0697","denChuong":"","cachCoDuoc":"Chọn lấy khi phân chia bảo vật tầng một","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Phân chia bảo vật tầng một","text":"Hàn Lập chọn lấy Cổ Bảo hình ống trúc khi phân chia bảo vật, chưa rõ uy lực.","anchor":"Món cổ bảo tới tay Hàn Lập là một kiện Cổ Bảo hình ống trúc, cũng không biết uy lực của nó như thế nào"}]},"nguon":["@c0697"]},{"id":"tuong-vang-yeu-than","name":"Tượng vàng yêu thần ba đầu sáu tay","category":"khac","categoryLabel":"Tượng thờ","phamCap":"Không rõ","soHuu":["Thương Khôn Thượng Nhân"],"trangThai":"đặt tại điện thờ","blurb":"Tượng yêu thần một sừng ba đầu sáu tay, mặt dữ tợn, đặt trên điện thờ tầng hai Hư Thiên điện. Bộ dáng giống hệt yêu thú trên Phạm Thánh Chân Phiến.","detail":"Tượng vàng yêu thần một sừng ba đầu sáu tay trên điện thờ phòng ngủ Thương Khôn Thượng Nhân tại tầng hai Hư Thiên điện. Mắt trợn tròn, sáu tay giơ lên trời, mặt dữ tợn. Hàn Lập nhận ra bộ dáng giống như đúc yêu thú trên đồng phiến Phạm Thánh Chân Phiến, tim đập gấp. Trước tượng có hỏa hồng tiểu lô đỉnh phát khí trắng mang mùi đàn hương.","dacDiem":"Một sừng ba đầu sáu tay, mắt trợn tròn, giống yêu thú trên Phạm Thánh Chân Phiến","tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập phát hiện tại tầng hai","text":"Hàn Lập nhận ra tượng yêu thần giống hệt yêu thú trên Phạm Thánh Chân Phiến, gợi mối liên hệ sâu xa.","anchor":"Bộ dáng thần tượng này cùng Phạm Thánh Chân Phiến yêu thú trên đồng phiến giống nhau như đúc"}]},"nguon":["@c0697"]},{"id":"giuong-han-ngoc-xanh","name":"Giường hàn ngọc xanh","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Thương Khôn Thượng Nhân"],"trangThai":"đặt tại tầng hai Hư Thiên điện","blurb":"Giường bằng hàn ngọc xanh phát âm hàn khí, đặt tại phòng ngủ tầng hai Hư Thiên điện. Đầu giường có ba hộp ngọc lớn nhỏ gây tranh chấp.","detail":"Giường ngọc màu xanh bằng hàn ngọc điêu khắc, phát âm hàn khí, đặt đối diện điện thờ yêu thần tại tầng hai. Đầu giường có ba hộp ngọc lớn nhỏ không đồng nhất, chưa mở, khiến Bạch sam lão giả lao tới chụp nhưng bị chặn.","tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Khám phá tầng hai","text":"Giường hàn ngọc xanh phát âm hàn khí lộ diện tại phòng ngủ Thương Khôn Thượng Nhân, đầu giường có ba hộp ngọc gây tranh chấp.","anchor":"Đối diện một hướng khác của điện thờ có đặt một giường ngọc màu xanh"}]},"nguon":["@c0697"]},{"id":"ba-hop-ngoc-dau-giuong","name":"Ba hộp ngọc đầu giường","category":"khac","categoryLabel":"Vật phẩm bí ẩn","phamCap":"Không rõ","soHuu":["Thương Khôn Thượng Nhân"],"trangThai":"chưa mở","blurb":"Ba hộp ngọc lớn nhỏ không đồng nhất đặt ở đầu giường hàn ngọc tầng hai Hư Thiên điện, chưa mở, gây tranh chấp tức thì.","detail":"Ba hộp ngọc lớn nhỏ không đồng nhất phi thường đáng chú ý đặt tại đầu giường hàn ngọc xanh phòng ngủ Thương Khôn Thượng Nhân. Bạch sam lão giả lao tới chụp nhưng bị một nhân ảnh bắn hắc mang ngăn cản, mở đầu xung đột.","tabs":{"tienTrinh":[{"chuong":"@c0697","loai":"xuất hiện","importance":"normal","giaiDoan":"Tranh chấp khi vừa lên tầng hai","text":"Bạch sam lão giả lao tới chụp hộp ngọc nhưng bị hắc mang ngăn cản, mở đầu xung đột tầng hai.","anchor":"Tại một đầu giường ngọc, có ba cái hộp ngọc lớn nhỏ không đồng nhất phi thường đáng chú ý"}]},"nguon":["@c0697"]},{"id":"thanh-te-giap","name":"Thanh Tê Giáp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Áo giáp phòng hộ màu xanh mặc bên trong, chịu được đòn ám toán ngân luân Nguyên Anh trung kỳ, cứu mạng Nam Lũng Hầu.","detail":"Giáp có ánh sáng màu xanh, mặc bên trong y phục. Khi bị ngân luân của lão giả họ Vân đánh trúng, giáp bị lõm sâu nhưng không bị thủng, chặn đứng đòn tấn công phá hộ thể kim quang của Nguyên Anh trung kỳ. Lão giả họ Vân biết trước Nam Lũng Hầu có bảo vật này.","congNang":["Phòng ngự vật lý mạnh, chịu được đòn ám toán cấp Nguyên Anh trung kỳ"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0698","denChuong":"","cachCoDuoc":"Không rõ, mặc sẵn bên trong","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0698","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện khi Nam Lũng Hầu bị ám toán","text":"Nam Lũng Hầu bị lão giả họ Vân phóng ngân luân đánh trúng ngực, phá hộ thể kim quang. Thanh Tê Giáp mặc bên trong lộ ra, bị lõm sâu nhưng không thủng, cứu mạng chủ nhân. Lão giả họ Vân nhận ra bảo vật, ra lệnh đồng bọn không để Nam Lũng chạy thoát.","anchor":"lộ ra một khối giáp có ánh sáng màu xanh. Mặc dù bị lõm sâu vào, nhưng cũng không có bị thủng"}]},"dinhDanh":"goc","nguon":["@c0698"]},{"id":"ngan-luan-bach-sam-lao-gia","name":"Ngân luân","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Bạch sam lão giả"],"trangThai":"dang-co","blurb":"Vòng bạc phun từ miệng, tốc độ nhanh như tia chớp, dùng để ám toán phá hộ thể kim quang Nguyên Anh trung kỳ.","detail":"Pháp bảo tấn công dạng vòng bạc của lão giả họ Vân, phun ra từ miệng. Tốc độ cực nhanh, trong gang tấc đánh trúng ngực Nam Lũng Hầu, phá được hộ thể kim quang của tu sĩ Nguyên Anh trung kỳ trong một đòn bất ngờ.","congNang":["Tấn công tốc độ cao, phá hộ thể kim quang Nguyên Anh trung kỳ"],"chuSoHuu":[{"ten":"Bạch sam lão giả","tuChuong":"@c0698","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0698","loai":"dùng","importance":"major","giaiDoan":"Ám toán Nam Lũng Hầu","text":"Lão giả họ Vân phun ngân luân từ miệng ám toán Nam Lũng Hầu, nhanh như tia chớp đánh trúng ngực, phá hộ thể kim quang, gây trọng thương.","anchor":"một cái vòng bạc bắn ra, nhanh như tia chớp đánh tới trên người Nam Lũng Hầu trong gang tấc"}]},"dinhDanh":"goc","nguon":["@c0698"]},{"id":"ho-lu-xanh-tu-si-ho-vuu","name":"Hồ lô màu xanh (của tu sĩ họ Vưu)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tu sĩ họ Vưu","Hàn Lập"],"trangThai":"doi-chu","blurb":"Hồ lô màu xanh của tu sĩ họ Vưu, bắn ra điện hồ màu xanh chói mắt để tấn công.","detail":"Tu sĩ họ Vưu rút hồ lô xanh từ Túi trữ vật, bắn ra một đạo điện hồ màu xanh chói mắt nhắm vào Hàn Lập nhưng không ngăn được đối phương áp sát.","congNang":["Bắn điện hồ màu xanh chói mắt tấn công @c0699","Phóng điện hồ màu lam tấn công"],"chuSoHuu":[{"ten":"Tu sĩ họ Vưu","tuChuong":"@c0699","denChuong":"@c0700","cachCoDuoc":"Pháp bảo gốc","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0700","denChuong":"","cachCoDuoc":"Đoạt từ tu sĩ họ Vưu sau khi đóng băng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0699","loai":"dùng","importance":"normal","giaiDoan":"Chiến đấu với Hàn Lập","text":"Tu sĩ họ Vưu rút hồ lô xanh bắn điện hồ màu xanh chói mắt nhưng không ngăn được Hàn Lập áp sát.","anchor":"một đạo điện hồ màu xanh từ trong hồ lô bắn nhanh ra, rất chói mắt"},{"chuong":"@c0700","loai":"doi-chu","importance":"normal","giaiDoan":"Bị đoạt","text":"Tu sĩ họ Vưu dùng hồ lô phóng điện hồ lam tấn công Hàn Lập nhưng bị điện võng hấp thu. Sau khi chủ nhân bị đóng băng, Hàn Lập đoạt lấy.","anchor":"từ trong hồ lô đồng thời cũng bắn ra điện hồ màu lam, thế như sét đánh bay tới trước mắt Hàn Lập"}]},"nguon":["@c0699","@c0700"]},{"id":"tieu-thuan-tho-hoang-sac","name":"Tiểu thuẫn thổ hoàng sắc","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Thai phu nhân"],"trangThai":"binh-thuong","blurb":"Tiểu thuẫn phòng thủ màu hoàng thổ của Thai phu nhân, dùng chắn đỡ kim quang của Nam Lũng Hầu.","detail":"Thai phu nhân hoảng hốt triệu ra tiểu thuẫn thổ hoàng sắc trước người để chống đỡ kim quang tấn công của Nam Lũng Hầu.","nguon":["@c0700"]},{"id":"khai-son-ky","name":"Khai Sơn Kỳ","cn":"开山旗","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Tiểu kỳ màu vàng của Nam Lũng Hầu, dùng phá cấm chế thạch bích mở đường thoát.","detail":"Tiểu kỳ màu vàng xoay tròn trên tay, phóng ra hoàng mang chui vào thạch bích để phá cấm chế mở đường. Chỉ có một cây nên cần thời gian phá. Nam Lũng Hầu dùng khi đào thoát khỏi Hư Thiên điện.","nguon":["@c0701"],"congNang":["Phá cấm chế thạch bích, mở đường thoát"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0701","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"dùng","importance":"normal","giaiDoan":"Nam Lũng Hầu dùng phá thạch bích","text":"Nam Lũng Hầu dùng Khai Sơn Kỳ phá cấm chế thạch bích trong Hư Thiên điện để mở đường thoát, chỉ có một cây nên cần thời gian.","anchor":"chỉ có một cây Khai Sơn Kỳ, cho nên cần một chút thời gian"}]}},{"id":"co-bao-bat-vang-nam-lung-hau","name":"Cổ bảo bát vàng (của Nam Lũng Hầu)","cn":"","category":"phap-bao","categoryLabel":"Cổ bảo","phamCap":"","soHuu":["Nam Lũng Hầu"],"trangThai":"dang-co","blurb":"Bát vàng lớn cổ bảo của Nam Lũng Hầu, tạo lồng sáng vây nhốt tu sĩ Nguyên Anh tạm thời.","detail":"Bát màu vàng thật lớn phiêu phù không trung, phía dưới tạo lồng sáng mờ vây nhốt đối thủ. Bên trong hắc quang bạch khí chớp động kèm tiếng sấm bạo liệt. Uy lực đủ vây tu sĩ Nguyên Anh (lão giả họ Vân và Vương Thiên Cổ) nhưng không bền, chỉ tạm thời.","nguon":["@c0701"],"congNang":["Vây nhốt đối thủ tạm thời bằng lồng sáng"],"chuSoHuu":[{"ten":"Nam Lũng Hầu","tuChuong":"@c0701","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"dùng","importance":"normal","giaiDoan":"Vây nhốt lão giả họ Vân và Vương Thiên Cổ","text":"Nam Lũng Hầu dùng cổ bảo bát vàng tạo lồng sáng vây nhốt lão giả họ Vân và Vương Thiên Cổ tạm thời để tranh thủ đào thoát.","anchor":"một cái bát màu vàng thật lớn phiêu phù ở không trung, phìa dưới có cái lồng sáng mờ"}]}},{"id":"sau-hop-ngoc-thuong-khon-thuong-nhan","name":"Sáu hộp ngọc Thương Khôn Thượng Nhân","cn":"","category":"khac","categoryLabel":"Vật chứa / Cổ bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"4/6 trong tay Hàn Lập","blurb":"Sáu hộp ngọc trong suốt do Thương Khôn Thượng Nhân lưu lại ở Cổ Bảo tầng hai, có đặc tính che dấu linh khí của vật bên trong.","detail":"Thương Khôn Thượng Nhân lưu lại tổng cộng sáu hộp ngọc trong suốt ở Cổ Bảo tầng hai. Bên ngoài có phong ấn bạch sắc linh quang, Hàn Lập dễ dàng phá bằng thanh sắc linh quang. Hộp ngọc có công năng che dấu linh khí của bảo vật bên trong, nhờ đó Ngân Nguyệt mới lén lấy được ba cái mà không bị các tu sĩ Nguyên Anh phát hiện. Hàn Lập đã có một từ trước, tổng cộng bốn trong sáu hộp giờ nằm trong tay hắn.","congNang":["Che dấu linh khí bảo vật bên trong, qua mắt thần thức tu sĩ Nguyên Anh @c0703"],"chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc lưu lại trong Cổ Bảo","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0703","denChuong":"","cachCoDuoc":"Ngân Nguyệt lén lấy 3 + đã có 1 từ trước","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"đổi chủ","importance":"major","giaiDoan":"4/6 hộp rơi vào tay Hàn Lập","text":"Ngân Nguyệt lén lấy ba hộp ngọc ở Cổ Bảo tầng hai nhờ độn thuật kết hợp tính năng che linh khí. Cộng một hộp Hàn Lập đã có, tổng cộng bốn trong sáu hộp ngọc Thương Khôn Thượng Nhân giờ thuộc về Hàn Lập.","anchor":"Thương Khôn Thượng Nhân tổng cộng lưu lại sáu cái hộp ngọc, nhưng trong đó bốn cái đã ở trong tay ta"}]},"nguon":["@c0703"]},{"id":"ngoc-gian-lam-nhat","name":"Ngọc giản lam nhạt","cn":"","category":"khac","categoryLabel":"Bảo vật / Thông tin","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Ngọc giản màu lam nhạt nằm trong hộp ngọc thứ nhất của Thương Khôn Thượng Nhân, nội dung bí ẩn chưa tiết lộ.","detail":"Nằm trong hộp ngọc thứ nhất. Hàn Lập đắm thần thức vào đọc, biểu cảm không thay đổi suốt quá trình, cuối cùng cau mày trầm ngâm rồi cất đi mà không tiết lộ nội dung cho Ngân Nguyệt, cho thấy nội dung quan trọng hoặc nhạy cảm.","chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0703","denChuong":"","cachCoDuoc":"Lấy từ hộp ngọc thứ nhất","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở hộp ngọc thứ nhất","text":"Hàn Lập phá phong ấn bạch sắc mở hộp ngọc thứ nhất, lấy ngọc giản lam nhạt ra đọc bằng thần thức, cau mày trầm ngâm rồi cất đi mà không tiết lộ nội dung.","anchor":"cuối cùng Hàn Lập thần sắc vừa động đem thần thức thu hồi, cau mày trầm ngâm đứng lên"}]},"nguon":["@c0703"]},{"id":"nhan-den","name":"Nhẫn đen","cn":"","category":"phap-bao","categoryLabel":"Pháp khí / Bảo vật bí ẩn","phamCap":"Không rõ (bề ngoài là pháp khí bình thường)","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Chiếc nhẫn đen thui vô quang nằm trong hộp ngọc thứ hai của Thương Khôn Thượng Nhân, tài liệu cổ quái, công dụng chưa rõ.","detail":"Nằm trong hộp ngọc thứ hai. Tinh xảo lung linh nhưng đen thui vô quang, tài liệu cổ quái, linh khí rất ít. Hàn Lập phán đoán bề ngoài chỉ là pháp khí bình thường, nhưng tin rằng Thương Khôn Thượng Nhân đặc ý cất giữ trong hộp ngọc phong ấn thì chắc chắn phải có công dụng, có thể là công dụng lớn sau này.","chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"","cachCoDuoc":"Chủ gốc","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0703","denChuong":"","cachCoDuoc":"Lấy từ hộp ngọc thứ hai","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0703","loai":"xuất hiện","importance":"normal","giaiDoan":"Mở hộp ngọc thứ hai","text":"Hàn Lập mở hộp ngọc thứ hai, bên trong là chiếc nhẫn đen thui vô quang, tài liệu cổ quái nhưng linh khí ít, phán đoán là pháp khí bình thường nhưng tin rằng có công dụng đặc biệt.","anchor":"Tài liệu có chút cổ quái, nhưng hẳn chỉ là nhất kiện pháp khí bình thường, có tác dụng cụ thể gì cũng khó mà nói"}]},"nguon":["@c0703"]},{"id":"tu-van-dau","name":"Tử Vân Đấu","cn":"紫云斗","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ Bảo đỉnh bậc (kém Thông thiên linh bảo)","soHuu":["Hàn Lập","Ngân Nguyệt"],"trangThai":"dang-co","blurb":"Hồng hoang Cổ Bảo phòng ngự đỉnh bậc, tử sắc tinh võng mềm mại trong suốt. Phòng ngự phạm vi trăm trượng đến ngàn trượng, bảo hộ sinh linh trăm dặm, đồng thời vây địch và phóng thích Ngọc Dương Chân Hỏa diệt sát cường địch.","detail":"Hàn Lập thu được từ hộp ngọc chiến lợi phẩm. Hình dáng là kiện tử sắc tinh võng trong suốt mềm mại, khi kích hoạt hóa thành tử vụ xoay quanh đỉnh đầu rồi hiện nguyên hình ti võng. Ngân Nguyệt nhận ra từ ký ức trước khi bị luyện hóa thành khí linh, xác nhận là hồng hoang Cổ Bảo danh khí không nhỏ, phòng ngự phạm vi lớn bậc nhất — có thể che kín từ trăm trượng đến ngàn trượng, bảo hộ sinh linh trong trăm dặm. Ngoài phòng ngự còn có thể vây địch và phóng thích Ngọc Dương Chân Hỏa để diệt sát cường địch. Đoán nguồn gốc từ Trụy Ma Cốc. Ngân Nguyệt thừa nhận hình như từng sở hữu kiện tương tự trước kiếp.","hinhDang":"Tử sắc tinh võng trong suốt mềm mại, khi kích hoạt hóa thành tử vụ xoay quanh đỉnh đầu","nguonGoc":"Hồng hoang Cổ Bảo, đoán đến từ Trụy Ma Cốc","congNang":["Phòng ngự phạm vi lớn: che kín trăm trượng đến ngàn trượng, bảo hộ sinh linh trăm dặm","Vây địch và phóng thích Ngọc Dương Chân Hỏa diệt sát cường địch","Phóng tử võng thoắt ẩn thoắt hiện chụp bắt đối phương","Miễn nhiễm kiếm khí và lục hỏa","Cầm cố tu sĩ Nguyên Anh trung kỳ","Phát động Ngọc Dương Chân Hỏa"],"chuSoHuu":[{"ten":"Thương Khôn Thượng Nhân","tuChuong":"","denChuong":"@c0704","cachCoDuoc":"Không rõ (có trong hộp ngọc của vị này)","trangThai":"da-mat"},{"ten":"Hàn Lập","tuChuong":"@c0704","denChuong":"","cachCoDuoc":"Thu từ hộp ngọc chiến lợi phẩm","trangThai":"dang-co"},{"ten":"Ngân Nguyệt","tuChuong":"@c0717","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"dang-co"}],"capNhatToi":"@c0704","tabs":{"tienTrinh":[{"chuong":"@c0704","loai":"xuat-hien","importance":"major","giaiDoan":"Hàn Lập phát hiện và thu được","phamCap":"Cổ Bảo đỉnh bậc","text":"Hàn Lập mở hộp ngọc chiến lợi phẩm, phát hiện kiện tử sắc tinh võng mềm mại, kích hoạt hóa thành tử vụ. Ngân Nguyệt nhận ra là Tử Vân Đấu, hồng hoang Cổ Bảo phòng ngự đỉnh bậc, phạm vi trăm-ngàn trượng, phóng Ngọc Dương Chân Hỏa diệt địch.","anchor":"Vật này không phải là Tử Vân Đấu sao chứ? Đây chính là hồng hoang Cổ Bảo danh khí không nhỏ"},{"chuong":"@c0717","loai":"dùng","importance":"normal","giaiDoan":"Bắt sống đại trưởng lão","text":"Ngân Nguyệt dùng Tử Vân Đâu phóng tử võng chụp bắt nữ tử băng lãnh đang xuyên đỉnh trốn thoát, cầm cố đối phương dù bị hắc bạch kiếm khí và lục hỏa tấn công cũng không hao tổn.","anchor":"vô luận là hắc bạch kiếm khí hay lục hỏa đều được tử võng tiếp được mà không chút hao tổn"}]},"nguon":["@c0704","@c0717"]},{"id":"binh-su-xanh-biec","name":"Bình sứ nhỏ xanh biếc","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Bình sứ nhỏ xanh biếc chứa chất cay độc dị thường, Hàn Lập sắc mặt đại biến vội đậy nắp thu cất. Công dụng cụ thể chưa rõ.","detail":"Thu được từ hộp ngọc chiến lợi phẩm. Khi mở nắp, một luồng hơi thở cay độc dị thường xông vào mũi khiến Hàn Lập sắc mặt đại biến, vội đậy nắp cẩn thận thu vào Túi Trữ Vật. Phản ứng mạnh cho thấy không phải vật tầm thường.","nguon":["@c0704"]},{"id":"hoang-sac-vu-phien","name":"Hoàng sắc vũ phiến","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hoàng bào pháp sĩ"],"trangThai":"dang-co","blurb":"Pháp bảo của pháp sĩ hoàng bào Nguyên Anh Sơ Kỳ, phun ra từ miệng, phẩy một cái tạo cuồng phong vàng đậm cao hơn mười trượng, cuốn gọn năm Kết Đan tu sĩ.","detail":"Pháp sĩ hoàng bào mất kiên nhẫn khi chiến đấu kéo dài, phun pháp bảo này ra từ miệng, chỉ phẩy một cái tạo cuồng phong vàng đậm quy mô lớn cao hơn mười trượng, cuốn toàn bộ năm Kết Đan tu sĩ vào trong.","congNang":["Tạo cuồng phong quy mô lớn, cuốn gọn nhiều tu sĩ Kết Đan"],"chuSoHuu":[{"ten":"Hoàng bào pháp sĩ","tuChuong":"@c0704","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"capNhatToi":"@c0704","tabs":{"tienTrinh":[{"chuong":"@c0704","loai":"dung","importance":"normal","giaiDoan":"Cuốn năm Kết Đan tu sĩ vào cuồng phong","text":"Pháp sĩ hoàng bào phun ra hoàng sắc vũ phiến, phẩy một cái tạo cuồng phong hơn mười trượng cuốn gọn năm Kết Đan tu sĩ.","anchor":"một cổ cuồng phong màu vàng đậm từ vũ phiến phát ra, trong nháy mắt cuồng trướng thật lớn"}]},"nguon":["@c0704"]},{"id":"vu-phien-phap-si-ho-dam","name":"Vũ phiến (của pháp sĩ họ Đàm)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Pháp sĩ họ Đàm"],"trangThai":"mat","blurb":"Pháp bảo của pháp sĩ họ Đàm, phát ra cuồng phong cấm chế khống chế năm tu sĩ, bị Hàn Lập bắn Thanh Nguyên kiếm khí đánh bay.","detail":"Vũ phiến phát ra cuồng phong mãnh liệt khống chế pháp bảo và thân thể năm tu sĩ. Bị Hàn Lập từ xa bắn một đạo Thanh Nguyên kiếm khí đánh bay.","congNang":["Phát cuồng phong cấm chế, khống chế pháp bảo và thân thể đối phương"],"chuSoHuu":[{"ten":"Pháp sĩ họ Đàm","tuChuong":"@c0705","denChuong":"@c0705","cachCoDuoc":"","trangThai":"mat"}],"tabs":{"tienTrinh":[{"chuong":"@c0705","loai":"dùng","importance":"normal","giaiDoan":"Xuất hiện và mất","text":"Pháp sĩ họ Đàm dùng vũ phiến phát cuồng phong khống chế năm tu sĩ, bị Hàn Lập bắn Thanh Nguyên kiếm khí đánh bay.","anchor":"lập tức đem vũ phiến nọ đánh bay"}]},"nguon":["@c0705"]},{"id":"dan-hoan-vang-cau-linh","name":"Hai khỏa đạn hoàn vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Hai khỏa đạn hoàn màu vàng của pháp sĩ họ Đàm, dùng làm linh hạch điều khiển Câu Linh Thổ Long, bị Hàn Lập thu sau khi phá hủy thổ long.","detail":"Pháp sĩ họ Đàm bắn xuống đất để triệu hoán thổ long, nằm trên trán thổ long làm linh hạch cung cấp linh khí. Sau khi thổ long bị Hàn Lập phá hủy, hai khỏa đạn hoàn bị Hàn Lập thu vào Túi Trữ Vật.","congNang":["Linh hạch điều khiển Câu Linh Thổ Long, cung cấp linh khí cho thổ long"],"chuSoHuu":[{"ten":"Pháp sĩ họ Đàm","tuChuong":"@c0705","denChuong":"@c0705","cachCoDuoc":"","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0705","denChuong":"","cachCoDuoc":"Thu được sau khi phá hủy thổ long","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0705","loai":"đổi chủ","importance":"normal","giaiDoan":"Đổi từ pháp sĩ họ Đàm sang Hàn Lập","text":"Pháp sĩ họ Đàm dùng đạn hoàn triệu hoán thổ long, bị Hàn Lập phá hủy rồi thu hai khỏa đạn hoàn vào Túi Trữ Vật.","anchor":"Hai khỏa đạn hoàn màu vàng bị hắn thong dong hút đến trong tay"}]},"nguon":["@c0705"]},{"id":"hoa-hong-phi-kiem-niep-doanh","name":"Hỏa hồng phi kiếm","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Niếp Doanh"],"trangThai":"dang-co","blurb":"Pháp bảo phi kiếm của Niếp Doanh, bị cuồng phong pháp sĩ họ Đàm làm mất khống chế.","detail":"Phi kiếm hỏa hồng do Niếp Doanh khu sử, bị cuồng phong từ vũ phiến của pháp sĩ họ Đàm làm mất quyền khống chế.","nguon":["@c0705"]},{"id":"lenh-bai-quan-su-vien-khon","name":"Lệnh bài quản sự Viên Khôn","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Lệnh bài chứng nhận thân phận quản sự trong Yểm Nguyệt Tông, Hàn Lập lấy từ Viên Khôn để trà trộn vào tông môn.","detail":"Lệnh bài quản sự trên người Viên Khôn, dùng để chứng nhận thân phận khi ra vào tông môn và xử lý công việc thương điếm. Hàn Lập lấy được sau khi bắt giữ Viên Khôn, nhờ đó dễ dàng trà trộn vào Yểm Nguyệt Tông.","congNang":["Chứng nhận thân phận quản sự trong Yểm Nguyệt Tông"],"chuSoHuu":[{"ten":"Viên Khôn","tuChuong":"@c0709","denChuong":"@c0709","cachCoDuoc":"Sở hữu ban đầu","trangThai":"bị lấy"},{"ten":"Hàn Lập","tuChuong":"@c0709","denChuong":"","cachCoDuoc":"Lấy từ Viên Khôn sau khi bắt giữ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0709","loai":"dùng","importance":"normal","giaiDoan":"Hàn Lập dùng trà trộn vào tông","text":"Hàn Lập lấy lệnh bài quản sự từ Viên Khôn, dùng để trà trộn vào Yểm Nguyệt Tông dễ dàng.","anchor":"Thông qua lệnh bài quản sự trên người Viên Khôn, lấy được tin xong hắn dễ dàng trà trộn vào bên trong Yểm Nguyệt Tông"}]},"nguon":["@c0709"]},{"id":"thanh-kiem-ngan-quang","name":"Thanh kiếm ngân quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Hàn Lập","Nam Cung Uyển"],"trangThai":"Đang được Nam Cung Uyển xem","blurb":"Cây kiếm to lóe ngân quang, được Hàn Lập đặt trong hộp gỗ dài dán phù cấm chế bạc làm lễ vật gửi lên cho Nam Cung Uyển. Có ý nghĩa đặc biệt giữa hai người, là tín vật khiến Nam Cung Uyển đồng ý triệu kiến.","detail":"Hàn Lập dùng thanh kiếm này làm tín vật, đặt trong hộp gỗ dài dán phù cấm chế bạc, giả làm lễ vật của bạn cũ gửi Nam Cung Uyển. Khi Nam Cung Uyển nhìn thấy thanh kiếm liền xác nhận người gửi là bạn cũ và triệu kiến Hàn Lập. Cuối chương Nam Cung Uyển đang cúi đầu nhìn thanh kiếm, hộp gỗ đã mở và trống không.","congNang":["Tín vật giữa Hàn Lập và Nam Cung Uyển, công năng chiến đấu chưa rõ"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0710","denChuong":"","cachCoDuoc":"Mang theo làm tín vật","trangThai":"giao cho Nam Cung Uyển xem"}],"tabs":{"tienTrinh":[{"chuong":"@c0710","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập dùng làm tín vật gửi Nam Cung Uyển","text":"Hàn Lập đặt thanh kiếm trong hộp gỗ dán phù cấm chế bạc, giả làm lễ vật gửi lên cho Nam Cung Uyển. Nam Cung Uyển mở hộp thấy kiếm, xác nhận bạn cũ và triệu kiến.","anchor":"Đó chính là một cây kiếm to lóe lên ngân quang"}]},"nguon":["@c0710"]},{"id":"chu-tuoc-hoan","name":"Chu Tước Hoàn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nam Cung Uyển"],"trangThai":"Không rõ","blurb":"Pháp bảo của Nam Cung Uyển, từng có ý dùng để nghiền xương cốt Hàn Lập trả thù sau vụ Huyết Sắc Thí Luyện nhưng cuối cùng buông tha.","detail":"Được nhắc đến trong hồi ức của Nam Cung Uyển khi kể lại tâm lộ trình sau khi thất thân với Hàn Lập trong cấm địa Huyết Sắc Thí Luyện.","nguon":["@c0711"]},{"id":"lenh-bai-khon-tam-thuat","name":"Lệnh bài Khốn Tâm Thuật","cn":"","category":"phap-bao","categoryLabel":"Pháp khí / Cấm chế vật","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-co","blurb":"Khối lệnh bài chứa mấu chốt của Khốn Tâm Thuật, hiện trong tay đại trưởng lão Yểm Nguyệt Tông. Phá hủy lệnh bài thì giải được cấm chế trên Nam Cung Uyển.","detail":"Lệnh bài là mấu chốt duy trì Khốn Tâm Thuật. Hiện nằm trong tay đại trưởng lão Yểm Nguyệt Tông. Hàn Lập đã nhận lời đi lấy lệnh bài để giải phóng Nam Cung Uyển khỏi cấm chế.","congNang":["Duy trì Khốn Tâm Thuật, khống chế đối tượng bị hạ chú trong phạm vi trăm dặm @c0712"],"chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0712","denChuong":"","cachCoDuoc":"Tự tạo bằng máu huyết khi hạ Khốn Tâm Thuật","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0712","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện","text":"Nam Cung Uyển tiết lộ mấu chốt cấm chế nằm ở lệnh bài trong tay sư tỷ. Hàn Lập hào khí nhận lời đi lấy.","anchor":"mấu chốt của cấm chế này là ở trên một khối lệnh bài"}]},"nguon":["@c0712"]},{"id":"linh-an-phu","name":"Linh Ẩn Phù","cn":"","category":"khac","categoryLabel":"Phù lục","phamCap":"Cao cấp","soHuu":["Cô gái áo vàng"],"trangThai":"da-dung","blurb":"Phù cấp cao hiếm thấy có tác dụng ẩn nặc thân hình. Cô gái áo vàng Trúc Cơ kỳ dán trên người để do thám, khiến Hàn Lập nghi ngờ tại sao tiểu tu sĩ lại sở hữu vật này.","detail":"Phù cao cấp hiếm thấy, dán lên người có thể ẩn nặc thân hình. Cô gái áo vàng (đệ tử Trúc Cơ kỳ Yểm Nguyệt Tông) dùng để rình bên ngoài đại sảnh, bị Hàn Lập phát hiện và chất vấn vì một tiểu tu sĩ Trúc Cơ không nên có vật này.","nguon":["@c0713"]},{"id":"cam-che-lenh-bai-do","name":"Cấm chế lệnh bài màu đỏ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-co","blurb":"Lệnh bài màu đỏ do đại trưởng lão Yểm Nguyệt Tông sở hữu, có thể dẫn phát Khốn Tâm thuật cấm chế trên người Nam Cung Uyển khi niệm chú.","detail":"Đại trưởng lão vỗ hông lấy ra lệnh bài màu đỏ, linh quang chớp động khi niệm chú, hồng quang yêu dị dần xuất hiện. Hàn Lập lập tức nhận ra đó là cấm chế lệnh bài và phản ứng tung Kinh Long chung ngăn cản.","congNang":["Kích hoạt Khốn Tâm thuật từ xa để khống chế đối tượng bị cấm chế"],"tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"dùng","importance":"normal","giaiDoan":"Đại trưởng lão cố phát động","text":"Đại trưởng lão rút lệnh bài màu đỏ niệm chú cố kích hoạt Khốn Tâm thuật, nhưng bị Hàn Lập dùng Kinh Long chung tấn công thần thức ngăn cản.","anchor":"ngọc thủ nhẹ nhàng nắm lệnh bài màu đỏ rung lên, cúi đầu niệm chú, nhất thời linh quang trên lệnh bài chớp động"}]},"nguon":["@c0714"]},{"id":"am-duong-bang-hoa-kiem","name":"Âm Dương Băng Hỏa kiếm","cn":"阴阳冰火剑","aliases":["hắc bạch phi kiếm","đôi phi kiếm một trắng một đen"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-co","blurb":"Đôi phi kiếm một trắng một đen của đại trưởng lão Yểm Nguyệt Tông, bạch kiếm tản hàn khí lạnh thấu xương, hắc kiếm cực nóng ngọn lửa đen chập chờn.","detail":"Đôi pháp bảo hiếm thấy. Bạch sắc phi kiếm trắng tinh như tuyết, tản ra hàn khí lạnh thấu xương. Hắc sắc phi kiếm cực nóng, ngọn lửa đen chập chờn. Khi thi triển, hình thể tăng vọt thành cự kiếm dài một trượng, song công băng hỏa.","congNang":["Song công băng hỏa, hình thể có thể tăng vọt thành cự kiếm"],"hinhDang":"Đôi phi kiếm, một trắng tinh một đen, hình thể có thể tăng vọt","tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"dùng","importance":"normal","giaiDoan":"Đại trưởng lão phản kích","text":"Đại trưởng lão phất tay áo thả đôi phi kiếm trắng đen, hình thể tăng vọt thành cự kiếm dài một trượng, phản kích trong cuộc phục kích.","anchor":"Bạch sắc phi kiếm trắng tinh như tuyết, tản ra hàn khí lạnh thấu xương, hắc sắc phi kiếm thì cực nóng"}]},"nguon":["@c0714"]},{"id":"ngan-kiem-tho-lau","name":"Ngân kiếm thô lậu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thấp","soHuu":["Hàn Lập","Nam Cung Uyển"],"trangThai":"dang-co","blurb":"Cây ngân kiếm luyện chế thô lậu do Hàn Lập gửi tặng Nam Cung Uyển qua quản sự giả dạng, khiến nàng kích động ngắm nghía trân trọng — có ý nghĩa tình cảm đặc biệt.","detail":"Lễ vật Hàn Lập gửi cho Nam Cung Uyển, luyện chế thô lậu nhưng khiến nàng kích động đến mức thay đổi chủ ý, chủ động phát Truyền Âm phù muốn gặp sư tỷ. Nam Cung Uyển ngồi ngắm nghía, thưởng thức trân trọng — rất có thể là tín vật gắn liền tình cảm giữa nàng và Hàn Lập.","chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0714","denChuong":"","cachCoDuoc":"Tự luyện chế","trangThai":"da-tang"},{"ten":"Nam Cung Uyển","tuChuong":"@c0714","denChuong":"","cachCoDuoc":"Nhận từ Hàn Lập","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0714","loai":"xuất hiện","importance":"normal","giaiDoan":"Hàn Lập gửi tặng Nam Cung Uyển","text":"Hàn Lập giả dạng quản sự cấp thấp gửi ngân kiếm thô lậu cho Nam Cung Uyển. Nàng nhận kiếm kích động, ngắm nghía trân trọng, rồi chủ động phát Truyền Âm phù gặp sư tỷ.","anchor":"trong tay cầm một ngân kiếm luyện chế thô lậu, đặt ngang trước người, đôi mắt xinh đẹp đang ngắm nghía, thưởng thức"}]},"nguon":["@c0714"]},{"id":"ngung-quang-bao-kinh","name":"Ngưng Quang Bảo Kính","cn":"凝光宝镜","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"đang sử dụng","blurb":"Cổ bảo thành danh của sư tỷ Nam Cung Uyển, toàn thân đen bóng, phun ngũ sắc quang trụ uy lực cực lớn, có thể phá cấm chế và vây khốn pháp bảo đối phương.","detail":"Bảo vật thành danh của Đại trưởng lão Yểm Nguyệt Tông, danh tiếng lớn trong tu sĩ Nguyên Anh kỳ. Toàn thân đen bóng, mặt gương đen tối âm u, phóng ra ngũ sắc quang trụ có thể phá sạch cấm chế quang hà, hỏa diễm, đồng thời vây khốn pháp bảo đối thủ trong cột sáng. Có thể phân cột sáng nhỏ hơn chế trụ bảo vật khác. Thanh Ngưng Kính mà Hàn Lập từng tìm được trong Huyết Sắc Thí Luyện chỉ là phỏng chế đơn giản, uy lực không bằng một phần trăm.","hinhDang":"Toàn thân đen bóng, mặt gương đen tối âm u","congNang":["Phóng ngũ sắc quang trụ phá cấm chế và hỏa diễm","Vây khốn pháp bảo đối phương trong cột sáng","Phân cột sáng nhỏ chế trụ bảo vật khác"],"chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0715","denChuong":"","cachCoDuoc":"","trangThai":"đang dùng"}],"dinhDanh":"goc","tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất thế trong trận chiến","text":"Băng lãnh nữ tử thi triển Ngưng Quang Bảo Kính, phun ngũ sắc quang trụ phá sạch cấm chế quang hà và hỏa diễm, vây khốn Chu Tước Hoàn. Hàn Lập nhận ra đây là nguyên bản của Thanh Ngưng Kính.","anchor":"Ngưng Quang Bảo Kính kia chính là một kiện cổ bảo mà Nam Cung Uyển nhắc tới nhiều nhất, cũng là một trong những bảo vật thành danh của sư tỷ nàng"}]},"nguon":["@c0715"]},{"id":"huyet-ma-kiem","name":"Huyết Ma Kiếm","cn":"血魔剑","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Ma kiếm","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"đang sử dụng","blurb":"Ma kiếm chỉ cỡ một tấc, toàn thân đỏ trong suốt, bên trong có hắc khí lượn lờ, tự động rung lên không cần thúc giục, máu tanh tràn ngập. Có nguy cơ ma khí cắn trả chủ nhân nếu dùng lâu.","detail":"Băng lãnh nữ tử phun ra từ miệng, chỉ cỡ một tấc, toàn thân đỏ trong suốt, bên trong mơ hồ có hắc khí lượn lờ, tự động rung lên không cần thúc giục, máu tanh nhất thời tràn ngập đại sảnh. Có nguy cơ ma khí cắn trả chủ nhân nếu dùng lâu, nhưng nữ tử tự tin đánh bại đối thủ nhanh trước khi bị cắn trả.","hinhDang":"Một tấc, toàn thân đỏ trong suốt, hắc khí bên trong, tự rung","congNang":["Ma kiếm tự phát, uy lực cực lớn, khiến Nguyên Anh tu sĩ lo ngại"],"dacDiem":"Ma khí cắn trả chủ nhân nếu dùng lâu","chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0715","denChuong":"","cachCoDuoc":"","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất thế","text":"Băng lãnh nữ tử phun ra Huyết Ma Kiếm leo thang chiến đấu, ma kiếm tự rung, máu tanh tràn ngập đại sảnh. Nam Cung Uyển nhận ra và lo ngại ma khí cắn trả.","anchor":"một cổ máu tanh nhất thời tràn ngập đại sảnh"}]},"nguon":["@c0715"]},{"id":"tru-ta-thu","name":"Tru Tà Thứ","cn":"诛邪刺","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nam Cung Uyển"],"trangThai":"đã dùng hết","blurb":"Vật phẩm tiêu hao dạng ám khí của Nam Cung Uyển, phóng xích hồng ám mang đả thương đối phương, phá vỡ việc cầm lệnh bài. Số lượng hữu hạn.","detail":"Nam Cung Uyển lén phóng xích hồng ám mang đả thương tay sư tỷ, phá vỡ việc cầm lệnh bài cấm chế. Sư tỷ tưởng Nam Cung Uyển đã dùng hết từ trước, không ngờ còn lưu lại một quả. Vật phẩm tiêu hao, số lượng hữu hạn.","congNang":["Ám kích, thương tích đủ cắt đứt thao khống pháp bảo"],"chuSoHuu":[{"ten":"Nam Cung Uyển","tuChuong":"@c0715","denChuong":"","cachCoDuoc":"","trangThai":"đã dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0715","loai":"dùng","importance":"normal","giaiDoan":"Ám kích sư tỷ","text":"Nam Cung Uyển lén phóng Tru Tà Thứ đả thương tay sư tỷ, phá vỡ việc cầm lệnh bài cấm chế.","anchor":"Tru Tà Thứ! Ngươi dĩ nhiên dùng vật ấy đả thương ta"}]},"nguon":["@c0715"]},{"id":"tieu-kiem-bac","name":"Tiểu kiếm bạc","cn":"","aliases":["ngân kiếm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại trưởng lão Yểm Nguyệt Tông"],"trangThai":"dang-dung","blurb":"Phi kiếm bạc của băng lãnh nữ tử, có thể thi triển Hóa kiếm vi ti biến thành ngàn sợi tơ bạc bén nhọn tấn công diện rộng.","detail":"Băng lãnh nữ tử phun ra từ miệng, bắt quyết thi triển Hóa kiếm vi ti. Kiếm hóa thành ngàn đạo hào quang nhỏ như tơ bạc bén nhọn, liên tục chém rơi Phệ Kim Trùng nhiều lần, tuy trùng sau đó phục sinh.","congNang":["Thi triển Hóa kiếm vi ti — biến thành ngàn sợi tơ bạc bén nhọn tấn công diện rộng"],"chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0716","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0716","loai":"dùng","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Băng lãnh nữ tử phun ra tiểu kiếm bạc, thi triển Hóa kiếm vi ti chém rơi Phệ Kim Trùng nhiều lần nhưng trùng phục sinh.","anchor":"phun ra một tiểu kiếm màu bạc, hai tay nhanh chóng bắt quyết"}]},"nguon":["@c0716"]},{"id":"chi-hoan","name":"Chỉ Hoàn","cn":"指环","aliases":["chiếc nhẫn đen","chỉ hoàn"],"category":"khac","categoryLabel":"Vật bí ẩn","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng (âm hoàn)","blurb":"Đôi nhẫn đen bóng tinh xảo giống hệt nhau, không có linh khí. Hàn Lập đã có sẵn một chiếc, tìm thêm chiếc thứ hai trong đồ đại trưởng lão Yểm Nguyệt Tông. Lai lịch và công dụng chưa rõ.","detail":"Toàn thân đen bóng, chế tác tinh xảo khéo léo nhưng không chứa linh khí, trông như pháp khí phổ thông. Hàn Lập phát hiện chiếc thứ hai trong đống đồ từ túi trữ vật của đại trưởng lão Yểm Nguyệt Tông, giống hệt chiếc nhẫn đen mình đã sở hữu từ trước. So sánh hai chiếc không thấy khác biệt, cất chung vào hộp ngọc. Tiêu đề chương đặt tên Chỉ Hoàn nhấn mạnh tầm quan trọng — có thể là bộ pháp bảo nhiều phần hoặc chìa khóa nào đó.","hinhDang":"Nhẫn toàn thân đen bóng, tinh xảo khéo léo","dacDiem":"Không chứa linh khí, có 2 chiếc giống hệt nhau","chuSoHuu":[{"ten":"Đại trưởng lão Yểm Nguyệt Tông","tuChuong":"@c0717","denChuong":"@c0717","cachCoDuoc":"Không rõ (nằm trong túi trữ vật)","trangThai":"mat"},{"ten":"Hàn Lập","tuChuong":"@c0717","denChuong":"","cachCoDuoc":"Lấy từ hộp ngọc (trước đó)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0717","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện đôi nhẫn","text":"Hàn Lập phát hiện chiếc nhẫn đen tinh xảo trong đống đồ sư tỷ Nam Cung Uyển, lấy chiếc nhẫn đen giống hệt mình đã có ra so sánh, cả hai không có linh khí, cất chung vào hộp ngọc.","anchor":"Đấy là một chiếc nhẫn tinh xảo khéo léo, toàn thân đen bóng"},{"chuong":"@c0723","loai":"khai phong","importance":"major","giaiDoan":"Xác nhận danh tính và công năng","text":"Chiếc nhẫn đen được Tuyền Kì Tử và Nam Lũng Hầu xác nhận là Lưỡng Nghi Hoàn (phần âm hoàn), do Huyền Hoàng Lão Nhân luyện chế từ thiên ngoại vẫn thiết. Hé lộ toàn bộ công năng: âm hoàn hộ thể khỏi Bắc Cực nguyên quang, dương hoàn thao túng nguyên quang tấn công. Là vật phẩm then chốt để vào Trụy Ma Cốc.","anchor":"Lưỡng Nghi hoàn này chia làm âm dương nhị hoàn, có âm hoàn trong người cũng không sợ nguyên quang làm tổn thương thân thể"}]},"nguon":["@c0717","@c0723"],"congNang":["Âm hoàn: bảo vệ thân thể khỏi Bắc Cực nguyên quang xâm phạm (@c0723)","Dương hoàn: thao túng Bắc Cực nguyên quang tấn công giết người vô hình (@c0723)"],"thanhVien":[]},{"id":"khan-lua-co-bao-vo-danh","name":"Khăn lụa cổ bảo vô danh","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Cổ bảo vô danh Nam Cung Uyển vô tình có được khi du ngoạn, chỉ cần ý niệm tự động bay lên phòng thân, linh khí dị thường.","detail":"Chiếc khăn lụa mỏng phát ra linh khí dị thường. Chỉ cần một ý niệm là tự động bay lên phòng thân, sử dụng cực kỳ thuận tiện. Nam Cung Uyển tặng cho Hàn Lập trước khi chia tay.","congNang":["Tự động bay lên phòng thân chỉ bằng ý niệm"],"nguon":["@c0718"],"chuSoHuu":[{"ten":"Nam Cung Uyển","tuChuong":"","denChuong":"@c0718","cachCoDuoc":"Vô tình có được khi du ngoạn","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0718","denChuong":"","cachCoDuoc":"Nam Cung Uyển tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0718","loai":"đổi chủ","importance":"normal","giaiDoan":"Nam Cung Uyển trao tặng Hàn Lập","text":"Nam Cung Uyển tặng Hàn Lập khăn lụa cổ bảo vô danh để phòng thân trước khi chia tay tại biên giới Bắc Lương Quốc.","anchor":"cơ hồ chỉ cần một ý niệm là có thể tự động bay lên phòng thân"}]}},{"id":"ich-hoa-boi","name":"Ích Hỏa bội","cn":"益火佩","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tín vật","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Tín vật Nam Cung Uyển thường mang trên người, hồng quang lập lòe. Dùng để sai khiến đệ tử ký danh của nàng tại Điền Thiên Thành.","detail":"Ngọc bội phát hồng quang lập lòe, là tín vật cá nhân Nam Cung Uyển thường xuyên mang theo. Có công năng làm tín vật chỉ huy đệ tử ký danh (không phải đệ tử Yểm Nguyệt Tông) của nàng. Được trao cho Hàn Lập trước khi chia tay.","congNang":["Tín vật chỉ huy/sai khiến đệ tử ký danh của Nam Cung Uyển"],"nguon":["@c0718"],"chuSoHuu":[{"ten":"Nam Cung Uyển","tuChuong":"","denChuong":"@c0718","cachCoDuoc":"Vật sở hữu cá nhân","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0718","denChuong":"","cachCoDuoc":"Nam Cung Uyển tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0718","loai":"đổi chủ","importance":"normal","giaiDoan":"Nam Cung Uyển trao cho Hàn Lập","text":"Nam Cung Uyển trao Ích Hỏa bội cho Hàn Lập để hắn có thể sai khiến đệ tử ký danh của nàng đang mở hàng tại Điền Thiên Thành.","anchor":"Đây là Ích Hỏa bội, là một kiện tín vật mà thiếp thường xuyên mang theo trên người"}]}},{"id":"ngoc-gian-luc-sac","name":"Ngọc giản lục sắc","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"dang-co","blurb":"Khối ngọc giản lục sắc do Lỗ Vệ Anh trưởng lão Thiên Cực Môn trao cho Hàn Lập, bên trong ghi địa chỉ hẹn gặp riêng đêm nay.","detail":"Lỗ Vệ Anh chuẩn bị sẵn ngọc giản này, ném cho Hàn Lập khi lộ diện giải vây cho đệ tử Bạch Thư Quân. Bên trong ghi một địa chỉ tại Điền Thiên Thành để mời Hàn Lập đêm nay đến gặp mặt bàn chuyện riêng.","congNang":["Chứa địa chỉ hẹn gặp riêng"],"chuSoHuu":[{"ten":"Lỗ Vệ Anh","tuChuong":"@c0719","denChuong":"@c0719","cachCoDuoc":"Tự chuẩn bị","trangThai":"da-trao"},{"ten":"Hàn Lập","tuChuong":"@c0719","denChuong":"","cachCoDuoc":"Lỗ Vệ Anh trao cho","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0719","loai":"xuất hiện","importance":"normal","giaiDoan":"Lỗ Vệ Anh trao cho Hàn Lập","text":"Lỗ Vệ Anh ném ngọc giản lục sắc cho Hàn Lập, bên trong ghi địa chỉ hẹn gặp đêm nay tại Điền Thiên Thành.","anchor":"theo đó một khối lục sắc ngọc giản sớm chuẩn bị bay vụt đến"}]},"nguon":["@c0719"]},{"id":"bao-vat-hac-hong-quang","name":"Bảo vật hắc hồng quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cổ quái)","soHuu":[],"trangThai":"dang-co","blurb":"Bảo vật cổ quái do hai pháp sĩ Nguyên Anh Sơ Kỳ dị loại sử dụng, phóng hắc hồng quang vô ảnh vô tung phong tỏa Nguyên Anh sau khi xuất khiếu, chặn thuấn di thần thông, trực tiếp dẫn tới tử vong Nguyên Anh tu sĩ.","detail":"Giương tay phóng ra hắc hồng quang vô ảnh vô tung, vây khốn Nguyên Anh sau khi xuất khiếu khiến không thể thuấn di trốn thoát. Là nguyên nhân trực tiếp khiến hai Nguyên Anh tu sĩ Thiên Nam tử trận trong chiến tranh Mộ Lan.","congNang":["Phong tỏa Nguyên Anh sau khi xuất khiếu, chặn thuấn di thần thông"],"dacDiem":"Hắc hồng quang vô ảnh vô tung, rất khó phòng bị","tabs":{"tienTrinh":[{"chuong":"@c0720","loai":"xuat-hien","importance":"major","giaiDoan":"Lộ diện trong chiến tranh Mộ Lan","text":"Hai pháp sĩ Nguyên Anh Sơ Kỳ cổ quái dùng bảo vật này phóng hắc hồng quang phong tỏa Nguyên Anh, trực tiếp dẫn tới tử vong hai Nguyên Anh tu sĩ Thiên Nam.","anchor":"giương tay thì có một đạo hắc hồng quang đến vô ảnh, đi vô tung, rất khó lòng phòng bị"}]},"nguon":["@c0720"]},{"id":"lam-quang-thuan","name":"Lam Quang Thuẫn","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Cổ bảo","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Tiểu thuẫn phát ánh sáng lam, cổ bảo phòng ngự đặc biệt thần diệu khi đối mặt công kích thuộc tính hỏa. Do Lệnh Hồ Lão Tổ tặng Hàn Lập.","detail":"Cổ bảo hình tiểu thuẫn, phát ánh sáng lam, cảm giác mềm mại nhẹ nhàng như không tồn tại, chất liệu bất minh. Thần thông không nhỏ, đặc biệt thần diệu khi đối mặt với công kích thuộc tính hỏa. Lệnh Hồ Lão Tổ tặng Hàn Lập trong giao dịch ba trọng bảo đổi ba lần tương trợ Hoàng Phong Cốc.","congNang":["Phòng ngự, đặc biệt khắc chế hỏa tính công kích"],"chuSoHuu":[{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Được Lệnh Hồ Lão Tổ tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"major","giaiDoan":"Lệnh Hồ Lão Tổ tặng Hàn Lập","text":"Lệnh Hồ Lão Tổ tặng Lam Quang Thuẫn cho Hàn Lập như một trong ba trọng bảo đổi ba lần tương trợ Hoàng Phong Cốc.","anchor":"Thần thông của bảo vật này không nhỏ, hơn nữa khi đối mặt với công kích thuộc tính hỏa càng vô cùng thần diệu"}]},"nguon":["@c0722"]},{"id":"that-cap-yeu-dan-thiet-si-dieu","name":"Thất cấp yêu đan Thiết Sí Điêu","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Thất cấp yêu đan","soHuu":["Hàn Lập"],"trangThai":"đang giữ","blurb":"Yêu đan thất cấp từ Thiết Sí Điêu tại Mộ Lan thảo nguyên, dùng luyện đan hoặc mục đích khác. Tại Thiên Nam vô cùng quý hiếm.","detail":"Nằm trong bình ngọc đỏ, do Lệnh Hồ Lão Tổ một mình tiến sâu vào Mộ Lan thảo nguyên diệt Thiết Sí Điêu thất cấp mà lấy được. Tại Thiên Nam xem là vô cùng quý hiếm, nhưng Hàn Lập thầm coi là vô tác dụng với mình.","congNang":["Tài liệu luyện đan hoặc sử dụng khác"],"chuSoHuu":[{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"Diệt Thiết Sí Điêu thất cấp tại Mộ Lan thảo nguyên","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Được Lệnh Hồ Lão Tổ tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"normal","giaiDoan":"Lệnh Hồ Lão Tổ tặng Hàn Lập","text":"Lệnh Hồ Lão Tổ tặng thất cấp yêu đan Thiết Sí Điêu cho Hàn Lập, Hàn Lập thầm coi là vô tác dụng với mình.","anchor":"Mặc dù thất cấp yêu đan tại Thiên Nam xem như vô cùng quý hiếm nhưng đối với hắn thật sự chỉ là thứ vô tác dụng"}]},"nguon":["@c0722"]},{"id":"ngoc-phu-thuong-co","name":"Ngọc phù thượng cổ","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Thượng cổ phù bảo","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Ngọc bội đen do cổ tu sĩ tinh thông đạo phù luyện chế thời thượng cổ, có thần thông quỷ thủ dùng âm hỏa bắt giữ gần như mọi thứ. Loại phù này đã thất truyền tại Thiên Nam.","detail":"Ngọc bội màu đen, do cổ tu sĩ tinh thông đạo phù luyện chế thời thượng cổ, loại phù này đã thất truyền tại Thiên Nam. Lệnh Hồ Lão Tổ cửu tử nhất sinh mới lấy được, nghiên cứu hơn mấy trăm năm chỉ khai thác được một thần thông: huyễn hóa thành hắc hồng đại thủ (quỷ thủ) dùng hắc sắc âm hỏa, bắt giữ gần như mọi thứ trừ bảo vật chí cương chí dương. Bảo vật bị bắt sẽ mất thần thông hoặc giảm linh tính. Uy lực đã tiêu hao hơn phân nửa, cần cẩn thận sử dụng. Ngọc phù còn chỗ thần diệu khác chưa khai thác.","congNang":["Huyễn hóa thành quỷ thủ (hắc hồng đại thủ) dùng hắc sắc âm hỏa bắt giữ/hủy diệt mục tiêu","Bảo vật bị bắt mất thần thông hoặc giảm linh tính"],"dacDiem":"Thượng cổ phù bảo, thất truyền tại Thiên Nam. Yếu điểm: vô hiệu trước bảo vật chí cương chí dương. Uy lực đã dùng hơn phân nửa.","chuSoHuu":[{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"Cửu tử nhất sinh tìm được","trangThai":"da-tang"},{"ten":"Hàn Lập","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Được Lệnh Hồ Lão Tổ tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"major","giaiDoan":"Lệnh Hồ Lão Tổ tặng Hàn Lập, biểu diễn quỷ thủ","text":"Lệnh Hồ Lão Tổ tặng ngọc phù thượng cổ cho Hàn Lập và biểu diễn thần thông quỷ thủ hủy bàn gỗ không dấu vết. Tiết lộ nghiên cứu hơn mấy trăm năm chỉ khai thác được một thần thông, uy lực đã dùng hơn phân nửa. Hàn Lập rất hứng thú, muốn nghiên cứu đạo phù cổ nhân.","anchor":"Dùng nó huyễn hóa thành quỷ thủ, trừ khi gặp bảo vật chí cương chí dương, cơ hồ không vật gì không bắt được"}]},"nguon":["@c0722"]},{"id":"ba-tran-ban-tin-vat","name":"Ba trận bàn trắng trong suốt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí","soHuu":["Lệnh Hồ Lão Tổ"],"trangThai":"đang giữ","blurb":"Ba trận bàn trắng trong suốt do Hàn Lập đích thân luyện chế, trao cho Lệnh Hồ Lão Tổ làm tín vật ba lần tương trợ Hoàng Phong Cốc.","detail":"Pháp khí do Hàn Lập đích thân luyện chế, người khác không thể bắt chước. Dùng làm tín vật cho cam kết ba lần xuất thủ tương trợ Hoàng Phong Cốc. Mỗi lần dùng một trận bàn.","congNang":["Tín vật triệu hồi tương trợ, mỗi trận bàn đại diện một lần"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"","denChuong":"@c0722","cachCoDuoc":"Tự luyện chế","trangThai":"da-tang"},{"ten":"Lệnh Hồ Lão Tổ","tuChuong":"@c0722","denChuong":"","cachCoDuoc":"Hàn Lập trao làm tín vật","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0722","loai":"doi-chu","importance":"normal","giaiDoan":"Hàn Lập trao cho Lệnh Hồ Lão Tổ","text":"Hàn Lập trao ba trận bàn trắng trong suốt do mình luyện chế cho Lệnh Hồ Lão Tổ làm tín vật ba lần tương trợ Hoàng Phong Cốc.","anchor":"Ba trận bàn này đều là pháp khí mà đích thân ta luyện chế ra, người khác không thể bắt chước"}]},"nguon":["@c0722"]},{"id":"lenh-bai-thien-cuc-mon","name":"Lệnh bài Thiên Cực Môn","category":"khac","categoryLabel":"Tín vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đang sử dụng","blurb":"Lệnh bài do Tuyền Ki Tử giao cho Hàn Lập, có thể điều động bất kỳ đệ tử Thiên Cực Môn nào để liên lạc với Tuyền Ki Tử.","detail":"Một khối lệnh bài thuộc Thiên Cực Môn, do Tuyền Ki Tử trao cho Hàn Lập. Người cầm lệnh bài này có thể điều động bất kỳ một đệ tử Thiên Cực Môn nào để liên lạc với Tuyền Ki Tử.","congNang":["Điều động đệ tử Thiên Cực Môn liên lạc với Tuyền Ki Tử"],"chuSoHuu":[{"ten":"Hàn Lập","tuChuong":"@c0724","denChuong":"","cachCoDuoc":"Tuyền Ki Tử trao tặng","trangThai":"đang giữ"}],"tabs":{"tienTrinh":[{"chuong":"@c0724","loai":"đổi chủ","importance":"normal","giaiDoan":"Tuyền Ki Tử giao cho Hàn Lập","text":"Tuyền Ki Tử giao lệnh bài cho Hàn Lập để liên lạc qua đệ tử Thiên Cực Môn.","anchor":"có lệnh bài này, Hàn Lập có thể điều động bất kỳ một gã đệ tử Thiên Cực Môn nào liên lạc với lão"}]},"nguon":["@c0724"]},{"id":"thien-thai-coc-di-bao-ma","name":"Dị bảo của lão giả họ Mã","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão giả họ Mã"],"trangThai":"dang-co","blurb":"Kiện dị bảo mà lão giả họ Mã mới có được, muốn thử uy lực trong trận tiếp ứng, chưa lộ hình dạng cụ thể.","detail":"Lão giả họ Mã nói mới có được nhất kiện dị bảo, xung phong đi tiếp ứng tu sĩ chiến bại từ Thiên Thai Cốc để thử uy lực.","nguon":["@c0727","@c0729"],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"dùng","importance":"normal","giaiDoan":"Trận đấu với Quật Diệu","text":"Lão giả họ Mã dốc toàn lực lấy ra quyển trục ngũ sắc hà quang vẽ bát quái đồ, phát ba động kinh người. Bị hỏa giao phun xích diễm bao phủ cùng chủ nhân trong biển lửa.","anchor":"ngũ sắc hà quang chợt đại phóng, một cổ ba động phi thường kinh người từ trong phát ra"}]},"aliases":["Quyển trục bát quái đồ ngũ sắc","quyển trục"],"congNang":["Phát ba động công kích kinh người"],"chuSoHuu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0729","denChuong":"","cachCoDuoc":"Sẵn có","trangThai":"dang-co"}]},{"id":"ngan-bach-gioi-xich","name":"Ngân bạch giới xích","loai":"phap-bao","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão giả họ Mã"],"trangThai":"dang-co","blurb":"Pháp bảo của lão giả họ Mã, từ miệng phun ra đón gió hóa thành, rung lên phát tiếng phượng minh cửu thiên.","detail":"Từ trong miệng phun ra dưới dạng ngân quang cỡ hạt đào, đón gió hóa thành thanh giới xích ngân bạch. Khẽ rung phát tiếng phượng minh cửu thiên, ngân quang như thiên huyễn.","hinhDang":"Giới xích ngân bạch","congNang":["Phát thanh âm phượng minh cửu thiên"],"chuSoHuu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0729","denChuong":"","cachCoDuoc":"Sẵn có","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"dùng","importance":"normal","giaiDoan":"Trận đấu với Quật Diệu","text":"Lão giả họ Mã phun ngân quang từ miệng hóa thành ngân bạch giới xích, phát tiếng phượng minh đối đầu Quật Diệu.","anchor":"một đạo ngân quang cỡ hạt đào từ trong miệng phun ra, đón gió hóa thành một thanh ngân bạch giới xích"}]},"nguon":["@c0729"]},{"id":"phi-dao-do-trong-suot","name":"Phi đao đỏ trong suốt","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quật Diệu"],"trangThai":"dang-co","blurb":"Pháp bảo phi đao của Quật Diệu, trong suốt đỏ đậm, quang mang chói mắt. Từ lòng bàn tay bắn ra hóa hồng quang nghênh chiến tầm xa.","detail":"Pháp bảo hình phi đao màu đỏ trong suốt của Quật Diệu. Bắn ra từ lòng bàn tay hóa thành hồng quang giao đấu ngang ngửa với ngân hồng phóng ra từ Thái Huyền Bát Quái Đồ của tu sĩ họ Mã.","congNang":["Bắn ra hóa hồng quang giao chiến tầm xa"],"tabs":{"tienTrinh":[{"chuong":"@c0730","loai":"dung","importance":"normal","giaiDoan":"Trận chiến với tu sĩ họ Mã","text":"Quật Diệu bắn phi đao đỏ trong suốt nghênh chiến ngân hồng từ Thái Huyền Bát Quái Đồ, hai bên giao đấu ngang ngửa.","anchor":"Một thanh phi đao màu đỏ từ lòng bàn tay bắn ra, hóa thành một đạo hồng quang nghênh đón ngân hồng"}]},"nguon":["@c0730"]},{"id":"luong-dien-hong-tieu-phien","name":"Lưỡng diện hồng tiểu phiên","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quật Diệu"],"trangThai":"dang-co","blurb":"Pháp bảo phiên kỳ của Quật Diệu, phất lên đón gió phồng to hơn một trượng, phóng ra hai đạo hỏa trụ hỗ trợ hỏa giao tụ hỏa vân.","detail":"Pháp bảo dạng phiên kỳ (cờ nhỏ) hai mặt đỏ của Quật Diệu. Phất lên đón gió phồng to hơn một trượng, bắn ra hai đạo hỏa trụ thô to hội hợp với hỏa giao tạo thành hỏa vân khổng lồ.","congNang":["Phóng hỏa trụ","Hỗ trợ hỏa giao tụ hỏa vân"],"tabs":{"tienTrinh":[{"chuong":"@c0730","loai":"dung","importance":"normal","giaiDoan":"Tăng cường hỏa giao","text":"Quật Diệu phất lưỡng diện hồng tiểu phiên phóng hai hỏa trụ hội hợp hỏa giao tạo hỏa vân khổng lồ.","anchor":"trong tay quang hoa sáng ngời xuất hiện lưỡng diện hồng tiểu phiên"}]},"nguon":["@c0730"]},{"id":"song-vi-phi-thuy-xa","name":"Song Vĩ Phỉ Thúy Xà","cn":"","category":"khac","categoryLabel":"Độc vật / Linh thú","phamCap":"Ngang thập đại tuyệt độc truyền thuyết","soHuu":["Kẻ ám sát đại điện"],"trangThai":"đang sử dụng","blurb":"Rắn hai đuôi màu xanh biếc (bích lục), độc tính cực mạnh ngang thập đại tuyệt độc truyền thuyết. Có thể ngụy trang thành ngọc giản, cắn một phát khiến tu sĩ Nguyên Anh cũng không thể độn thoát, thi thể tan chảy.","detail":"Song Vĩ Phỉ Thúy Xà — rắn hai đuôi bích lục, mắt xanh âm độc, phun nọc tím đen. Kẻ ám sát dùng nó ngụy trang thành lục sắc ngọc giản rồi biến thành tiểu xà cắn chết đại hán trọc mi Nguyên Anh kỳ. Bị cắn thì ngay cả nguyên anh cũng không có lực độn thoát, thi thể bắt đầu tan chảy. Kẻ ám sát tiếc rằng nó không có cánh để bay, nếu có sẽ trở thành sát thủ tu sĩ cực kỳ sắc bén.","congNang":["Ngụy trang thành vật phẩm (ngọc giản)","Cắn độc giết tu sĩ Nguyên Anh, nguyên anh không thể độn thoát","Nọc khiến thi thể nạn nhân tan chảy"],"chuSoHuu":[{"ten":"Kẻ ám sát đại điện","tuChuong":"@c0732","denChuong":"","cachCoDuoc":"Không rõ","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"dùng","importance":"major","giaiDoan":"Ám sát đại hán trọc mi","text":"Kẻ ám sát dùng Song Vĩ Phỉ Thúy Xà ngụy trang thành lục sắc ngọc giản, biến thành tiểu xà cắn chết đại hán trọc mi Nguyên Anh kỳ tại đại điện Hoàng Long Sơn.","anchor":"lục quang ngọc giản chợt lóe, đột nhiên hóa thành một con tiểu xà màu xanh, thế như sét đánh cắn ngay cổ tay của đại hán","phamCap":"Ngang thập đại tuyệt độc"}]},"nguon":["@c0732"]},{"id":"tui-tru-vat-thien-khoc","name":"Túi trữ vật màu đen (của Thiên Khốc)","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Không rõ","soHuu":["Hàn Lập"],"trangThai":"đổi chủ","blurb":"Túi trữ vật màu đen của hắc bào nhân Thiên Khốc, Hàn Lập thu được sau khi diệt sát Thiên Khốc.","detail":"Túi trữ vật màu đen thuộc về hắc bào nhân Thiên Khốc (đến từ Bàng Đại đế quốc). Hàn Lập thu được sau khi dùng Ích Tà Thần Lôi diệt sát Thiên Khốc, kim hồ co rút lại bao bọc túi đem về.","chuSoHuu":[{"ten":"Hắc bào nhân","tuChuong":"@c0732","denChuong":"@c0732","cachCoDuoc":"Vật sở hữu ban đầu","trangThai":"chủ chết"},{"ten":"Hàn Lập","tuChuong":"@c0732","denChuong":"","cachCoDuoc":"Thu chiến lợi phẩm sau khi diệt Thiên Khốc","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"đổi chủ","importance":"normal","giaiDoan":"Hàn Lập thu chiến lợi phẩm","text":"Hàn Lập thu Túi trữ vật màu đen từ hắc bào nhân Thiên Khốc sau khi diệt sát.","anchor":"kim hồ co rút lại, bao bọc lấy một cái Túi trữ vật màu đen đem lại trên tay"}]},"nguon":["@c0732"]},{"id":"tui-tru-vat-dai-han-luc","name":"Túi trữ vật (của đại hán họ Lục)","cn":"","category":"khac","categoryLabel":"Túi trữ vật","phamCap":"Không rõ","soHuu":["Kẻ ám sát đại điện"],"trangThai":"đổi chủ","blurb":"Túi trữ vật của đại hán trọc mi (họ Lục), bị kẻ ám sát lấy từ thi thể đang tan chảy và hạ thần thức tìm kiếm vật gì đó bên trong.","detail":"Túi trữ vật thuộc về đại hán trọc mi (họ Lục), chỉ huy phòng thủ Hoàng Long Sơn. Sau khi đại hán bị Song Vĩ Phỉ Thúy Xà cắn chết, kẻ ám sát lấy túi trữ vật từ thi thể đang tan chảy, kích động hạ thần thức tìm kiếm vật gì đó — ám chỉ bên trong có vật phẩm quan trọng.","chuSoHuu":[{"ten":"Đại hán họ Lục","tuChuong":"@c0732","denChuong":"@c0732","cachCoDuoc":"Vật sở hữu ban đầu","trangThai":"chủ chết"},{"ten":"Kẻ ám sát đại điện","tuChuong":"@c0732","denChuong":"","cachCoDuoc":"Cướp từ thi thể","trangThai":"đang dùng"}],"tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"đổi chủ","importance":"normal","giaiDoan":"Kẻ ám sát cướp lấy","text":"Kẻ ám sát lấy Túi trữ vật trên thi thể đang tan chảy của đại hán trọc mi, kích động hạ thần thức tìm kiếm vật gì đó bên trong.","anchor":"Túi trữ vật trên thi thể trực tiếp bay đến trên tay hắn"}]},"nguon":["@c0732"]},{"id":"lam-sac-phi-xoa","name":"Lam sắc phi xoa","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":null,"soHuu":["Cốc Song Bồ"],"trangThai":"đang sử dụng","blurb":"Pháp bảo màu xanh lam hình phi xoa của Cốc Song Bồ, có thể hợp nhất với độn quang tấn công hoặc xoay tròn thành màn chắn hộ thể.","detail":"Pháp bảo được Cốc Song Bồ phun ra từ miệng khi bị nhốt trong quang tráo đại trận Hoàng Long Sơn. Khi tấn công, phi xoa hợp làm một với độn quang thành lam hồng to lớn đánh mãnh liệt vào lồng ánh sáng bạc, nhưng bị bắn ngược trở lại. Khi phòng ngự, phi xoa xoay tròn biến thành màn chắn xanh lam che hộ thể chống đỡ ngân hoa hủy diệt từ cấm chế. Cả hai lần đều không đủ sức phá vỡ cấm chế trung tâm đại trận.","nguon":["@c0733"]},{"id":"huyet-nhuc-khoi-loi-the-than-luc","name":"Huyết nhục khôi lỗi thế thân (của đại hán họ Lục)","cn":null,"category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":null,"soHuu":["Đại hán họ Lục"],"trangThai":"đã sử dụng (bị hủy)","blurb":"Khôi lỗi bằng huyết nhục giống hệt đại hán họ Lục, do tu sĩ bí ẩn ở Cửu Quốc Minh luyện chế, dùng để giả chết dụ gian tế lộ mặt.","detail":"Huyết nhục khôi lỗi thế thân được một vị tu sĩ thần bí ở Cửu Quốc Minh luyện chế, giống bản thân đại hán họ Lục như đúc. Bên trong trống rỗng, sau khi bị hủy sẽ hóa thành bãi máu đen. Tinh vi đến mức tu sĩ Nguyên Anh nếu không dùng thần thức quét kỹ sẽ không nhận ra. Đại hán họ Lục đã dùng khôi lỗi này thay thế bản thân, để Cốc Song Bồ dùng song vĩ phỉ thúy xà giết chết khôi lỗi mà tưởng đã đắc thủ, từ đó lộ mặt gian tế. Bản thân đại hán họ Lục thừa nhận việc thỉnh người luyện chế khôi lỗi ban đầu chỉ là nhất thời cao hứng.","nguon":["@c0733"]},{"id":"ngoc-gian-trang","name":"Ngọc giản trắng","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Đại hán họ Lục"],"trangThai":"dang-co","blurb":"Ngọc giản màu trắng được đại hán trọc mi dùng bí thuật phục chế đoạn đối thoại với Cốc Song Bồ vào bên trong làm chứng cớ vụ gián điệp Mộ Lan.","detail":"Đại hán trọc mi dùng bí thuật phục chế đoạn đối thoại giữa mình với Cốc Song Bồ vào ngọc giản trắng này, dự định trình làm chứng cớ cho Ngự Linh Tông.","congNang":["Lưu trữ phục chế đối thoại làm chứng cớ"],"tabs":{"tienTrinh":[{"chuong":"@c0734","loai":"xuất hiện","importance":"normal","giaiDoan":"Được tiết lộ làm chứng cớ","text":"Đại hán trọc mi cho biết đã phục chế đối thoại vào ngọc giản trắng làm bằng chứng vụ gián điệp Cốc Song Bồ.","anchor":"trong tay đã xuất hiện một cái ngọc giản màu trắng, mặt lộ vẻ quỷ dị nói"}]},"capNhatToi":"@c0734","nguon":["@c0734"]},{"id":"lenh-bai-cam-che","name":"Lệnh bài cấm chế","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Đại hán họ Lục"],"trangThai":"dang-co","blurb":"Lệnh bài phát ánh bạc dùng để điều khiển và gia cố cấm chế quang tráo giam giữ Cốc Song Bồ.","detail":"Đại hán trọc mi phun tinh khí kích hoạt lệnh bài, ném lên đỉnh đầu rồi phóng hơn mười đạo pháp quyết vào màn hào quang, khiến ngân quang dày thêm ba phần và ngân sắc lôi hoa ngưng tụ trên quang bích.","congNang":["Điều khiển cấm chế quang tráo","Gia cố ngân quang bích và triệu hoán lôi hoa"],"tabs":{"tienTrinh":[{"chuong":"@c0734","loai":"dùng","importance":"normal","giaiDoan":"Gia cố cấm chế giam Cốc Song Bồ","text":"Đại hán trọc mi dùng lệnh bài gia cố cấm chế khi quái xà phụ linh tấn công quang bích, nhưng quái xà vẫn phá được lỗ hổng thoát ra.","anchor":"quang mang chợt lóe, lệnh bài cấm chế phát ra ánh sáng màu bạc liền hiện ra trong tay"}]},"capNhatToi":"@c0734","nguon":["@c0734"]},{"id":"chien-giap-den-cu-thu","name":"Chiến giáp đen của cự thú","cn":"","category":"linh-khi","categoryLabel":"Linh khí","phamCap":"Không rõ","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","blurb":"Tầng chiến giáp đen thui phát sáng khoác trên cự thú khổng lồ của Nhạc thượng sư, mơ hồ có chú văn chớp động, giá trị xa xỉ.","detail":"Chiến giáp đen thui phát sáng, khoác trên thân cự thú khổng lồ (dài hai mươi trượng, cao ba mươi trượng) của Nhạc thượng sư. Bên trên mơ hồ có các loại chú văn chớp động, giá trị xa xỉ.","nguon":["@c0735"],"tabs":{"tienTrinh":[{"chuong":"@c0735","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Khoác trên cự thú khổng lồ của Nhạc thượng sư khi đại quân pháp sĩ tiến đến Hoàng Long Sơn.","anchor":"Trên thân hình to lớn kia có khoác một tầng chiến giáp đen thui phát sáng, bên trên mơ hồ có các loại chú văn chớp động"}]}},{"id":"cu-te-thu","name":"Cự Tê Thú","cn":"","category":"khac","categoryLabel":"Linh thú","phamCap":"","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","blurb":"Linh thú chiến đấu của Nhạc Thượng Sư, sẽ phối hợp cùng Quật Diệu phá trận Hoàng Long Sơn.","detail":"Nhạc Thượng Sư cho Cự Tê Thú phối hợp Quật Diệu phá trận, dùng trong chiến dịch tổng công kích đại trận Hoàng Long Sơn.","nguon":["@c0736"]},{"id":"nac-thien-ky","name":"Nặc Thiên Kỳ","cn":"匿天旗","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lão giả họ Mã"],"trangThai":"dang-dung","blurb":"Pháp bảo của lão giả họ Mã, có thể che khuất cả nửa đỉnh núi nhưng tiêu hao đáng kể pháp lực.","detail":"Pháp bảo ẩn tàng, lão giả họ Mã dùng để che khuất nửa đỉnh núi Hỏa Long Sơn, tiêu hao đáng kể pháp lực, chỉ còn đủ sức cầm chân một Mộ Lan Đại Thượng Sư.","congNang":["Che giấu, ẩn tàng khu vực rộng lớn (nửa đỉnh núi)"],"chuSoHuu":[{"ten":"Lão giả họ Mã","tuChuong":"@c0737","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"dùng","importance":"normal","giaiDoan":"Che khuất Hỏa Long Sơn","text":"Lão giả họ Mã vận dụng Nặc Thiên Kỳ che khuất nửa đỉnh núi, tiêu hao đáng kể pháp lực.","anchor":"Mã huynh mới vừa rồi vận dụng Nặc Thiên Kỳ che khuất nửa đỉnh núi"}]},"nguon":["@c0737"]},{"id":"luc-dien-hong-cu-phien","name":"Lục diện hồng cự phiên","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Quật Diệu"],"trangThai":"dang-dung","blurb":"Sáu cái kỳ phiên lục diện màu đỏ của Quật Diệu, phối hợp linh thuật đại trận, phát quang trụ dẫn dắt hỏa cầu phá cấm chế.","detail":"Bộ sáu kỳ phiên lục diện màu đỏ, pháp bảo của Quật Diệu, vây quanh khi chủ trì linh thuật đại trận. Bắn ra sáu đạo quang trụ đỏ dẫn dắt hỏa cầu lao vào phá tan cấm chế vụ hải.","congNang":["Phối hợp linh thuật đại trận, phát sáu đạo quang trụ đỏ dẫn dắt hỏa cầu phá cấm chế"],"chuSoHuu":[{"ten":"Quật Diệu","tuChuong":"@c0737","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"dùng","importance":"normal","giaiDoan":"Phá cấm chế vụ hải","text":"Quật Diệu dùng sáu lục diện hồng cự phiên bắn ra sáu đạo quang trụ đỏ dẫn hỏa cầu phá cấm chế vụ hải Hỏa Long Sơn.","anchor":"sáu đạo quang trụ màu đỏ từ trong kỳ phiên nghiêng bắn ra"}]},"nguon":["@c0737"]},{"id":"vien-quyen-vang","name":"Viên quyển màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-dung","blurb":"Pháp bảo của nữ tử áo xanh (Nhạc Thượng Sư), ném choàng lên sừng cự tê thú phát kim quang kích thích con thú điên cuồng xông vào chiến trường.","detail":"Viên quyển kim sắc, nữ tử áo xanh ném choàng lên sừng xanh của cự tê thú, phát kim quang chói mắt khiến mắt con thú đỏ bừng, điên cuồng lao vào vụ hải.","congNang":["Kích thích, điều khiển cự thú (choàng lên sừng phát kim quang)"],"chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0737","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c0737","loai":"dùng","importance":"normal","giaiDoan":"Kích hoạt cự tê thú","text":"Nữ tử áo xanh ném viên quyển vàng choàng lên sừng xanh cự tê thú, phát kim quang chói mắt kích thích con thú điên cuồng lao vào vụ hải.","anchor":"kim sắc quyển chuẩn xác choàng lên sừng màu xanh của cự tê"}]},"nguon":["@c0737"]},{"id":"bach-doan-con-tu-nhi-kim-vien","name":"Bạch đoản côn (Tứ Nhĩ Kim Viên khí linh)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Khí linh chi bảo","soHuu":["Đại hán họ Lục"],"trangThai":"dang-co","blurb":"Khí linh chi bảo của đại hán họ Lục, phun từ miệng ra rồi hóa kim hoàng quang hiện bóng ảnh Tứ Nhĩ Kim Viên — vượn vàng bốn tai cao năm sáu trượng, có thể chiến đấu tự chủ.","detail":"Bạch đoản côn ban đầu phát bạch quang, sau chuyển kim hoàng, hiện ra bóng ảnh Tứ Nhĩ Kim Viên — vượn vàng khổng lồ bốn tai, cao năm sáu trượng, tướng mạo hung ác. Cự viên ôm đại côn hóa kim quang tấn công đối thủ. Quật Diệu (Nguyên Anh Kỳ) thất thanh kinh hãi khi nhận ra đó là khí linh chi bảo. Đại hán họ Lục tuyên bố đây là lần đầu hiển lộ khí linh trước người khác.","congNang":["Hóa hiện bóng ảnh Tứ Nhĩ Kim Viên (vượn vàng bốn tai) chiến đấu tự chủ"],"chuSoHuu":[{"ten":"Đại hán họ Lục","tuChuong":"@c0738","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0738","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu hiển lộ","text":"Đại hán họ Lục há mồm phun ra bạch đoản côn, phát kim hoàng quang hóa Tứ Nhĩ Kim Viên khổng lồ tấn công Quật Diệu. Quật Diệu kinh hãi nhận ra là khí linh chi bảo.","anchor":"đây là lần đầu tiên từ khi Lục mỗ có được tứ nhĩ kim viên khí linh trước mặt người khác hiển lộ"}]},"nguon":["@c0738"]},{"id":"hai-thanh-ngan-qua","name":"Hai thanh ngân qua (giáo bạc lôi điện)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":[],"trangThai":"dang-co","blurb":"Hai ngọn giáo ngân quang có lôi hình quấn quanh, hỗ kích nhau tạo điện hồ cực thô. Được dùng để dụ cự tê thú tách khỏi đội hình pháp sĩ Mộ Lan.","detail":"Hai ngọn giáo ngân quang lập lòe, có lôi hình cung quấn quanh, bay ra từ sương mù. Né tránh pháp bảo của Kết Đan pháp sĩ, hai thanh ngân qua hỗ kích nhau tạo ra điện hồ cực thô đánh xuống đầu cự tê. Phá được linh quang hộ thể của cự tê nhưng không xuyên thủng chiến giáp. Mục đích chính là chọc giận dụ cự tê đuổi theo vào sương mù, tách khỏi đội hình.","congNang":["Hai giáo hỗ kích tạo lôi điện cường đại"],"tabs":{"tienTrinh":[{"chuong":"@c0738","loai":"dùng","importance":"normal","giaiDoan":"Dụ cự tê tách đội hình","text":"Hai thanh ngân qua bay ra từ sương mù, hỗ kích tạo điện hồ đánh cự tê chọc giận, dụ nó đuổi theo vào sương mù tách khỏi đám pháp sĩ Mộ Lan.","anchor":"hai thanh ngân qua không có dấu hiệu đan vào nhau mà hỗ kích, nhất thời một tiếng tiếng sấm nổ truyền ra"}]},"nguon":["@c0738"]},{"id":"thanh-sac-vien-chau","name":"Thanh sắc viên châu","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhạc Thượng Sư"],"trangThai":"dang-co","aliases":["Thanh châu"],"blurb":"Viên châu thanh sắc to cỡ nắm tay, bảo vật của nữ tử áo xanh (Nhạc Thượng Sư), rút ra chuẩn bị giao chiến với Hàn Lập. Công năng chưa rõ.","detail":"Viên châu thanh sắc to cỡ nắm tay, nữ tử áo xanh vỗ nhẹ Túi trữ vật rồi viên châu hiện lên trong tay, chuẩn bị đối đầu Hàn Lập. Công năng cụ thể chưa hé lộ.","chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0738","denChuong":"","cachCoDuoc":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0738","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Nữ tử áo xanh rút thanh châu to cỡ nắm tay từ Túi trữ vật, chuẩn bị giao chiến với Hàn Lập.","anchor":"một khỏa thanh châu to cỡ nắm tay bỗng nhiên hiện lên ở trong tay"}]},"nguon":["@c0738"]},{"id":"tuyet-dieu-phap-bao","name":"Tuyết điêu pháp bảo","cn":"","aliases":["Bạch sắc đoạn pháp bảo","Tuyết sắc cự điêu","Cự điêu"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nhạc Thượng Sư"],"trangThai":"hong","blurb":"Bạch địa đoạn mang trạng pháp bảo, ném ra hóa thành tuyết điêu khổng lồ cánh rộng mấy trượng, mắt đỏ móng vuốt đen, tốc độ cực nhanh, phóng phong nhận tấn công.","detail":"Pháp bảo của nữ tử áo xanh (Nhạc Thượng Sư), dạng bạch sắc đoạn mang trên người. Ném ra hóa thành con tuyết điêu khổng lồ cánh rộng mấy trượng, mắt đỏ, móng vuốt đen như kim loại. Tốc độ dịch chuyển cực nhanh, có thể phóng phong nhận từ cánh phá được kim võng. Bị Hàn Lập dùng hắc hồng cự thủ bắt gọn và phun Kiền Lam Băng Diễm đóng băng hoàn toàn.","hinhDang":"Bạch sắc đoạn (dải lụa trắng), hóa thành cự điêu cánh rộng mấy trượng, mắt đỏ, móng vuốt đen","congNang":["Hóa thành cự điêu tấn công","Phóng phong nhận từ cánh"],"chuSoHuu":[{"ten":"Nhạc Thượng Sư","tuChuong":"@c0739","denChuong":"","cachCoDuoc":"","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c0739","loai":"dùng","importance":"major","giaiDoan":"Xuất hiện và bị đóng băng","text":"Nhạc Thượng Sư ném ra tấn công Hàn Lập, tuyết điêu phóng phong nhận phá kim võng. Bị Hàn Lập dùng hắc hồng cự thủ bắt gọn và phun Kiền Lam Băng Diễm đóng băng hoàn toàn.","anchor":"bạch mang pháp bảo sau khi xoay quanh một cái thì chợt hóa thành một con chim lớn vỗ hai cánh lớn chừng mấy trượng"}]},"capNhatToi":"@c0739","nguon":["@c0739"]}]};
